insert into anki.decks (id, name, description, config) values ('55555555-5555-5555-5555-555555550001', 'Собеседование · JavaScript', 'Подготовка к собеседованию: JavaScript', '{"newCardsPerDay":30,"maxReviewsPerDay":300}'::jsonb) on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('d3064121-0fa2-7a24-2243-537625acef45', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Какие примитивные типы есть в JavaScript и чем примитив отличается от объекта при копировании?","Back":"В JS **7 примитивов**: `string`, `number`, `bigint`, `boolean`, `undefined`, `null`, `symbol`. Всё остальное — объекты (включая массивы, функции, даты).\n\n**Ключевые отличия:**\n- Примитивы **иммутабельны** и копируются **по значению**. Объекты копируются **по ссылке**.\n- `typeof null === ''object''` — историческая бага, которую нельзя исправить из-за обратной совместимости.\n- У примитивов нет методов, но `''abc''.length` работает за счёт **автобоксинга**: движок временно оборачивает примитив в объект-обёртку (`String`/`Number`/`Boolean`), вызывает метод и выбрасывает обёртку.\n\n```js\nlet a = 1; let b = a; b = 2; // a === 1 (копия значения)\nlet o = {x:1}; let p = o; p.x = 2; // o.x === 2 (та же ссылка)\n```\n\n**Подводный камень:** `const` защищает только биндинг, не содержимое. `const o = {}; o.x = 1` — валидно. Для иммутабельности нужен `Object.freeze`."}'::jsonb, ARRAY['primitives', 'value-vs-reference', 'autoboxing', 'syntax']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('620dc202-6ec9-72fa-2ef5-94378f42e137', 'd3064121-0fa2-7a24-2243-537625acef45', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('8ddaf0c6-74f3-1b19-2459-3339d41dec87', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Чем отличается == от === и какие подводные камни у нестрогого сравнения?","Back":"`===` (strict) сравнивает **без приведения типов**: разные типы — сразу `false`. `==` (loose) запускает **абстрактный алгоритм сравнения** с приведением.\n\n**Главные грабли `==`:**\n- `null == undefined` → `true`, но `null == 0` → `false` (специальный случай, `null`/`undefined` не приводятся к числу в `==`).\n- `'''' == 0` → `true`, `''0'' == 0` → `true`, но `'''' == ''0''` → `false`.\n- `[] == ![]` → `true` (`![]` → `false` → `0`, `[]` → `''''` → `0`).\n- `NaN == NaN` → `false` всегда.\n\n**Правило:** всегда используй `===`, кроме одного идиоматичного случая — `x == null` для проверки «null или undefined одновременно».\n\n```js\nif (x == null) {} // эквивалент x === null || x === undefined\n```\n\nПод капотом `==` для объект+примитив вызывает `ToPrimitive` (через `Symbol.toPrimitive` / `valueOf` / `toString`)."}'::jsonb, ARRAY['equality', 'coercion', 'syntax']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('4fb54757-9316-4ddd-60e2-121a778a2ef4', '8ddaf0c6-74f3-1b19-2459-3339d41dec87', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('c6b84db1-b29d-a5e6-1ff7-1f33fa4f2534', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Как работает приведение типов (coercion) в операторах + и -? Почему [] + {} и {} + [] дают разное?","Back":"**Оператор `+`** перегружен: если хотя бы один операнд после `ToPrimitive` — строка, идёт **конкатенация**, иначе сложение. Остальные арифметические операторы (`-`, `*`, `/`) всегда приводят к числу.\n\n```js\n1 + ''2''   // ''12'' (строка)\n1 - ''2''   // -1 (число)\n''5'' * 2   // 10\n[] + {}   // ''[object Object]'' ([]→'''', {}→''[object Object]'')\n[1,2] + [3] // ''1,23'' (массивы → строки через join)\n```\n\n**`{} + []` в консоли** даёт `0`, потому что ведущая `{}` парсится как **пустой блок кода**, а не объект, и остаётся унарный `+[]` → `+''''` → `0`. В выражении (`var x = {} + []`) будет `''[object Object]''`.\n\n**ToPrimitive** для `+` использует hint `''default''`: сначала `valueOf()`, потом `toString()`. Для объектов `valueOf` обычно возвращает сам объект (не примитив), поэтому срабатывает `toString`."}'::jsonb, ARRAY['coercion', 'operators', 'toprimitive', 'syntax']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('0ee5de9f-2f7e-5e37-5b24-3facdc6e5ab5', 'c6b84db1-b29d-a5e6-1ff7-1f33fa4f2534', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('b6b03bca-5197-d508-ac3c-167da1cf18ac', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое NaN, как его корректно проверять и какие значения являются falsy?","Back":"`NaN` (Not-a-Number) — единственное значение в JS, **не равное самому себе**: `NaN === NaN` → `false`. Появляется при невалидных матоперациях (`0/0`, `parseInt(''x'')`, `Math.sqrt(-1)`).\n\n**Проверка:**\n- `Number.isNaN(x)` — правильный способ, без приведения типа.\n- `isNaN(x)` (глобальный) — **опасен**: сначала приводит к числу, поэтому `isNaN(''foo'')` → `true`.\n- Трюк: `x !== x` → `true` только для `NaN`.\n\n**Falsy-значения (8 штук):** `false`, `0`, `-0`, `0n`, `''''`, `null`, `undefined`, `NaN`. Всё остальное truthy — включая `[]`, `{}`, `''0''`, `''false''`.\n\n```js\nObject.is(NaN, NaN)  // true (в отличие от ===)\nObject.is(0, -0)     // false (в отличие от ===)\n```\n\n`Object.is` — как `===`, но корректно различает `±0` и считает `NaN` равным `NaN`."}'::jsonb, ARRAY['nan', 'falsy', 'object-is', 'syntax']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('394cacf0-ce44-1566-9d8c-0409e5b42771', 'b6b03bca-5197-d508-ac3c-167da1cf18ac', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('ec7604bf-f2a5-f66a-c0db-291b9dd57265', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"В чём разница между поверхностной (shallow) и глубокой (deep) копией? Как сделать каждую?","Back":"**Shallow copy** копирует только верхний уровень; вложенные объекты остаются общими ссылками.\n\n```js\nconst shallow = { ...obj };          // spread\nconst shallow2 = Object.assign({}, obj);\nconst arrShallow = [...arr];\n```\n\n**Deep copy** рекурсивно копирует всё.\n\n```js\nstructuredClone(obj); // нативно, с 2022 — лучший способ\n```\n\n**Подводные камни:**\n- `JSON.parse(JSON.stringify(obj))` — теряет `undefined`, функции, `Symbol`, ломает `Date` (→ строка), `Map`/`Set`, циклические ссылки (кидает), `BigInt` (кидает). Медленно.\n- `structuredClone` поддерживает циклы, `Map`, `Set`, `Date`, `ArrayBuffer`, но **не клонирует функции, DOM-узлы, прототипы** (кидает `DataCloneError`).\n- `Object.assign` вызывает геттеры/сеттеры (копирует результат, а не дескриптор)."}'::jsonb, ARRAY['copy', 'deep-clone', 'structured-clone', 'syntax']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('73e32544-b615-d9d0-5fad-3a291b284ede', 'ec7604bf-f2a5-f66a-c0db-291b9dd57265', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('427d5698-edc9-3d28-ed9e-fb6c16851d74', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Объясни event loop: чем отличаются микротаски от макротасков и в каком порядке они выполняются?","Back":"JS однопоточный: есть **call stack**, **очередь макротасков** (task queue) и **очередь микротасков** (microtask queue).\n\n**Алгоритм цикла:**\n1. Выполнить один макротаск (скрипт, `setTimeout`, I/O, событие).\n2. **Полностью опустошить очередь микротасков** (Promise-колбэки, `queueMicrotask`, `MutationObserver`).\n3. Отрендерить (в браузере) при необходимости.\n4. Взять следующий макротаск.\n\nКлюч: **после каждого макротаска все микротаски выполняются до конца**, даже если они порождают новые микротаски.\n\n```js\nconsole.log(1);\nsetTimeout(() => console.log(2));      // макротаск\nPromise.resolve().then(() => console.log(3)); // микротаск\nconsole.log(4);\n// 1, 4, 3, 2\n```\n\n**Подводный камень:** бесконечная генерация микротасков (`Promise.resolve().then(loop)`) **заблокирует рендер и макротаски** — браузер зависнет, в отличие от рекурсивного `setTimeout`."}'::jsonb, ARRAY['event-loop', 'microtask', 'macrotask', 'async']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('73988bc9-cac3-b91e-bb3d-ff5fb9fc2c96', '427d5698-edc9-3d28-ed9e-fb6c16851d74', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('55b0664a-ea21-b294-df70-f89669ac9a3d', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое Promise, в каких состояниях он бывает и чем .then/.catch/.finally отличаются по поведению?","Back":"`Promise` — объект, представляющий результат отложенной операции. **3 состояния:** `pending` → `fulfilled` (resolved) или `rejected`. Переход **необратим** (settled один раз).\n\n- `.then(onFulfilled, onRejected)` — возвращает **новый** промис; значение из колбэка оборачивается в resolved-промис, исключение → rejected.\n- `.catch(fn)` ≡ `.then(undefined, fn)`.\n- `.finally(fn)` — выполняется в любом исходе, **не получает значение и не меняет его** (но если кинет/вернёт rejected-промис — перебьёт результат).\n\n**Подводные камни:**\n- Возврат промиса из `.then` приводит к его **развёртыванию** (thenable assimilation) — цепочка ждёт его.\n- Необработанный reject → `unhandledrejection`.\n- `.then().catch()` ловит ошибки из всей цепочки выше; `.then(ok, err)` — НЕ ловит ошибку из своего же `ok`.\n\n```js\np.then(handleOk).catch(handleErr); // err ловит и handleOk тоже\np.then(handleOk, handleErr);        // err НЕ ловит ошибку handleOk\n```"}'::jsonb, ARRAY['promise', 'then-catch', 'async']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('90f198f6-32af-6e2c-4164-616654d686ab', '55b0664a-ea21-b294-df70-f89669ac9a3d', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('2eb6f995-4a16-9c57-490d-04c77142d688', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Как async/await соотносится с промисами и где прячутся ошибки производительности при последовательном await?","Back":"`async`-функция **всегда возвращает промис**. `await` приостанавливает выполнение функции до settle промиса, а под капотом разворачивается в `.then` — то есть продолжение функции становится **микротаском**.\n\n**Главная ошибка — лишняя последовательность:**\n```js\n// ПЛОХО: 600мс, запросы ждут друг друга\nconst a = await fetchA(); // 300мс\nconst b = await fetchB(); // 300мс\n\n// ХОРОШО: 300мс, параллельно\nconst [a, b] = await Promise.all([fetchA(), fetchB()]);\n```\n\n**Нюансы:**\n- Промисы стартуют при создании, а не при `await`. Можно создать заранее и await-ить позже.\n- `await` в цикле `for...of` — последовательно; `map` + `Promise.all` — параллельно.\n- Ошибки ловятся `try/catch`. Забытый `await` теряет стектрейс и может проглотить reject.\n- `return await x` внутри try/catch нужен, чтобы catch поймал reject (иначе reject утечёт наружу)."}'::jsonb, ARRAY['async-await', 'promise', 'parallelism', 'async']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('6094bced-ba07-7f67-e188-3e4d758e1135', '2eb6f995-4a16-9c57-490d-04c77142d688', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('bea48389-c968-35bd-ba1b-450bc687eed3', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Чем отличаются Promise.all, allSettled, race и any?","Back":"Все принимают итерабельность промисов:\n\n- **`Promise.all`** — резолвится массивом результатов, когда **все** выполнены; **реджектится при первом** же reject (fail-fast). Остальные промисы НЕ отменяются, просто игнорируются.\n- **`Promise.allSettled`** — ждёт **все**, никогда не реджектится; возвращает массив `{status:''fulfilled'', value}` / `{status:''rejected'', reason}`. Идеален, когда нужны все результаты независимо.\n- **`Promise.race`** — settle первым **settled** промисом (хоть fulfilled, хоть rejected). Используется для таймаутов.\n- **`Promise.any`** — резолвится первым **fulfilled**; если все реджектнулись — `AggregateError` со всеми причинами.\n\n```js\n// таймаут через race\nPromise.race([fetch(url), new Promise((_, rej) =>\n  setTimeout(() => rej(new Error(''timeout'')), 5000))]);\n```\n\n**Подводный камень:** `all` с пустым массивом сразу резолвится `[]`; `any`/`race` с пустым — `any` реджектится, `race` зависает навсегда."}'::jsonb, ARRAY['promise-combinators', 'promise-all', 'async']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('60b44fdc-6812-4893-acfb-e6fb7e0f4532', 'bea48389-c968-35bd-ba1b-450bc687eed3', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('9ff00891-b111-ef86-509c-224aa22d259a', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое AbortController и как отменить fetch или другую асинхронную операцию?","Back":"`AbortController` — стандартный механизм отмены. Содержит `signal`, который передаётся в API; вызов `controller.abort()` переводит сигнал в aborted и эмитит событие `abort`.\n\n```js\nconst ctrl = new AbortController();\nfetch(url, { signal: ctrl.signal })\n  .catch(e => { if (e.name === ''AbortError'') {/* отменено */} });\nctrl.abort(); // прерывает запрос\n```\n\n**Применения:**\n- Отмена устаревших запросов (гонка автокомплита).\n- `addEventListener(ev, fn, { signal })` — автоснятие слушателя при abort (удобно для очистки группы подписок одним сигналом).\n- `AbortSignal.timeout(ms)` — готовый сигнал-таймаут.\n- `AbortSignal.any([s1, s2])` — комбинирование сигналов.\n\n**Нюансы:**\n- `abort()` после settle — no-op.\n- Своя async-функция должна сама проверять `signal.aborted` / слушать `abort` — отмена не «волшебная».\n- В отменённом fetch промис **реджектится** `AbortError`, а не резолвится."}'::jsonb, ARRAY['abort-controller', 'fetch', 'cancellation', 'async']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('d782f922-2f52-4878-3b17-5384c165c37f', '9ff00891-b111-ef86-509c-224aa22d259a', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('3186cb3c-ddd5-8c41-cd55-a979a1296e3d', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое дескрипторы свойств (property descriptors) и какие флаги у них есть?","Back":"Каждое свойство объекта имеет **дескриптор** — метаданные. Два вида: **data descriptor** (`value`, `writable`) и **accessor descriptor** (`get`, `set`). Общие флаги:\n\n- **`writable`** — можно ли менять `value` (только data).\n- **`enumerable`** — попадает ли в `for...in`, `Object.keys`, spread.\n- **`configurable`** — можно ли удалять свойство и переопределять дескриптор.\n\n```js\nObject.defineProperty(obj, ''id'', {\n  value: 42, writable: false, enumerable: false, configurable: false\n});\nObject.getOwnPropertyDescriptor(obj, ''id'');\n```\n\n**Важно:** при создании через `defineProperty` все флаги по умолчанию `false`. При обычном `obj.x = 1` — все `true`.\n\n**Подводный камень:** `configurable: false` необратимо (можно только ужесточить — например, `writable: true → false`). Неэнумерируемые свойства не видны в `Object.keys`, но видны в `Object.getOwnPropertyNames` и через `Reflect.ownKeys`."}'::jsonb, ARRAY['property-descriptors', 'define-property', 'objects']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('0e8baf31-e09f-5549-da9a-a19a7fade1b6', '3186cb3c-ddd5-8c41-cd55-a979a1296e3d', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('8b485b74-5c76-9b1a-8837-017ed761e179', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Чем геттеры/сеттеры отличаются от обычных свойств и в чём их подводные камни?","Back":"Геттер/сеттер — **accessor-свойство**: при чтении вызывается `get`, при записи — `set`. Снаружи выглядит как обычное свойство, но за ним стоит логика.\n\n```js\nconst obj = {\n  _v: 0,\n  get value() { return this._v; },\n  set value(x) { if (x < 0) throw Error(''neg''); this._v = x; }\n};\nobj.value = 5; // вызывает сеттер\n```\n\n**Нюансы:**\n- Accessor-свойство **не имеет `value`/`writable`** — только `get`/`set`/`enumerable`/`configurable`.\n- Геттер без сеттера → запись молча игнорируется (в strict mode — TypeError).\n- Геттеры **вычисляются при каждом доступе** — дорогая логика в геттере = скрытые тормоза (особенно в реактивных шаблонах Vue, где геттер дёргается на каждый рендер).\n- `JSON.stringify` вызывает геттеры (сериализует результат).\n- Бесконечная рекурсия, если в геттере обратиться к самому свойству вместо backing-поля."}'::jsonb, ARRAY['getters-setters', 'accessors', 'objects']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('8fb7fb1c-36ec-b32d-d113-1513af81a3fa', '8b485b74-5c76-9b1a-8837-017ed761e179', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('c10bd7eb-a927-4b04-113b-d8bf784f53ff', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что делает Object.freeze, в чём разница с seal/preventExtensions и почему freeze поверхностный?","Back":"Три уровня «запечатывания», от мягкого к жёсткому:\n\n- **`Object.preventExtensions`** — нельзя добавлять новые свойства; существующие можно менять/удалять.\n- **`Object.seal`** — `preventExtensions` + все свойства `configurable: false` (нельзя удалять/переопределять), но **значения менять можно**.\n- **`Object.freeze`** — `seal` + все свойства `writable: false` (полная заморозка значений).\n\n```js\nconst o = Object.freeze({ a: 1, nested: { b: 2 } });\no.a = 9;          // молча игнор (TypeError в strict)\no.nested.b = 9;   // РАБОТАЕТ — freeze поверхностный!\n```\n\n**Подводные камни:**\n- Freeze **shallow** — вложенные объекты не заморожены. Нужен рекурсивный deepFreeze.\n- Проверка: `Object.isFrozen(o)`.\n- Vue 3: `markRaw`/замороженные объекты не делаются реактивными — иногда это фича (большие неизменяемые данные), иногда баг (ожидали реактивность)."}'::jsonb, ARRAY['object-freeze', 'immutability', 'seal', 'objects']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('bc6728ac-035b-8778-87c4-baa8302398d4', 'c10bd7eb-a927-4b04-113b-d8bf784f53ff', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('c5bea1cc-9cce-4dcb-ed89-401e6d1280d1', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое Proxy и Reflect, и зачем они нужны вместе?","Back":"**`Proxy`** оборачивает объект и перехватывает фундаментальные операции через **ловушки (traps)**: `get`, `set`, `has`, `deleteProperty`, `apply`, `construct` и др.\n\n```js\nconst p = new Proxy(target, {\n  get(obj, key, receiver) {\n    console.log(''read'', key);\n    return Reflect.get(obj, key, receiver);\n  }\n});\n```\n\n**`Reflect`** — объект с методами, зеркалящими traps (`Reflect.get/set/has/...`). Зачем в паре:\n- Делегирует операцию **корректно**, включая `receiver` (важно для геттеров в цепочке прототипов — без `receiver` `this` в геттере будет неправильным).\n- Возвращает булев успех вместо исключений (`Reflect.set` → `true/false`).\n\n**Применение:** реактивность Vue 3 (`reactive` построен на Proxy), валидация, логирование, виртуальные свойства, негативные индексы массивов.\n\n**Подводные камни:** Proxy **не транзитивен** (вложенные объекты не проксируются автоматически — Vue проксирует лениво при доступе); нельзя проксировать приватные поля `#field` чужого класса; небольшой оверхед на каждую операцию."}'::jsonb, ARRAY['proxy', 'reflect', 'metaprogramming', 'objects']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('a031ce72-1bff-d780-0658-e1e01fcb4587', 'c5bea1cc-9cce-4dcb-ed89-401e6d1280d1', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('832a5963-9187-ebea-f828-b58846769072', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое Symbol, чем полезны well-known символы и Symbol.for?","Back":"`Symbol()` создаёт **уникальное неизменяемое значение**. Два символа никогда не равны, даже с одинаковым описанием. Используются как **неконфликтующие ключи свойств**.\n\n```js\nconst id = Symbol(''id'');\nobj[id] = 1; // не виден в for...in, Object.keys, JSON\n```\n\n- **Символьные ключи** скрыты от обычного перебора, но доступны через `Object.getOwnPropertySymbols` / `Reflect.ownKeys`. Это НЕ приватность (доступны при желании).\n- **`Symbol.for(key)`** — глобальный реестр: возвращает один и тот же символ для одного ключа (шеринг между модулями/realm).\n- **Well-known символы** настраивают поведение объекта: `Symbol.iterator` (итерируемость, `for...of`, spread), `Symbol.asyncIterator`, `Symbol.toPrimitive` (приведение), `Symbol.hasInstance` (`instanceof`), `Symbol.toStringTag`.\n\n```js\nconst range = {\n  [Symbol.iterator]() { let i = 0; return { next: () => ({ value: i, done: i++ >= 3 }) }; }\n};\n[...range]; // [0,1,2]\n```"}'::jsonb, ARRAY['symbol', 'iterator', 'well-known-symbols', 'objects']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('8b3e37d7-1e9c-c720-e292-3d89ae3a0365', '832a5963-9187-ebea-f828-b58846769072', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('c066f6ca-5bc0-62a2-5a4a-b3f930f7f172', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Как устроена прототипная цепочка и чем [[Prototype]] отличается от свойства prototype?","Back":"Каждый объект имеет внутреннюю ссылку **`[[Prototype]]`** (доступна как `__proto__` / `Object.getPrototypeOf`). При чтении свойства движок ищет его на объекте, затем поднимается по цепочке прототипов до `null`.\n\n**Не путать:**\n- **`[[Prototype]]`** есть у каждого объекта — это его «родитель» для поиска свойств.\n- **`prototype`** есть только у **функций** — это объект, который станет `[[Prototype]]` экземпляров, созданных через `new`.\n\n```js\nfunction F() {}\nconst f = new F();\nObject.getPrototypeOf(f) === F.prototype; // true\nF.prototype.constructor === F;            // true\n```\n\n**Нюансы:**\n- Запись свойства идёт **на сам объект** (shadowing), не на прототип — кроме случая сеттера в прототипе.\n- `Object.create(proto)` создаёт объект с заданным прототипом.\n- Менять прототип на лету (`Object.setPrototypeOf`, `__proto__ =`) **дорого** — деоптимизирует hidden class в V8.\n- `Object.create(null)` — объект без прототипа (нет `toString`, удобен как чистая map)."}'::jsonb, ARRAY['prototype', 'prototype-chain', 'oop']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('022c7a92-9c11-821d-ab22-2fb272799899', 'c066f6ca-5bc0-62a2-5a4a-b3f930f7f172', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('f90c44f5-5f76-75f3-906c-9a7515e2e30a', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Чем class в JS отличается от обычной функции-конструктора? Это «синтаксический сахар»?","Back":"В основе `class` — прототипы, но это **не полный сахар**, есть семантические отличия:\n\n- Тело класса всегда в **strict mode**.\n- Класс **не поднимается** как функция: до объявления — TDZ (в отличие от function declaration).\n- Нельзя вызвать без `new` (`TypeError`), функцию-конструктор — можно.\n- Методы класса **неэнумерируемы** (не попадают в `for...in`), в отличие от методов на `prototype` вручную.\n- Поддержка **приватных полей** `#field`, статических полей/блоков, геттеров/сеттеров на уровне синтаксиса.\n\n```js\nclass A {\n  #secret = 1;              // приватное поле\n  static count = 0;\n  get val() { return this.#secret; }\n}\n```\n\n**Приватные поля `#`** — настоящая инкапсуляция на уровне движка (не доступны рефлексией), проверка наличия — `#x in obj`. Доступ извне — синтаксическая ошибка, не рантайм."}'::jsonb, ARRAY['class', 'constructor-function', 'private-fields', 'oop']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('f4fba994-4381-a232-ce14-8852d371f50e', 'f90c44f5-5f76-75f3-906c-9a7515e2e30a', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('bf1b55e1-90ec-0326-4b16-82e576bd295c', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Как работает this и какие есть способы потери/привязки контекста?","Back":"`this` определяется **способом вызова**, а не местом объявления (кроме стрелочных функций):\n\n1. **Метод** `obj.fn()` → `this === obj`.\n2. **Свободный вызов** `fn()` → `undefined` (strict) или `window` (sloppy).\n3. **`new fn()`** → новый объект.\n4. **`call/apply/bind`** → явно заданный.\n5. **Стрелочная функция** — `this` лексический, берётся из окружения, `bind/call` его не меняют.\n\n**Классическая потеря контекста:**\n```js\nconst obj = { x: 1, getX() { return this.x; } };\nconst f = obj.getX;\nf();                  // undefined — потеряли this\nsetTimeout(obj.getX, 0); // тоже потеря\nsetTimeout(() => obj.getX(), 0); // ок (стрелка сохраняет obj)\nconst bound = obj.getX.bind(obj); // ок\n```\n\n**Нюансы:** `bind` создаёт новую функцию (повторный bind не переопределяет первый); в обработчиках событий `this` = элемент (но в стрелке — нет); в class методах при передаче как колбэк — потеря, поэтому биндят в конструкторе или используют поля-стрелки."}'::jsonb, ARRAY['this', 'context-binding', 'arrow-functions', 'oop']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('79ddb1bf-d83c-d8df-dc09-2c9a85f21d42', 'bf1b55e1-90ec-0326-4b16-82e576bd295c', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('f5592c6c-3f40-9932-d5b2-e6ca2fa80ceb', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Как реализовать наследование на классах с super и как работает instanceof?","Back":"**Наследование:**\n```js\nclass Animal {\n  constructor(name) { this.name = name; }\n  speak() { return `${this.name} sound`; }\n}\nclass Dog extends Animal {\n  constructor(name) {\n    super(name);        // ОБЯЗАТЕЛЕН до обращения к this\n    this.legs = 4;\n  }\n  speak() { return super.speak() + '' woof''; }\n}\n```\n\n- `super(...)` в конструкторе вызывает родительский конструктор; **обращение к `this` до `super` → ReferenceError**.\n- `super.method()` зовёт метод родителя через `[[HomeObject]]` (привязан к месту определения, не к `this`).\n\n**`instanceof`** проверяет, есть ли `Constructor.prototype` в **цепочке прототипов** объекта (а не сравнивает конструкторы напрямую).\n```js\ndog instanceof Animal; // true (поднимается по цепочке)\n```\n\n**Подводные камни:** `instanceof` ломается между разными realm (iframe/worker) — там другой `Array`; настраивается через `Symbol.hasInstance`; для типа примитивов бесполезен (используй `typeof` / `Array.isArray`)."}'::jsonb, ARRAY['inheritance', 'super', 'instanceof', 'oop']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('278b0b2a-22fb-7818-6d57-8dfdee43f536', 'f5592c6c-3f40-9932-d5b2-e6ca2fa80ceb', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('627e8261-bccc-1fce-cb62-4530060a8a15', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое замыкание (closure) и как оно хранится в памяти?","Back":"**Замыкание** — функция вместе с лексическим окружением (ссылками на переменные внешних областей), где она была **создана**. Функция «помнит» эти переменные даже после завершения внешней функции.\n\n```js\nfunction counter() {\n  let count = 0;\n  return () => ++count; // замыкает count\n}\nconst c = counter();\nc(); c(); // 1, 2 — count живёт в замыкании\n```\n\n**В памяти:** переменные, на которые ссылается замыкание, **не собираются GC**, пока жива функция-замыкание. V8 оптимизирует: в замыкание попадают только реально используемые переменные (Closure-объект), остальные из скоупа собираются.\n\n**Применения:** приватность (модульный паттерн), мемоизация, каррирование, фабрики функций, инкапсуляция состояния.\n\n**Подводные камни:**\n- Утечки памяти: замыкание держит большой объект/DOM-узел дольше нужного.\n- Классика `var` в цикле:\n```js\nfor (var i = 0; i < 3; i++) setTimeout(() => console.log(i)); // 3,3,3\nfor (let i = 0; i < 3; i++) setTimeout(() => console.log(i)); // 0,1,2 (новый биндинг на итерацию)\n```"}'::jsonb, ARRAY['closures', 'memory', 'functional', 'scope']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('0651a82f-fc4e-2f15-ee6a-c498189d3185', '627e8261-bccc-1fce-cb62-4530060a8a15', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('53a9dd0e-062b-bb59-c398-2572c51dc231', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое чистая функция и почему иммутабельность важна для предсказуемости?","Back":"**Чистая функция:**\n1. Возвращает один и тот же результат для одних аргументов (детерминизм).\n2. Без **побочных эффектов** (не мутирует внешнее состояние, не делает I/O, не читает изменяемое глобальное).\n\n```js\nconst add = (a, b) => a + b;        // чистая\nlet total = 0;\nconst impure = x => total += x;     // нечистая (мутирует внешнее)\n```\n\n**Польза:** легко тестировать (нет моков), кешировать (мемоизация), распараллеливать, переиспользовать; нет скрытых зависимостей.\n\n**Иммутабельность** — не мутировать данные, а создавать новые:\n```js\nconst next = { ...state, count: state.count + 1 }; // вместо state.count++\nconst arr2 = [...arr, item];                       // вместо arr.push\n```\n\n**Почему важно:** в Vue/React сравнение по ссылке определяет ререндер; мутация «на месте» ломает реактивность (Vue 3 ловит мутацию через Proxy, но в Pinia/общем стейте мутация снаружи action — антипаттерн). Иммутабельные апдейты дают предсказуемый поток данных и упрощают time-travel/undo."}'::jsonb, ARRAY['pure-functions', 'immutability', 'functional', 'side-effects']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('f07d7dd6-d2e5-d5d5-caf8-07a9aafab4b5', '53a9dd0e-062b-bb59-c398-2572c51dc231', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('58ffd2b6-0129-b7db-1199-e1a699110e89', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое функции высшего порядка (HOF), каррирование и композиция?","Back":"**HOF** — функция, которая принимает функцию и/или возвращает функцию (`map`, `filter`, `reduce`, `debounce`).\n\n**Каррирование** — превращение `f(a, b, c)` в `f(a)(b)(c)`; позволяет частичное применение.\n```js\nconst curry = fn => function curried(...args) {\n  return args.length >= fn.length\n    ? fn(...args)\n    : (...rest) => curried(...args, ...rest);\n};\nconst add = curry((a, b, c) => a + b + c);\nadd(1)(2)(3); // 6; add(1, 2)(3) тоже\n```\n\n**Композиция** — сборка функции из других, выход одной = вход другой.\n```js\nconst compose = (...fns) => x => fns.reduceRight((acc, f) => f(acc), x);\nconst pipe = (...fns) => x => fns.reduce((acc, f) => f(acc), x);\nconst process = pipe(trim, toLower, capitalize);\n```\n\n`compose` идёт справа-налево, `pipe` — слева-направо. На практике pipe читаемее. Композиция требует **унарных** (одноаргументных) функций между шагами."}'::jsonb, ARRAY['hof', 'currying', 'composition', 'functional']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('768c6ff7-0634-8824-84fc-8eaaf50b1ee8', '58ffd2b6-0129-b7db-1199-e1a699110e89', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('100e8133-135c-d23f-7f92-2264376e27c7', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое мемоизация и debounce/throttle? Где применяются в реальных задачах?","Back":"**Мемоизация** — кеш результатов чистой функции по аргументам:\n```js\nconst memoize = fn => {\n  const cache = new Map();\n  return (...args) => {\n    const key = JSON.stringify(args);\n    if (!cache.has(key)) cache.set(key, fn(...args));\n    return cache.get(key);\n  };\n};\n```\nГрабли: ключ через `JSON.stringify` не различает объекты по ссылке и порядок; для объектов-аргументов лучше `WeakMap`.\n\n**Debounce** — вызвать функцию только после паузы N мс без новых вызовов (поиск-автокомплит, resize).\n```js\nconst debounce = (fn, ms) => {\n  let t;\n  return (...a) => { clearTimeout(t); t = setTimeout(() => fn(...a), ms); };\n};\n```\n\n**Throttle** — не чаще раза в N мс (scroll, mousemove).\n\n**Разница:** debounce ждёт тишины (один вызов в конце), throttle гарантирует регулярность (вызовы через интервал). В Vue это типичные обёртки для watch/обработчиков ввода."}'::jsonb, ARRAY['memoization', 'debounce-throttle', 'functional']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('682792f0-0e20-6a2f-772b-80967e7bc16e', '100e8133-135c-d23f-7f92-2264376e27c7', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('8a8acefe-1aa1-5462-e4b5-dbef535d238d', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое делегирование событий и как работают фазы всплытия и перехвата?","Back":"Событие проходит **3 фазы**: capturing (от `window` вниз к target), target, **bubbling** (от target вверх). По умолчанию слушатели срабатывают на bubbling; `addEventListener(ev, fn, true)` или `{capture:true}` — на capturing.\n\n**Делегирование** — повесить один слушатель на общего родителя вместо многих на детей, и определить источник через `event.target`:\n```js\nlist.addEventListener(''click'', e => {\n  const item = e.target.closest(''li'');\n  if (item) handle(item.dataset.id);\n});\n```\n\n**Плюсы:** работает для динамически добавленных элементов, меньше слушателей (память/перф).\n\n**Нюансы:**\n- `event.target` — где произошло, `event.currentTarget` — где висит слушатель (`this`).\n- `stopPropagation()` останавливает дальнейшее всплытие; `stopImmediatePropagation()` — ещё и другие слушатели на этом же элементе.\n- `preventDefault()` отменяет дефолт (переход по ссылке), не влияет на всплытие.\n- Не всплывают: `focus`/`blur` (есть `focusin`/`focusout`), `mouseenter`/`mouseleave`. Для них делегирование требует capture или -in/-out версий."}'::jsonb, ARRAY['event-delegation', 'bubbling-capturing', 'dom', 'browser-api']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('b0c560a5-e171-b289-d0d3-28226da7a8c2', '8a8acefe-1aa1-5462-e4b5-dbef535d238d', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('c863e4bd-3567-d494-6030-641fe0dead35', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Чем fetch отличается от XHR и какие у fetch подводные камни (ошибки, тело, CORS)?","Back":"`fetch` — промис-based замена `XMLHttpRequest`.\n\n**Подводные камни:**\n- **Не реджектится на HTTP-ошибки** (404/500): промис резолвится, надо проверять `res.ok` / `res.status` вручную. Реджект только на сетевые сбои/CORS/abort.\n- Тело читается **один раз** (stream): `res.json()` после `res.text()` кинет ошибку. Для повторного — `res.clone()`.\n- По умолчанию **не шлёт куки** для cross-origin: нужен `credentials: ''include''`.\n- Не поддерживает progress загрузки нативно (нужен ReadableStream от `res.body`).\n- Не имеет встроенного таймаута — через `AbortSignal.timeout`.\n\n```js\nconst res = await fetch(url);\nif (!res.ok) throw new Error(`HTTP ${res.status}`);\nconst data = await res.json();\n```\n\n**CORS:** браузер для cross-origin делает preflight `OPTIONS` при «непростых» запросах; сервер должен вернуть `Access-Control-Allow-*`. `mode: ''no-cors''` даёт **opaque**-ответ (нельзя прочитать тело) — частая ловушка."}'::jsonb, ARRAY['fetch', 'cors', 'http', 'browser-api']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('c96fa864-d3e1-9c78-cfb2-6f391c5d6877', 'c863e4bd-3567-d494-6030-641fe0dead35', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('2804a722-50a2-6f17-2088-fff85fd39042', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Чем отличаются localStorage, sessionStorage, cookies и IndexedDB?","Back":"| Хранилище | Объём | Время жизни | Доступ | Шлётся на сервер |\n|---|---|---|---|---|\n| **localStorage** | ~5-10MB | до явного удаления | синхронный, строки | нет |\n| **sessionStorage** | ~5MB | вкладка/сессия | синхронный | нет |\n| **cookies** | ~4KB | задаётся `expires` | строки | **да, с каждым запросом** |\n| **IndexedDB** | сотни MB+ | постоянное | асинхронный, структурир. | нет |\n\n**Нюансы:**\n- `localStorage`/`sessionStorage` **синхронны** — блокируют поток, не для больших данных; хранят только строки (объекты через `JSON`).\n- Привязаны к **origin** (protocol+host+port). `sessionStorage` не шарится между вкладками, `localStorage` — шарится (и эмитит событие `storage` в других вкладках — основа кросс-табовой синхронизации).\n- Cookies для аутентификации — флаги `HttpOnly` (недоступна из JS, защита от XSS), `Secure`, `SameSite` (защита от CSRF).\n- IndexedDB — для офлайн/больших структур; обычно через обёртки (idb, Dexie)."}'::jsonb, ARRAY['storage', 'localstorage', 'cookies', 'indexeddb', 'browser-api']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('d22dcdb4-a699-543f-2d86-19e751ccaf08', '2804a722-50a2-6f17-2088-fff85fd39042', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('6d7abba4-0b08-cf47-aec9-989ae07e1929', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Зачем нужен requestAnimationFrame и чем он лучше setTimeout для анимаций?","Back":"`requestAnimationFrame(cb)` планирует колбэк **перед следующей перерисовкой** браузера (обычно ~60fps, синхронно с частотой монитора).\n\n**Преимущества над `setTimeout(cb, 16)`:**\n- Синхронизирован с циклом рендеринга → нет рассинхрона и дёрганья (jank).\n- **Пауза в фоновых вкладках** — экономит CPU/батарею (setTimeout продолжает тикать, хоть и троттлится до ~1с).\n- Колбэк получает high-res timestamp для расчёта дельты времени (анимация, независимая от FPS).\n\n```js\nfunction animate(ts) {\n  // двигаем по dt, а не по фиксированному шагу\n  el.style.transform = `translateX(${x}px)`;\n  if (notDone) requestAnimationFrame(animate);\n}\nrequestAnimationFrame(animate);\n```\n\n**Нюансы:** один rAF = один кадр, для непрерывной анимации вызывают рекурсивно; отмена — `cancelAnimationFrame(id)`. Тяжёлые вычисления в rAF всё равно блокируют кадр → для не-визуальной работы лучше `requestIdleCallback` или Web Worker. Чтение layout-свойств (`offsetHeight`) внутри после записи стилей вызывает **forced reflow** — батчить чтения/записи."}'::jsonb, ARRAY['raf', 'animation', 'rendering', 'browser-api']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('0ae830c0-506c-7654-7a7c-ca1add4a3866', '6d7abba4-0b08-cf47-aec9-989ae07e1929', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('b2c929ff-8df4-8eea-c6c0-acbf20b7b308', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Что такое hoisting и чем поднятие var, let/const и функций отличается? Что такое TDZ?","Back":"**Hoisting** — на этапе компиляции движок «поднимает» объявления в начало области видимости.\n\n- **`var`** — поднимается и инициализируется `undefined`. Доступ до строки объявления → `undefined`, не ошибка.\n- **`function declaration`** — поднимается **целиком** (можно вызвать выше объявления).\n- **`let`/`const`** — поднимаются, но **не инициализируются**: попадают в **TDZ** (Temporal Dead Zone) от начала блока до строки объявления. Доступ в TDZ → `ReferenceError`.\n- **`function expression` / стрелки** — поднимается только переменная (по правилам её типа), не функция.\n\n```js\nconsole.log(a); // undefined (var)\nconsole.log(b); // ReferenceError (TDZ)\nfoo();          // работает (declaration)\nvar a = 1;\nlet b = 2;\nfunction foo() {}\n```\n\n**Зачем TDZ:** защищает от использования `let`/`const` до инициализации, делает поведение предсказуемым. `typeof` в TDZ тоже кидает (в отличие от необъявленных переменных, где `typeof` → `''undefined''`)."}'::jsonb, ARRAY['hoisting', 'tdz', 'scope', 'engine']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('5465ab1e-6136-d3c2-c4aa-1cb05cb6eb2d', 'b2c929ff-8df4-8eea-c6c0-acbf20b7b308', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('a7df6ccb-34f8-0a43-ab91-455bbdbc9a14', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Как работает scope и lexical scope в JS? Чем отличается scope-цепочка от прототипной?","Back":"**Scope** — где доступна переменная. JS использует **лексическую (статическую) область видимости**: вложенность определяется **местом написания кода**, а не местом вызова.\n\n**Виды:**\n- Global scope.\n- Function scope (`var`, параметры).\n- Block scope (`let`/`const`, `{}`, тело `if`/`for`).\n\n**Scope chain:** при разрешении переменной движок ищет в текущем окружении, затем в родительском лексическом, до глобального. Это основа замыканий.\n\n```js\nlet x = ''global'';\nfunction outer() {\n  let x = ''outer'';\n  function inner() { return x; } // лексически видит outer\n  return inner();\n}\nouter(); // ''outer''\n```\n\n**Не путать со scope-цепочкой прототипов:**\n- **Scope chain** — для разрешения **переменных** (лексически, на этапе компиляции).\n- **Prototype chain** — для разрешения **свойств объекта** (динамически, в рантайме через `[[Prototype]]`).\n\nЭто два независимых механизма."}'::jsonb, ARRAY['scope', 'lexical-scope', 'scope-chain', 'engine']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('aba59f0c-9f0e-5add-3dc7-d9dc176e1323', 'a7df6ccb-34f8-0a43-ab91-455bbdbc9a14', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('739039f1-3b72-bcbc-28e1-df67619f61d8', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Как V8 исполняет JS: интерпретация, JIT, hidden classes и инлайн-кеши?","Back":"V8 — конвейер из нескольких уровней:\n\n1. **Parser** → AST.\n2. **Ignition** — интерпретатор, генерирует и исполняет байткод (быстрый старт).\n3. **TurboFan** (и Sparkplug/Maglev) — оптимизирующий **JIT**: «горячий» код компилируется в машинный на основе профилирования типов.\n\n**Hidden Classes (Shapes/Maps):** V8 присваивает объектам скрытые классы по их структуре. Объекты с одинаковым набором свойств **в одном порядке** разделяют hidden class → быстрый доступ по смещению.\n\n**Inline Caches (IC):** запоминают, какой hidden class встречался в точке доступа `obj.x`, и кешируют путь.\n\n**Деоптимизация:** код возвращается к интерпретатору при нарушении предположений.\n\n**Что убивает оптимизацию:**\n- Добавление свойств в разном порядке / после создания → разные hidden classes (мегаморфизм IC).\n- `delete obj.prop` → переход в slow/dictionary mode.\n- Смешивание типов в массиве (числа + объекты) ломает elements kind.\n- Смена `[[Prototype]]` на лету.\n\n**Вывод:** инициализируй все поля в конструкторе в одном порядке, держи однотипные массивы."}'::jsonb, ARRAY['v8', 'jit', 'hidden-classes', 'inline-cache', 'engine']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('dc733d3d-7685-f902-996c-d63722498729', '739039f1-3b72-bcbc-28e1-df67619f61d8', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('2a31c8fa-25ca-0f0d-28d8-43d64237ec05', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550001', '{"Front":"Как работает сборка мусора в JS и из-за чего возникают утечки памяти?","Back":"JS использует **mark-and-sweep**: GC периодически проходит от корней (global, стек, активные замыкания) и помечает достижимые объекты; недостижимые освобождаются. **Подсчёт ссылок не используется** в чистом виде (не ловит циклы) — достижимость решает.\n\nV8 — **generational GC**: молодые объекты в **new space** (быстрый Scavenge), выжившие переходят в **old space** (Mark-Compact). Большинство объектов умирают молодыми.\n\n**Типичные утечки:**\n- **Забытые таймеры/подписки** — `setInterval`/`addEventListener` держат замыкание и DOM. Всегда снимать в cleanup (в Vue — `onUnmounted`).\n- **Замыкания**, удерживающие большие структуры дольше нужного.\n- **Глобальные переменные** (случайные, без объявления в sloppy mode).\n- **Detached DOM** — JS-ссылка на удалённый из дерева узел.\n- Растущие `Map`/массивы-кеши без вытеснения.\n\n**Решение:** `WeakMap`/`WeakSet`/`WeakRef` — слабые ссылки, **не мешают GC** (ключи собираются, если на них нет других ссылок). Удобны для кешей и приватных данных, привязанных к объекту."}'::jsonb, ARRAY['garbage-collection', 'memory-leaks', 'weakmap', 'engine']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('effd14be-187a-8051-5f30-b9d6fd6a4e43', '2a31c8fa-25ca-0f0d-28d8-43d64237ec05', '55555555-5555-5555-5555-555555550001', 0, 'new') on conflict (id) do nothing;
insert into anki.decks (id, name, description, config) values ('55555555-5555-5555-5555-555555550002', 'Собеседование · TypeScript', 'Подготовка к собеседованию: TypeScript', '{"newCardsPerDay":30,"maxReviewsPerDay":300}'::jsonb) on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('302c3bfc-ba9b-8b30-bb77-a7cf0f81371f', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550002', '{"Front":"Что такое structural typing (структурная типизация) в TypeScript и чем она отличается от номинальной? Какие из этого следуют грабли?","Back":"TypeScript использует **структурную** систему типов (\"duck typing\"): совместимость определяется по форме (набору свойств), а не по имени типа или явному наследованию. Если объект имеет все требуемые свойства подходящих типов — он совместим, даже если объявлен через другой тип/класс.\n\n```ts\ninterface Point { x: number; y: number }\nclass Vec { constructor(public x: number, public y: number) {} }\nconst p: Point = new Vec(1, 2); // OK — структуры совпадают\n```\n\n**Грабли и нюансы:**\n- **Лишние свойства (excess property checks)** ловятся только для *литералов объектов*, присваиваемых напрямую. Через промежуточную переменную проверка не срабатывает:\n```ts\ntype Cfg = { a: number };\nconst x: Cfg = { a: 1, b: 2 };   // Error: лишнее b\nconst tmp = { a: 1, b: 2 };\nconst y: Cfg = tmp;               // OK — excess check не применяется\n```\n- Два разных доменных типа с одинаковой формой взаимозаменяемы — нет защиты от смешивания (например `type UserId = string` и `type OrderId = string` совместимы). Решается **branded/nominal types**: `type UserId = string & { readonly __brand: unique symbol }`.\n- Классы с `private`/`#`-полями получают элемент номинальности: класс с приватным полем совместим только сам с собой."}'::jsonb, ARRAY['structural-typing', 'type-compatibility', 'branded-types', 'excess-property-check']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('1825f667-0437-2ebe-d7c6-2ba253ac2c33', '302c3bfc-ba9b-8b30-bb77-a7cf0f81371f', '55555555-5555-5555-5555-555555550002', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('ea92fed3-2f3c-bf74-dfe9-d0ed16785dc0', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550002', '{"Front":"В чём разница между any, unknown и never? Когда что использовать?","Back":"**`any`** — отключает проверку типов. Значение `any` можно присвоить чему угодно и вызвать любой метод — компилятор молчит. Это \"escape hatch\", который заражает код: ошибки уходят в рантайм. Используется минимально (миграция, сторонние нетипизированные либы).\n\n**`unknown`** — типобезопасный аналог `any`: принять можно что угодно, но **использовать нельзя без сужения** (narrowing) через type guard / проверку / assert.\n```ts\nfunction parse(json: string): unknown { return JSON.parse(json); }\nconst data = parse(s);\n// data.id;            // Error\nif (typeof data === ''object'' && data && ''id'' in data) {\n  // здесь data сужен\n}\n```\nИдеален для границ системы: ответы API, `JSON.parse`, `catch (e: unknown)`.\n\n**`never`** — тип, у которого нет значений. Возникает у функций, которые не возвращаются (`throw`/бесконечный цикл), как результат невозможного сужения, и как поглощающий элемент в union (`T | never === T`). Используется для **exhaustiveness checking**:\n```ts\nfunction assertNever(x: never): never { throw new Error(''unhandled: '' + x); }\n```\n\n**Соотношение:** `unknown` — верх (top type, всё ему присваиваемо), `never` — низ (bottom type, присваиваем всему). `any` стоит \"вне решётки\" — совместим в обе стороны, что и делает его опасным."}'::jsonb, ARRAY['any', 'unknown', 'never', 'top-bottom-types', 'exhaustiveness']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('ce20feb3-52d6-84ed-f0ec-4ed777f5259d', 'ea92fed3-2f3c-bf74-dfe9-d0ed16785dc0', '55555555-5555-5555-5555-555555550002', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('ea1ee6a4-8ee7-d289-932b-c407e54d85b2', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550002', '{"Front":"type vs interface: в чём отличия и что выбрать?","Back":"Оба описывают форму. Ключевые различия:\n\n| | `interface` | `type` |\n|---|---|---|\n| Declaration merging | да (объявления сливаются) | нет |\n| Расширение | `extends` | `&` (intersection) |\n| Union / tuple / primitive alias | нет | да |\n| Mapped/conditional types | нет | да |\n| Производительность проверок | чуть лучше кешируется | сложные типы могут быть тяжелее |\n\n**Declaration merging** — интерфейс с одним именем, объявленный несколько раз, объединяется. Это нужно для аугментации сторонних типов (`declare module`, расширение `Window`, добавление полей в `Vue`-инстанс через `ComponentCustomProperties`):\n```ts\ninterface Window { myGlobal: string }\n```\nС `type` так нельзя — будет ошибка дублирования.\n\n**Только `type` умеет:** union (`type T = A | B`), кортежи, алиасы примитивов, mapped/conditional типы, `infer`.\n\n**Тонкость с extends vs &:** `interface B extends A` проверяет совместимость сразу и даёт понятную ошибку; `A & B` при конфликте свойств молча даёт `never` для конфликтного поля.\n\n**Практика:** для публичных объектных контрактов и того, что может расширяться/аугментироваться — `interface`; для union, утилит, сложных вычисляемых типов — `type`. В одной кодовой базе главное — единообразие."}'::jsonb, ARRAY['type-vs-interface', 'declaration-merging', 'module-augmentation']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('271375a5-bd8b-eac1-d571-a86079ae83a6', 'ea1ee6a4-8ee7-d289-932b-c407e54d85b2', '55555555-5555-5555-5555-555555550002', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('e4600560-21bd-9375-95c9-1784d6f4dff1', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550002', '{"Front":"Union и intersection типы: семантика, и почему intersection несовместимых примитивов даёт never?","Back":"**Union (`A | B`)** — значение принадлежит *одному из* типов. Доступны только **общие** члены (то, что гарантированно есть в каждом варианте), пока не сделано сужение.\n\n**Intersection (`A & B`)** — значение принадлежит *обоим* типам одновременно; для объектов это \"слияние\" наборов свойств.\n```ts\ntype Named = { name: string };\ntype Aged = { age: number };\ntype Person = Named & Aged; // { name; age }\n```\n\n**Почему `string & number` = `never`:** не существует значения, которое одновременно строка и число, поэтому пересечение — пустой тип `never`. Аналогично intersection объектов с конфликтующими типами одного поля даёт `never` для этого поля.\n\n**Дистрибутивность и кардинальность (контринтуитивно):**\n- Union *расширяет* множество значений, но *сужает* доступный API (общие члены).\n- Intersection *сужает* множество значений, но *расширяет* API (все члены).\n\n**Грабли с функциями:** intersection функциональных типов ведёт себя как перегрузка, а union функций требует, чтобы аргумент подходил всем сигнатурам (контравариантность параметров):\n```ts\ntype F = ((x: string) => void) | ((x: number) => void);\n// f(arg) потребует arg: string & number => never\n```"}'::jsonb, ARRAY['union', 'intersection', 'never', 'variance']::text[]) on conflict (id) do nothing;
