insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('499ca739-e24f-289e-2bc0-c0957fb81b69', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Что такое stacking context (контекст наложения) и как он создаётся? Почему z-index не всегда работает как ожидаешь?","Back":"**Stacking context** — это локальная \"вселенная\" наложения элементов по оси Z. `z-index` сравнивается **только внутри одного контекста**: элемент с `z-index: 9999` внутри родителя с `z-index: 1` никогда не перекроет соседа родителя с `z-index: 2`.\n\nКонтекст создаётся:\n- корнем документа (`<html>`);\n- `position` (relative/absolute/fixed/sticky) **+ z-index != auto**;\n- `position: fixed/sticky` (сами по себе);\n- `opacity < 1`;\n- `transform`, `filter`, `perspective`, `clip-path`, `mask` != none;\n- `will-change` со значением, которое создаёт контекст;\n- `isolation: isolate` (специально для этого и нужен);\n- flex/grid-ребёнок с `z-index != auto`;\n- `mix-blend-mode != normal`, `contain: layout/paint/strict`.\n\n**Подводный камень:** добавление `transform` или `opacity` ради анимации внезапно \"запирает\" z-index детей. Лечится либо переносом элемента вверх по дереву, либо `isolation: isolate` на нужном уровне, чтобы явно управлять границей."}'::jsonb, ARRAY['positioning', 'z-index', 'stacking-context']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('edc9f606-8088-db2d-60aa-ef598d19931f', '499ca739-e24f-289e-2bc0-c0957fb81b69', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('d0b2bc3c-03ca-eff6-3851-1c60d07f3bb6', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Чем отличаются position: relative, absolute, fixed и sticky? Относительно чего позиционируется каждый?","Back":"- **static** — дефолт, в потоке, top/left игнорируются.\n- **relative** — остаётся в потоке (место сохраняется), сдвигается относительно своей нормальной позиции; создаёт **containing block** для absolute-детей.\n- **absolute** — выпадает из потока, позиционируется относительно **ближайшего позиционированного предка** (не static), либо относительно `transform`/`filter`/`contain`-предка, иначе — initial containing block (вьюпорт).\n- **fixed** — выпадает из потока, относительно **вьюпорта**. НО: любой `transform`/`filter`/`perspective`/`will-change` у предка делает его новым containing block — и fixed начинает скроллиться вместе с ним (частый баг с модалками внутри transformed-контейнеров).\n- **sticky** — гибрид: в потоке как relative, пока не достигнет порога (`top`/`bottom`...), затем \"прилипает\". Работает в рамках **ближайшего скролл-контейнера** и только пока виден родитель; ломается, если у предка `overflow: hidden/auto` обрезает контекст."}'::jsonb, ARRAY['positioning', 'position', 'sticky']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('8cae6f25-287b-f48e-f6fe-b154a510f00b', 'd0b2bc3c-03ca-eff6-3851-1c60d07f3bb6', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('6d42cf8f-f9d8-acf7-f343-e9ade28d7d15', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Как работают CSS Custom Properties (переменные)? Чем они принципиально отличаются от препроцессорных переменных SCSS?","Back":"Объявление через `--name: value`, чтение через `var(--name, fallback)`.\n\n**Ключевые отличия от SCSS:**\n- **Рантайм, а не compile-time.** Их можно менять из JS (`el.style.setProperty`), в media-queries, по `:hover`, в разных темах — SCSS-переменные \"запекаются\" при сборке.\n- **Наследуются по DOM и каскадируются.** Значение берётся из ближайшего предка; меняешь на `:root` — меняется везде, меняешь на компоненте — локально.\n- **Динамическая подстановка.** `var()` резолвится в момент применения, поэтому работает с наследованием и переопределением темы без пересборки.\n\n**Подводные камни:**\n- Тип не валидируется: `--gap: 10` без единиц в `width: var(--gap)` даст невалидное значение. Лечится `calc(var(--gap) * 1px)` или `@property` с `syntax`.\n- Fallback: `var(--x, var(--y, 10px))` — можно цепочкой.\n- `@property` (Houdini) позволяет задать `syntax`, `inherits`, `initial-value` — и тогда переменную **можно анимировать** (обычные кастом-свойства анимируются как дискретные)."}'::jsonb, ARRAY['custom-properties', 'css-variables', 'houdini']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('7891a245-85bb-c590-93c4-6ea95aa66e5f', '6d42cf8f-f9d8-acf7-f343-e9ade28d7d15', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('82e83104-900e-cf3a-4f82-4449f9763bdf', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Что выведет наследование CSS-переменной: где она резолвится и почему var() может \"сломать\" значение целиком?","Back":"Custom properties **наследуются как обычные свойства**: ребёнок видит значение, вычисленное на ближайшем предке, у которого оно задано.\n\n```css\n:root { --color: black; }\n.box { --color: red; }\n.box p { color: var(--color); } /* red */\n```\n\n**Важный нюанс — \"invalid at computed-value time\":** если `var()` подставляет невалидное для свойства значение, браузер НЕ откатывается к предыдущему правилу каскада, а применяет **inherited или initial** значение свойства.\n\n```css\n.x { --w: foo; width: 100px; width: var(--w); } /* width станет auto (initial), а не 100px */\n```\n\nЭто отличается от обычного невалидного CSS, где правило просто игнорируется и берётся предыдущее. Поэтому fallback в `var()` — это не страховка от плохого *значения переменной*, а только от её *отсутствия*."}'::jsonb, ARRAY['custom-properties', 'css-variables', 'inheritance']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('18649b0e-c17f-63dc-44e5-f76296f4300b', '82e83104-900e-cf3a-4f82-4449f9763bdf', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('89951beb-2642-54fc-93aa-fc2806df7ae6', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Разница между псевдоэлементами (::before/::after) и псевдоклассами (:hover, :nth-child)? Почему ::before иногда не отображается?","Back":"- **Псевдокласс** (`:hover`, `:focus`, `:checked`, `:nth-child`) — выбирает существующий элемент в определённом **состоянии/позиции**.\n- **Псевдоэлемент** (`::before`, `::after`, `::first-line`, `::selection`, `::placeholder`, `::marker`) — создаёт/выбирает **виртуальную часть** элемента, которой нет в DOM.\n\n`::before/::after`:\n- **обязателен `content`** (хотя бы `content: \"\"`), иначе элемент не генерируется — самая частая причина \"не работает\";\n- по умолчанию `display: inline` — для размеров нужен `inline-block`/`block`;\n- **не работают на replaced-элементах** (`img`, `input`, `br`), т.к. у них нет содержимого для вставки до/после;\n- являются детьми элемента (внутри него), а не соседями.\n\nСинтаксис: один двоеточие (`:before`) — это устаревший CSS2-синтаксис псевдоэлементов, оставлен для совместимости; современный — два (`::before`)."}'::jsonb, ARRAY['pseudo-elements', 'pseudo-classes', 'selectors']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('b203ca33-0835-a24f-e1fb-4d0deef0208f', '89951beb-2642-54fc-93aa-fc2806df7ae6', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('a9b7a5b2-c472-d549-cfe6-cb84f56435bf', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Как работает :nth-child() и чем он отличается от :nth-of-type()? Что значит формула an+b?","Back":"`:nth-child(an+b)` считает позицию среди **всех** детей родителя; `:nth-of-type(an+b)` — среди детей **того же тега**.\n\n```css\nli:nth-child(2n)      /* чётные: 2,4,6 */\nli:nth-child(2n+1)    /* нечётные: 1,3,5 (== odd) */\nli:nth-child(3)       /* третий */\nli:nth-child(-n+3)    /* первые три */\nli:nth-last-child(2)  /* второй с конца */\np:nth-of-type(odd)    /* нечётные именно <p> */\n```\n\n`n` идёт 0,1,2,...; `a` — шаг, `b` — смещение.\n\n**Ловушка:** `p:nth-child(2)` сработает, только если 2-й ребёнок вообще `<p>`. Если перед `<p>` стоит `<h2>`, то `p:nth-child(2)` выберет p на позиции 2, а не \"второй параграф\". Когда нужен именно второй параграф независимо от других тегов — `:nth-of-type`.\n\nСовременная альтернатива: `:nth-child(2 of .item)` — n-й среди детей, **подходящих под селектор**."}'::jsonb, ARRAY['pseudo-classes', 'nth-child', 'selectors']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('bb3b2530-c232-bd28-9c20-ec05089d27b3', 'a9b7a5b2-c472-d549-cfe6-cb84f56435bf', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('d41d21f3-cb7f-d621-5432-b7a3d92de4cb', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"В чём разница :focus, :focus-within и :focus-visible? Почему :focus-visible важен для UX?","Back":"- **`:focus`** — элемент в фокусе (любым способом: мышь, клавиатура, программно).\n- **`:focus-within`** — элемент **или любой его потомок** в фокусе. Полезно подсветить всю форму/группу при фокусе на инпуте без JS.\n- **`:focus-visible`** — фокус, который браузер по эвристике считает заслуживающим видимой обводки (как правило, навигация **с клавиатуры**, а не клик мышью).\n\n**Зачем `:focus-visible`:** раньше дизайнеры убирали `outline: none` ради эстетики кликов мышью и ломали доступность для клавиатурных пользователей. Теперь правильный паттерн:\n\n```css\n:focus { outline: none; }\n:focus-visible { outline: 2px solid #06f; outline-offset: 2px; }\n```\n\nМышь не показывает обводку, Tab — показывает. Никогда не убирай фокус-индикатор глобально без замены."}'::jsonb, ARRAY['pseudo-classes', 'focus', 'accessibility']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('4d3118ae-9a00-0952-bf4a-dd3712c13fda', 'd41d21f3-cb7f-d621-5432-b7a3d92de4cb', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('20a3d443-e259-e6ea-8b56-efb2a5c68e90', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Какие типы input существуют и зачем они нужны помимо визуала? Что даёт правильный type на мобильных?","Back":"Тип влияет не только на вид, но и на **поведение, валидацию и UX**:\n- `email`, `url`, `tel`, `number`, `search` — на мобильных вызывают **подходящую клавиатуру** (цифровую, с @ и т.д.), дают встроенную валидацию формата (email/url).\n- `date`, `time`, `datetime-local`, `month`, `week` — нативные пикеры.\n- `range` — слайдер; `color` — color picker; `file` — выбор файла (+ `accept`, `multiple`, `capture`).\n- `checkbox`/`radio` — группируются по `name`.\n- `password`, `hidden`.\n\n**Нюансы:**\n- `type=number` не подходит для телефонов/карт (режет ведущие нули, spinner мешает) — лучше `type=tel` + `inputmode`.\n- Тонкий контроль клавиатуры — атрибут **`inputmode`** (`numeric`, `decimal`, `tel`) независимо от type.\n- `autocomplete` (`email`, `name`, `cc-number`...) критичен для автозаполнения и менеджеров паролей.\n- Валидацию из `type=email` всё равно дублируй на бэке — клиент не доверенный."}'::jsonb, ARRAY['forms', 'input', 'mobile']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('a0df8ce4-6245-8cee-2d4d-77511c8f9474', '20a3d443-e259-e6ea-8b56-efb2a5c68e90', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('af1d2da2-f577-a547-b010-035f3bcf56a4', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Как устроена нативная HTML-валидация форм (Constraint Validation API) и её псевдоклассы? Как кастомизировать сообщения?","Back":"Атрибуты ограничений: `required`, `min`/`max`, `minlength`/`maxlength`, `pattern`, `step`, тип (`email`/`url`).\n\n**Псевдоклассы состояния:** `:valid`, `:invalid`, `:required`, `:optional`, `:in-range`/`:out-of-range`, `:user-invalid` (новее — срабатывает только после взаимодействия, не сразу при загрузке).\n\n**JS API (Constraint Validation):**\n```js\ninput.validity         // ValidityState: valueMissing, typeMismatch, patternMismatch...\ninput.checkValidity()  // bool + событие invalid\ninput.reportValidity() // покажет нативную подсказку\ninput.setCustomValidity(''Свой текст'') // делает поле invalid; '''' — сбрасывает\nform.noValidate        // отключить нативную валидацию\n```\n\n**Подводные камни:**\n- `:invalid` срабатывает сразу при загрузке у пустых required-полей — раздражает; используй `:user-invalid` или класс через JS после blur/submit.\n- Стилизовать нативные тултипы нельзя — для кастомного UI делают `novalidate` + своя логика на `validity`.\n- `pattern` работает без флагов и якорится неявно (матч всей строки)."}'::jsonb, ARRAY['forms', 'validation', 'constraint-validation-api']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('1b007dee-3e56-9f04-7c31-9ec991814440', 'af1d2da2-f577-a547-b010-035f3bcf56a4', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('e47fe167-1375-dc72-468a-508a16534591', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Что критично для доступности форм (a11y)? Как правильно связать label и input?","Back":"**Связь label↔input** (обязательно — клик по подписи фокусирует поле, скринридер озвучивает):\n```html\n<label for=\"email\">Email</label><input id=\"email\">\n<!-- или оборачиванием -->\n<label>Email <input></label>\n```\n\n**Ключевое:**\n- `placeholder` — НЕ замена label (исчезает, низкий контраст, не озвучивается стабильно).\n- Группы radio/checkbox оборачивай в `<fieldset>` + `<legend>`.\n- Ошибки: `aria-invalid=\"true\"` + `aria-describedby` указывает на элемент с текстом ошибки; контейнер ошибок — `role=\"alert\"`/`aria-live` для озвучки.\n- Обязательность: атрибут `required` (+ визуальная пометка), не только звёздочка.\n- `autocomplete` помогает не только UX, но и когнитивной доступности.\n- Используй нативные элементы (`<button>`, `<select>`) вместо div+role — они дают фокус, клавиатуру и семантику бесплатно.\n- Кнопка отправки должна быть `<button type=\"submit\">` (Enter в поле сабмитит форму)."}'::jsonb, ARRAY['forms', 'accessibility', 'aria']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('052b3fa9-e1f3-8d07-29f7-30aa9f2018c8', 'e47fe167-1375-dc72-468a-508a16534591', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('204a1fd8-29b6-4051-4fb5-b063e1d8bd91', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Как сделать адаптивные изображения через srcset, sizes и picture? В чём разница между resolution switching и art direction?","Back":"**Resolution switching** (один и тот же кадр, разный размер/плотность) — `srcset` + `sizes` на `<img>`:\n```html\n<img\n  src=\"img-800.jpg\"\n  srcset=\"img-400.jpg 400w, img-800.jpg 800w, img-1600.jpg 1600w\"\n  sizes=\"(max-width: 600px) 100vw, 50vw\"\n  alt=\"...\">\n```\nБраузер сам выбирает файл по ширине слота (`sizes`) и DPR экрана. `w`-дескрипторы + `sizes` — для отзывчивой ширины; `x`-дескрипторы (`img.jpg 2x`) — для фикс. размера под Retina.\n\n**Art direction** (разный КАДР/кроп под брейкпоинт) — `<picture>`:\n```html\n<picture>\n  <source media=\"(max-width:600px)\" srcset=\"crop-mobile.jpg\">\n  <source srcset=\"wide.jpg\">\n  <img src=\"wide.jpg\" alt=\"...\">\n</picture>\n```\n`<picture>` также для **форматов**: `<source type=\"image/avif\">`, `type=\"image/webp\"` с fallback на `<img>` (jpg). `<img>` внутри `<picture>` обязателен — он и рендерится, source лишь подменяет источник."}'::jsonb, ARRAY['media', 'responsive-images', 'srcset', 'picture']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('187578df-cc62-f9b5-a290-bba31ccad243', '204a1fd8-29b6-4051-4fb5-b063e1d8bd91', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('3e4f2de4-655c-474c-e029-ada963395c4f', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Как работает lazy loading медиа и как избежать сдвига макета (CLS)? Что такое decoding и fetchpriority?","Back":"**Нативный lazy-load:** `loading=\"lazy\"` на `<img>`/`<iframe>` — браузер откладывает загрузку, пока элемент не приблизится к вьюпорту. Для контента \"выше сгиба\" (LCP) ставь `loading=\"eager\"` или ничего.\n\n**Предотвращение CLS (layout shift):** всегда указывай `width`+`height` (или `aspect-ratio`) — браузер резервирует место до загрузки:\n```html\n<img src=\"x.jpg\" width=\"800\" height=\"600\" alt=\"\"> /* считает aspect-ratio */\n```\n\n**Дополнительно:**\n- `decoding=\"async\"` — декодировать вне основного потока, чтобы не блокировать.\n- `fetchpriority=\"high\"` на LCP-картинке + `<link rel=\"preload\">` ускоряют ключевое изображение; `fetchpriority=\"low\"` для второстепенных.\n- Для `<video>`: `preload=\"none|metadata|auto\"`, `poster`, `playsinline`, `muted` (нужен для autoplay на мобильных).\n- Не лениво грузи LCP-картинку — это замедлит метрику."}'::jsonb, ARRAY['media', 'lazy-loading', 'performance', 'cls']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('2b36a874-3402-09e6-5bca-129d20d6ba71', '3e4f2de4-655c-474c-e029-ada963395c4f', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('18bf0b28-b27a-08be-2a06-6bfc98fdf39f', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Объясни модель Flexbox: главная/поперечная ось и как работают justify-content, align-items, align-content.","Back":"Flex — одномерная раскладка вдоль **главной оси** (задаётся `flex-direction: row|column`); перпендикулярная — **поперечная**.\n\n- **`justify-content`** — распределение по **главной** оси: `flex-start`, `center`, `space-between`, `space-around`, `space-evenly`.\n- **`align-items`** — выравнивание по **поперечной** оси для каждого элемента: `stretch` (дефолт), `center`, `flex-start`, `baseline`.\n- **`align-self`** — переопределяет align-items для одного элемента.\n- **`align-content`** — распределение **рядов** по поперечной оси; работает **только при `flex-wrap: wrap`** и наличии нескольких рядов. На одной строке не действует — частая путаница.\n- **`gap`** — отступы между элементами (заменяет хаки с margin).\n\nПри смене `flex-direction: column` оси меняются местами: justify-content теперь вертикаль, align-items — горизонталь."}'::jsonb, ARRAY['flexbox', 'alignment', 'layout']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('84e3aa5e-8512-2546-8134-282fbd9c5bb7', '18bf0b28-b27a-08be-2a06-6bfc98fdf39f', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('cc25e02c-314a-c79f-4bb2-01eafebe33ce', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Что такое flex-grow, flex-shrink, flex-basis и что значит shorthand flex: 1? Как считается итоговый размер?","Back":"`flex: <grow> <shrink> <basis>`.\n- **`flex-basis`** — базовый размер вдоль главной оси ДО распределения (имеет приоритет над width/height; `auto` = смотреть на content/width).\n- **`flex-grow`** — коэффициент распределения **свободного** места. 0 — не растёт. Если у троих grow 1/1/2 — третий получит вдвое больше излишка.\n- **`flex-shrink`** — коэффициент **сжатия** при нехватке места (учитывается взвешенно по basis). 0 — не сжимается (частый фикс \"расплющивания\" иконок).\n\n**Shorthands:**\n- `flex: 1` = `1 1 0%` — элементы делят всё место поровну, игнорируя контент.\n- `flex: auto` = `1 1 auto` — растут, но учитывают свой контент.\n- `flex: none` = `0 0 auto` — фиксированный, не тянется/не жмётся.\n- `flex: 0 1 auto` — дефолт.\n\n**Нюанс:** `flex: 1` (basis 0) и `flex: 1 1 auto` ведут себя по-разному при разном контенте — первый делит ровно, второй пропорционально содержимому."}'::jsonb, ARRAY['flexbox', 'flex-grow', 'flex-basis']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('6e309e5e-397e-c426-8b1a-5c25009fbfd4', 'cc25e02c-314a-c79f-4bb2-01eafebe33ce', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('e554c402-840a-eaaf-6a69-e535168c9f22', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Как объявлять CSS Grid и в чём его отличие от Flexbox? Когда что выбирать?","Back":"**Grid — двумерная** раскладка (строки И столбцы одновременно); **Flex — одномерная** (один ряд/колонка с переносом).\n\n```css\n.grid {\n  display: grid;\n  grid-template-columns: 200px 1fr 1fr;  /* fr = доля свободного места */\n  grid-template-rows: auto 1fr;\n  gap: 16px;\n}\n```\n\n**Выбор:**\n- Grid — макет страницы/секции, где важно совмещение по обеим осям, выравнивание в \"сетку\", перекрытие ячеек.\n- Flex — компоненты-ряды: тулбары, списки тегов, выравнивание содержимого, когда количество элементов заранее неизвестно и важен перенос/распределение по одной оси.\n\nОни **комбинируются**: Grid для скелета страницы, Flex внутри ячеек. Grid позволяет верстать \"от макета\" (`grid-template-areas`), не завися от порядка элементов в HTML."}'::jsonb, ARRAY['grid', 'flexbox', 'layout']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('7b23b39e-acca-c0de-a038-7b823f0a4de7', 'e554c402-840a-eaaf-6a69-e535168c9f22', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('5ce67702-c0d5-9e58-1467-3fc73e200e74', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Объясни auto-fit vs auto-fill и minmax() в Grid. Как сделать адаптивную сетку карточек без media-queries?","Back":"Классический адаптивный паттерн:\n```css\n.cards {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));\n  gap: 16px;\n}\n```\n`minmax(250px, 1fr)` — колонка не уже 250px, но тянется до равной доли. Карточки сами переносятся при сужении — **без media-queries**.\n\n**auto-fill vs auto-fit** (разница видна, когда элементов меньше, чем влезает колонок):\n- **`auto-fill`** — создаёт максимум колонок, **оставляя пустые** треки. Существующие карточки НЕ растягиваются на всю ширину — остаётся \"дырка\" справа.\n- **`auto-fit`** — \"схлопывает\" пустые треки до 0, и существующие карточки **растягиваются** на всю доступную ширину.\n\nЧаще нужен `auto-fit` (карточки занимают всю строку). `auto-fill` — когда важна стабильная ширина ячейки и не нужно растягивать неполный ряд."}'::jsonb, ARRAY['grid', 'auto-fit', 'minmax', 'responsive']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('dd560313-866c-5299-00a1-1d1dae5ae2ad', '5ce67702-c0d5-9e58-1467-3fc73e200e74', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('c522a0bc-75ff-bdcb-1baa-b88a1a4755e5', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Как использовать grid-template-areas и разные способы размещения элементов в Grid?","Back":"**Areas** — наглядная раскладка \"картинкой\":\n```css\n.layout {\n  display: grid;\n  grid-template-columns: 200px 1fr;\n  grid-template-rows: auto 1fr auto;\n  grid-template-areas:\n    \"header header\"\n    \"sidebar main\"\n    \"footer footer\";\n}\n.header  { grid-area: header; }\n.sidebar { grid-area: sidebar; }\n```\nИмена должны образовывать **прямоугольники**; `.` — пустая ячейка. Легко переставить блоки под мобильный, переписав areas в media-query, не трогая HTML.\n\n**Другие способы:**\n- Линиями: `grid-column: 1 / 3;` `grid-row: 1 / span 2;` (span — на сколько треков).\n- Именованные линии: `grid-template-columns: [start] 1fr [mid] 1fr [end];` затем `grid-column: start / mid`.\n- Выравнивание: `justify-items`/`align-items` (ячейки), `justify-content`/`align-content` (вся сетка), `place-items`/`place-content` — шорткаты."}'::jsonb, ARRAY['grid', 'grid-template-areas', 'layout']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('90ef9484-14f6-d03d-7df9-57627cf825e7', 'c522a0bc-75ff-bdcb-1baa-b88a1a4755e5', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('820eb57d-4dbf-f10f-5aa3-6d432e5319bb', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Как рассчитывается специфичность селекторов? Объясни тройку (a,b,c) и роль !important, inline-стилей и каскадных слоёв.","Back":"Специфичность — кортеж **(A, B, C)**, сравнивается слева направо:\n- **A** — id-селекторы (`#id`).\n- **B** — классы, атрибуты (`[type]`), псевдоклассы (`:hover`).\n- **C** — теги и псевдоэлементы (`div`, `::before`).\n\n`*`, комбинаторы (`>`, `+`, `~`, ` `), `:where()` — **0**. `:not()/:is()/:has()` сами по нулю, но берут специфичность **самого тяжёлого аргумента** внутри.\n\n**Порядок переопределения (грубо сверху вниз):**\n1. inline `style=\"\"` (как будто 1,0,0,0);\n2. сравнение специфичности; при равенстве — **кто позже в источнике**;\n3. `!important` инвертирует приоритеты (important-объявления соревнуются между собой, и там слои/origin идут в обратном порядке);\n4. **`@layer`** (каскадные слои) идут НИЖЕ специфичности по приоритету слоёв: правило из более позднего слоя бьёт более ранний независимо от специфичности.\n\n**Практика:** избегай `!important` и id в стилях; используй `@layer` и `:where()` для управляемой низкой специфичности (удобно для библиотек/перекрытий)."}'::jsonb, ARRAY['specificity', 'cascade', 'important']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('3f5b866c-4235-72ff-6c90-ff17082aa7c6', '820eb57d-4dbf-f10f-5aa3-6d432e5319bb', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('8e5bb02c-9078-8331-0161-89a271a9c055', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Какие есть комбинаторы селекторов и чем отличаются потомок, ребёнок, соседи? Что нового даёт :has()?","Back":"- **` ` (потомок)** — `.a .b` — любой `.b` внутри `.a` на любой глубине.\n- **`>` (дочерний)** — `.a > .b` — только прямой ребёнок.\n- **`+` (соседний)** — `.a + .b` — `.b` сразу после `.a` (один).\n- **`~` (общий сосед)** — `.a ~ .b` — все `.b` после `.a` у общего родителя.\n\n**`:has()` — \"родительский\" селектор**, прорыв последних лет:\n```css\nlabel:has(input:checked) { font-weight: bold; }  /* стилизуем по состоянию ребёнка */\n.card:has(> img) { padding: 0; }                  /* родитель по наличию ребёнка */\nh2:has(+ p) { margin-bottom: 0; }                 /* по соседу справа */\n```\nДо `:has()` \"подняться вверх\" по дереву в CSS было невозможно — только JS. Теперь можно реагировать на наличие/состояние потомков и соседей. Учитывай производительность при очень общих `:has` на больших деревьях."}'::jsonb, ARRAY['combinators', 'selectors', 'has']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('762bd728-5730-81ae-5805-14a0668be87c', '8e5bb02c-9078-8331-0161-89a271a9c055', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('d2978fd5-4346-bc75-40d0-cab5e864b6e0', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Что такое БЭМ и какую проблему он решает? Покажи именование Block__Element--Modifier и типичные ошибки.","Back":"**БЭМ (Block-Element-Modifier)** — методология именования классов для **плоской низкой специфичности** и переиспользуемости компонентов без вложенных селекторов.\n\n- **Block** — самостоятельная сущность: `.card`, `.menu`.\n- **Element** — часть блока, не существует отдельно: `.card__title`, `.menu__item` (двойное подчёркивание).\n- **Modifier** — вариант/состояние: `.card--featured`, `.menu__item--active` (двойной дефис).\n\n```html\n<div class=\"card card--featured\">\n  <h3 class=\"card__title\">...</h3>\n</div>\n```\n\n**Зачем:** все селекторы — один класс (специфичность 0,1,0), нет каскадных войн, легко искать по коду, стили не текут.\n\n**Типичные ошибки:**\n- цепочки элементов `.card__body__title` — БЭМ плоский, элемент именуется от блока: `.card__title`;\n- модификатор без базового класса (`.card--featured` без `.card`);\n- использование тегов/вложенности вместо классов (теряется суть).\n\nВ Vue с `scoped`-стилями БЭМ часто избыточен, но полезен в дизайн-системах и больших общих стилях."}'::jsonb, ARRAY['bem', 'methodology', 'naming']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('01566ce3-3d6e-8d04-7c46-244cb9e089be', 'd2978fd5-4346-bc75-40d0-cab5e864b6e0', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('08e900ad-3434-6349-9dd4-fb583cf35e23', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Чем отличаются DOM и CSSOM? Как они объединяются в Render Tree?","Back":"- **DOM (Document Object Model)** — дерево, построенное из HTML; узлы — элементы, текст, комментарии. Строится инкрементально по мере парсинга.\n- **CSSOM (CSS Object Model)** — дерево стилей из всех источников (внешние, `<style>`, inline, user-agent). Содержит вычисленные правила и каскад.\n\n**Render Tree** = DOM + CSSOM. В него попадают только **видимые** узлы:\n- `display: none` — узла НЕТ в render tree (не занимает места, не рендерится);\n- `visibility: hidden` — узел ЕСТЬ (занимает место, но невидим);\n- псевдоэлементы (`::before`) — в DOM их нет, но в render tree есть;\n- `<head>`, `<script>` и т.п. — не визуальные, исключаются.\n\nCSSOM **блокирует рендеринг**: браузер не строит render tree, пока не загрузит и не распарсит CSS, чтобы не показать неотстилизованный контент (FOUC). Поэтому CSS считается render-blocking ресурсом."}'::jsonb, ARRAY['dom', 'cssom', 'render-tree']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('f3b1c1d3-0024-d5e9-82fe-30a4fe1a1db1', '08e900ad-3434-6349-9dd4-fb583cf35e23', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('85179945-7cdd-055f-5698-664b430ee9f3', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Опиши Critical Rendering Path. Почему CSS блокирует рендеринг, а скрипты — парсинг? Что делают async и defer?","Back":"**Critical Rendering Path:** HTML → DOM, CSS → CSSOM → **Render Tree** → **Layout** (геометрия) → **Paint** (пиксели) → **Composite** (слои).\n\n**CSS блокирует рендеринг:** браузер не паинтит, пока CSSOM не готов (иначе мелькнёт неотстилизованная страница). Поэтому CSS грузят в `<head>`, минимизируют критический CSS, некритичный — `media`/`preload`.\n\n**Скрипт блокирует парсинг:** встретив `<script>` без атрибутов, парсер останавливает построение DOM, скачивает и выполняет JS (т.к. JS может менять DOM/CSSOM через `document.write`). Более того, скрипт ждёт завершения предшествующего CSSOM.\n\n**Атрибуты `<script>`:**\n- без атрибутов — блокирует парсинг, выполняется сразу.\n- **`defer`** — грузится параллельно, выполняется **после** парсинга DOM, **в порядке** объявления (идеально для скриптов, зависящих от DOM).\n- **`async`** — грузится параллельно, выполняется **сразу по готовности**, порядок не гарантирован (для независимых скриптов: аналитика).\n- `type=\"module\"` — defer по умолчанию."}'::jsonb, ARRAY['critical-rendering-path', 'render-blocking', 'async-defer']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('aee18c53-c258-1f24-a797-5935a4ada534', '85179945-7cdd-055f-5698-664b430ee9f3', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('956cf8be-293a-f943-6029-a0f6c69bba87', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Чем отличаются reflow (layout), repaint и composite? Какие свойства анимировать дёшево и почему?","Back":"Этапы при изменении:\n- **Reflow / Layout** — пересчёт геометрии (размеры, позиции). Самый дорогой: меняет один элемент — может пересчитать соседей/предков. Триггеры: width/height, top/left, margin, font-size, добавление/удаление узлов, чтение `offsetWidth`/`getBoundingClientRect` (форсирует синхронный layout — **layout thrashing**).\n- **Repaint** — перерисовка пикселей без изменения геометрии: `color`, `background`, `box-shadow`, `visibility`.\n- **Composite** — сборка готовых слоёв на GPU без layout и paint.\n\n**Дёшево анимировать `transform` и `opacity`** — они обрабатываются на стадии composite (GPU), пропуская layout и paint. Поэтому `transform: translate()` вместо `top/left`, `transform: scale()` вместо width/height.\n\n**Оптимизации:**\n- `will-change: transform` — заранее поднять элемент в свой слой (не злоупотреблять — память).\n- группировать чтения/записи DOM, избегать чтения геометрии в цикле после записи.\n- `contain: layout/paint` — ограничить область пересчёта."}'::jsonb, ARRAY['reflow', 'repaint', 'composite', 'performance']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('196ed222-a757-1448-e27c-7eb1bd4db44b', '956cf8be-293a-f943-6029-a0f6c69bba87', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('4498805f-27cb-57da-e8fe-90e4b15310ca', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Из каких основных компонентов состоит браузер? За что отвечает рендеринг-движок и его потоки?","Back":"**Компоненты браузера:**\n- **User Interface** — адресная строка, кнопки, вкладки (всё, кроме области страницы).\n- **Browser Engine** — посредник между UI и рендеринг-движком.\n- **Rendering Engine** — парсит HTML/CSS и рисует страницу (Blink в Chrome/Edge, WebKit в Safari, Gecko в Firefox).\n- **Networking** — HTTP-запросы, кэш.\n- **JS Engine** — исполняет JS (V8 в Blink, JavaScriptCore, SpiderMonkey).\n- **UI Backend** — отрисовка базовых виджетов через ОС.\n- **Data Storage** — cookies, localStorage, IndexedDB, Cache API.\n\n**Внутри рендеринга (Chrome, мультипроцессность):**\n- браузер-процесс, **процесс рендеринга на сайт** (изоляция), GPU-процесс, сетевой/плагин-процессы.\n- В рендер-процессе: **main thread** (парсинг, JS, style, layout, paint-инструкции), **compositor thread** и **raster threads** (собирают слои на GPU, могут скроллить/анимировать transform независимо от main thread — отсюда плавность composite-анимаций даже при занятом JS)."}'::jsonb, ARRAY['browser-architecture', 'rendering-engine', 'internals']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('3e16d631-e92d-9260-0b0a-cefce16c1485', '4498805f-27cb-57da-e8fe-90e4b15310ca', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('3777dd4a-86f1-a97b-c90b-bf396fcc2f28', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Какие есть способы изоляции стилей: Vue scoped, CSS Modules, Shadow DOM? Их механизмы и трейдоффы.","Back":"**1. Vue `<style scoped>`** — компилятор добавляет уникальный data-атрибут (`data-v-xxxx`) элементам компонента и дописывает его в селекторы (`.btn[data-v-xxxx]`). Это **атрибутная**, не настоящая изоляция: глобальные стили всё ещё могут просочиться. Для детей-компонентов нужен `:deep()`; для слотов — `:slotted()`; для глобального — `:global()`.\n\n**2. CSS Modules** — при сборке имена классов **хэшируются** (`.btn` → `.btn_a3f9`), импортируются как объект (`styles.btn`). Уникальность через переименование, работает в любом фреймворке. Нет рантайма, но нет и реальной инкапсуляции каскада/наследования.\n\n**3. Shadow DOM** — **настоящая** инкапсуляция на уровне платформы: стили внутри shadow root не текут наружу и наружные (кроме наследуемых свойств и custom properties) не текут внутрь. Граница `::part()`/`::slotted()` для контролируемого пробивания. Цена: сложнее темизация (только через CSS-переменные), нюансы с формами/событиями, SSR.\n\n**Трейдофф:** scoped/Modules — простота и совместимость, но \"мягкая\" изоляция; Shadow DOM — строгая изоляция ценой гибкости и сложности стилизации извне."}'::jsonb, ARRAY['style-isolation', 'scoped', 'css-modules', 'shadow-dom']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('ec082f67-8de6-fc6f-479d-426070690ad6', '3777dd4a-86f1-a97b-c90b-bf396fcc2f28', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('ba4eecda-a960-3d82-ed63-8a24fbdb7d6b', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Что такое семантическая вёрстка и почему она важнее div-супа? Приведи ключевые теги и их смысл.","Back":"Семантика — использование тегов **по смыслу**, а не только для вида. Даёт доступность (скринридеры, ориентиры), SEO, бесплатное поведение и читаемость.\n\n**Ключевые теги:**\n- `<header>`, `<nav>`, `<main>` (один на страницу), `<article>` (самодостаточная единица), `<section>` (тематический блок, обычно с заголовком), `<aside>`, `<footer>`.\n- `<h1>`–`<h6>` — иерархия заголовков (не прыгать через уровни, один логический h1).\n- `<button>` vs `<a>`: кнопка — действие, ссылка — навигация по URL.\n- `<figure>`+`<figcaption>`, `<time datetime>`, `<address>`, `<mark>`, `<details>`/`<summary>` (нативный аккордеон).\n\n**Почему лучше div-супа:** ARIA-роли проставляются автоматически, навигация по ориентирам (landmarks) для скринридеров, клавиатура и фокус работают из коробки, легче поддерживать. Правило ARIA №1: **не используй ARIA, если есть нативный элемент** — `role=\"button\"` на div требует руками добавлять tabindex, обработку Enter/Space и состояние."}'::jsonb, ARRAY['semantic-html', 'accessibility', 'seo']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('a4b09c97-0981-42a7-44e7-d6fe959be43a', 'ba4eecda-a960-3d82-ed63-8a24fbdb7d6b', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('07241579-95fe-4000-401f-94965b8da0c8', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Как строить адаптивную вёрстку: mobile-first, media-queries, современные единицы и container queries?","Back":"**Mobile-first:** базовые стили под узкий экран, расширяем через `min-width` — меньше переопределений, прогрессивное усложнение:\n```css\n.col { width: 100%; }\n@media (min-width: 768px) { .col { width: 50%; } }\n```\n\n**Единицы:**\n- относительные `rem`/`em`, `%`, `ch` вместо px для масштабируемости;\n- вьюпортные `vw`/`vh`, а также `svh`/`lvh`/`dvh` — учитывают динамическую панель браузера на мобильных (`dvh` подстраивается под показ/скрытие адресной строки);\n- `clamp(min, preferred, max)` — флюидный размер без брейкпоинтов: `font-size: clamp(1rem, 2vw + 1rem, 1.5rem)`.\n\n**Container Queries** — реагируют на размер **родителя-контейнера**, а не вьюпорта:\n```css\n.card-wrap { container-type: inline-size; }\n@container (min-width: 400px) { .card { display: flex; } }\n```\nПозволяет одному компоненту адаптироваться по месту вставки — то, чего media-queries не умели.\n\nНе забывай `<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">`."}'::jsonb, ARRAY['responsive', 'media-queries', 'container-queries', 'mobile-first']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('22e70e30-ce79-ed9a-d895-a70ab502e9ae', '07241579-95fe-4000-401f-94965b8da0c8', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('48e7f388-0682-1ee3-727a-9db41dfc2a92', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Чем отличаются CSS transition и animation? Что можно анимировать и какие подводные камни?","Back":"**`transition`** — плавный переход свойства **между двумя состояниями** при изменении (hover, добавление класса). Нужно событие-триггер.\n```css\n.btn { transition: transform .2s ease, background-color .2s; }\n.btn:hover { transform: scale(1.05); }\n```\n\n**`animation` + `@keyframes`** — многошаговая анимация, может зацикливаться, идти сама без триггера:\n```css\n@keyframes pulse { 0%{opacity:1} 50%{opacity:.5} 100%{opacity:1} }\n.dot { animation: pulse 1s infinite ease-in-out; }\n```\n\n**Подводные камни:**\n- Анимировать выгодно `transform`/`opacity` (composite, GPU); анимация `width`/`top`/`margin` вызывает reflow — дёргается.\n- `display: none` ↔ `block` не анимируется напрямую (хотя появляется `@starting-style` и `transition-behavior: allow-discrete` для входных анимаций и discrete-свойств).\n- `transition` на `auto` (height: auto) не работает — нужен `max-height`-хак, `grid-template-rows: 0fr→1fr` или новые API.\n- Уважай `@media (prefers-reduced-motion: reduce)` — отключай/смягчай анимации для пользователей с этой настройкой."}'::jsonb, ARRAY['css-animation', 'transition', 'keyframes', 'performance']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('01af63a0-1da5-6839-90b7-0ab788608ba2', '48e7f388-0682-1ee3-727a-9db41dfc2a92', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('87953644-54fc-3158-6756-eff0a9325d88', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Когда выбирать SVG, а когда Canvas? В чём фундаментальная разница подходов?","Back":"**SVG — векторный, ретейн-режим (декларативный):** фигуры — это **DOM-элементы** (`<path>`, `<rect>`, `<circle>`).\n- Плюсы: масштабируется без потери качества, доступен (можно `aria`, текст индексируется), стилизуется CSS, реагирует на события мышью по элементам, легко анимировать.\n- Минусы: тяжелеет при тысячах элементов (каждый — узел DOM), производительность падает.\n- Применение: иконки, логотипы, графики/диаграммы, иллюстрации, интерактивные схемы.\n\n**Canvas — растровый, immediate-режим (императивный):** рисуешь пикселями через JS API, **DOM-узлов нет** — после отрисовки браузер не помнит фигуры.\n```js\nconst ctx = canvas.getContext(''2d'');\nctx.fillRect(10, 10, 100, 50);\n```\n- Плюсы: высокая производительность при многих объектах/кадрах (игры, частицы, обработка изображений, визуализации с тысячами точек), есть WebGL/WebGPU для 3D.\n- Минусы: не масштабируется (зависит от разрешения, нужен учёт DPR), нет встроенной доступности и hit-testing (всё руками), события только на весь canvas.\n\n**Правило:** мало объектов + интерактивность/доступность/масштаб → SVG; много объектов + частая перерисовка → Canvas."}'::jsonb, ARRAY['svg', 'canvas', 'graphics', 'performance']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('03a8828c-326f-fc57-6b2f-914f04e182da', '87953644-54fc-3158-6756-eff0a9325d88', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('fe1f5173-c3eb-5fa3-719f-297eac493c5b', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Что такое PostCSS и чем он отличается от препроцессоров вроде Sass? Назови ключевые плагины.","Back":"**PostCSS** — это **инструмент для трансформации CSS через JS-плагины**, а не язык. Он парсит CSS в AST, прогоняет через цепочку плагинов и сериализует обратно. Сам по себе ничего не делает — всё определяют плагины.\n\n**Отличие от Sass/Less:** препроцессор — это монолитный язык с фиксированным набором фич (переменные, вложенность, миксины), компилируемый в CSS. PostCSS — **модульный конвейер**: подключаешь только нужное, можешь писать свои плагины. Их часто используют вместе (Sass → CSS → PostCSS).\n\n**Ключевые плагины:**\n- **autoprefixer** — добавляет вендорные префиксы по данным Can I Use + browserslist.\n- **postcss-preset-env** — позволяет писать будущий CSS (nesting, custom-media, `:has`), транспилируя под цель.\n- **cssnano** — минификация.\n- **postcss-import** — инлайнит `@import`.\n- **Tailwind CSS** — построен как PostCSS-плагин.\n- **postcss-nested**, **postcss-custom-properties** (фолбэки для старых браузеров).\n\nКонфиг — `postcss.config.js`; browserslist управляет тем, под какие браузеры транспилировать/префиксить."}'::jsonb, ARRAY['postcss', 'tooling', 'autoprefixer', 'build']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('0d64fe85-9274-83ee-a4a9-9280d6b9f13c', 'fe1f5173-c3eb-5fa3-719f-297eac493c5b', '55555555-5555-5555-5555-555555550003', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('fa5a4719-5d7f-f32d-ccb5-77e887ee0ed2', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550003', '{"Front":"Что такое блочно-строчная модель и box-sizing? Чем content-box отличается от border-box и зачем margin collapse?","Back":"**Box model:** каждый элемент = content → padding → border → margin (изнутри наружу).\n\n**`box-sizing`:**\n- `content-box` (дефолт) — `width` = только контент; padding и border **прибавляются** сверху. Итоговая ширина = width + padding + border. Неудобно для раскладки.\n- `border-box` — `width` включает content + padding + border. Зада­ёшь `width: 200px` — элемент ровно 200px. Общепринятый сброс:\n```css\n*, *::before, *::after { box-sizing: border-box; }\n```\n\n**Margin collapse (схлопывание вертикальных отступов):** соседние вертикальные margin не суммируются, а берётся **больший**. Также margin ребёнка может \"вытечь\" за родителя без границы/паддинга/overflow между ними.\n- Схлопываются: соседние блоки, родитель/первый-последний ребёнок, пустые блоки.\n- НЕ схлопываются: горизонтальные margin, во flex/grid-контейнерах, при наличии border/padding/`overflow != visible`, у float/absolute.\n\nЭто частый источник \"лишних\" отступов; flex/grid с `gap` устраняет проблему."}'::jsonb, ARRAY['box-model', 'box-sizing', 'margin-collapse']::text[]) on conflict (id) do nothing;
