insert into anki.decks (id, name, description, config) values ('55555555-5555-5555-5555-555555550004', 'Собеседование · Vue 3', 'Подготовка к собеседованию: Vue', '{"newCardsPerDay":30,"maxReviewsPerDay":300}'::jsonb) on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('8959b59e-75f0-e767-2b19-d0edd20f0c95', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Чем Options API отличается от Composition API и когда что выбирать?","Back":"**Options API** — код организован по \"опциям\" компонента: `data`, `methods`, `computed`, `watch`, хуки. Логика одной фичи размазана по разным секциям.\n\n**Composition API** — код организован по логическим зонам ответственности через `setup()` / `<script setup>`. Логику можно выносить в **композаблы** (`useX()`) и переиспользовать без миксинов.\n\nКлючевые отличия:\n- **Переиспользование логики**: Composition API через композаблы решает проблемы миксинов (неявные коллизии имён, непрозрачный источник свойств).\n- **Типизация**: Composition API даёт куда лучший вывод типов в TS (нет магии `this`).\n- **Tree-shaking**: импортируемые API (`ref`, `computed`) шейкаются.\n- **`this`**: в `<script setup>` его нет — меньше путаницы с контекстом.\n\nКогда что:\n- **Composition API / `<script setup>`** — дефолт для новых проектов, особенно на TS и с переиспользуемой логикой.\n- **Options API** — ок для простых компонентов, команд, привыкших к Vue 2, или когда строгая структура помогает джунам.\n\nВажно: это не взаимоисключающие парадигмы — они работают на одной реактивной системе и могут сосуществовать."}'::jsonb, ARRAY['options-api', 'composition-api', 'script-setup', 'composables']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('b9f238ce-060a-eb89-4670-0ced993df11e', '8959b59e-75f0-e767-2b19-d0edd20f0c95', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('82a47527-09b7-de03-57e5-c9ed54c10bd4', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Как устроена реактивность в Vue 3? Чем Proxy лучше Object.defineProperty из Vue 2?","Back":"Vue 3 строит реактивность на **`Proxy`**. При создании `reactive(obj)` оборачивается весь объект, и перехватываются операции `get` (для **track** — сбора зависимостей) и `set`/`deleteProperty` (для **trigger** — запуска эффектов).\n\nПреимущества `Proxy` над `Object.defineProperty` (Vue 2):\n- **Перехват добавления/удаления свойств** — больше не нужны `Vue.set`/`Vue.delete`.\n- **Реактивность массивов по индексу и `length`** работает из коробки.\n- **Поддержка `Map`/`Set`/`WeakMap`** через отдельные хендлеры.\n- **Ленивость**: вложенные объекты оборачиваются в Proxy **по требованию** при первом доступе, а не рекурсивно при инициализации — дешевле для больших структур.\n\nМеханизм отслеживания:\n1. Геттер вызывает `track(target, key)` — связывает текущий активный эффект (`activeEffect`) с парой target+key.\n2. Сеттер вызывает `trigger(target, key)` — поднимает все зависящие эффекты (рендер-функция, computed, watcher).\n\nПодводные камни:\n- Реактивность теряется при **деструктуризации** `reactive` (получаешь обычное значение, не Proxy).\n- Идентичность: `reactive(obj) !== obj` — сравнение по ссылке с оригиналом ломается.\n- Proxy не поддерживается в IE11 (для Vue 3 это не цель)."}'::jsonb, ARRAY['reactivity', 'proxy', 'track-trigger', 'vue2-vs-vue3']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('0e1011f8-8b6d-d2c1-c601-198fc11c64bc', '82a47527-09b7-de03-57e5-c9ed54c10bd4', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('eb96f4cc-ba20-426a-bbd8-f95d50e62cc5', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"ref vs reactive: в чём разница и что выбрать?","Back":"**`ref(value)`** — обёртка над любым значением (примитив или объект) с полем `.value`. В шаблоне `.value` разворачивается автоматически (auto-unwrap). Под капотом для объектов `ref` использует `reactive`.\n\n**`reactive(obj)`** — Proxy только для объектов/массивов/коллекций. К свойствам обращаешься напрямую, без `.value`.\n\nРазница и трейдоффы:\n- **Примитивы**: `reactive` для них не работает — нужен `ref`.\n- **Замена значения целиком**: `ref` можно переприсвоить (`r.value = newObj`), сохранив реактивность. `reactive`-переменную **нельзя переприсвоить** — потеряешь Proxy: `state = newObj` разорвёт связь.\n- **Деструктуризация**: при деструктуризации `reactive` свойства теряют реактивность; для `ref` это не проблема (но при деструктуризации `reactive` спасает `toRefs`).\n- **`.value`** — бойлерплейт у `ref`, но зато явно видно, что это реактивная ссылка.\n\nРекомендация (официальный стиль): использовать **`ref` как основной примитив** — единообразно для всего, проще не потерять реактивность. `reactive` — для сгруппированного состояния, где удобен прямой доступ."}'::jsonb, ARRAY['reactivity', 'ref', 'reactive', 'torefs']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('164e1591-cda2-a2dc-4710-90f47a239b23', 'eb96f4cc-ba20-426a-bbd8-f95d50e62cc5', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('363d1146-f34d-78ea-41e1-a2b2d78c91d8', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Зачем нужен toRefs / toRef и какую проблему они решают?","Back":"Проблема: при **деструктуризации** `reactive`-объекта реактивность теряется, потому что вы извлекаете обычное значение, а не реактивную связь:\n```js\nconst state = reactive({ count: 0 })\nconst { count } = state // count — обычное число, связь разорвана\n```\n\n**`toRefs(reactiveObj)`** превращает каждое свойство реактивного объекта в `ref`, сохраняющий двустороннюю связь с источником:\n```js\nconst state = reactive({ count: 0, name: ''a'' })\nconst { count, name } = toRefs(state)\ncount.value++ // state.count тоже изменится\n```\n\n**`toRef(obj, ''key'')`** делает то же для одного свойства; поддерживает и не-реактивные источники (создаёт ref, синхронизированный с полем).\n\nГлавный кейс: **возврат из композабла**. Чтобы потребитель мог деструктурировать результат без потери реактивности:\n```js\nfunction useFeature() {\n  const state = reactive({ x: 1, y: 2 })\n  return toRefs(state) // деструктуризация на стороне вызова безопасна\n}\n```\n\nНюанс: `toRefs` создаёт ref только для **существующих** на момент вызова ключей; динамически добавленные позже свойства не попадут."}'::jsonb, ARRAY['reactivity', 'torefs', 'toref', 'composables']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('6f607bda-7c6b-2090-0f3f-2995f93eabe5', '363d1146-f34d-78ea-41e1-a2b2d78c91d8', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('20a5f7bd-984b-c30b-f4c0-0744c87c597f', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Опиши жизненный цикл компонента Vue 3 и его хуки в Composition API.","Back":"Основные фазы и хуки (Options → Composition):\n- `beforeCreate`/`created` → **отсутствуют**: код `setup()` выполняется на их месте.\n- `beforeMount` → **`onBeforeMount`** — перед первой вставкой в DOM.\n- `mounted` → **`onMounted`** — DOM доступен, можно работать с рефами, запускать запросы, подписки.\n- `beforeUpdate` → **`onBeforeUpdate`** — перед перерисовкой после изменения реактивных данных.\n- `updated` → **`onUpdated`** — DOM обновлён (осторожно: не менять состояние, можно зациклить).\n- `beforeUnmount` → **`onBeforeUnmount`** — компонент ещё жив, удобно чистить таймеры/слушатели.\n- `unmounted` → **`onUnmounted`** — компонент снят.\n\nДополнительно:\n- **`onActivated` / `onDeactivated`** — для компонентов внутри `<keep-alive>`.\n- **`onErrorCaptured`** — перехват ошибок потомков.\n- **`onRenderTracked` / `onRenderTriggered`** — дев-хуки для отладки реактивных зависимостей рендера.\n\nВажные нюансы:\n- Хуки регистрируются **синхронно** внутри `setup` (или связанного с инстансом контекста) — нельзя вызывать в `setTimeout`/после `await` первой строки.\n- Можно регистрировать **несколько** колбэков одного хука — вызовутся по порядку.\n- В SSR `onMounted` и подобные **не выполняются** на сервере."}'::jsonb, ARRAY['lifecycle', 'composition-api', 'hooks', 'ssr']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('6e7a544f-6b26-3458-710e-d68096d46e07', '20a5f7bd-984b-c30b-f4c0-0744c87c597f', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('1736de22-b1bc-c43f-84cc-57c925421aa2', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"props и emits: как объявлять, валидировать и почему props read-only?","Back":"В `<script setup>`:\n```ts\nconst props = defineProps<{ id: number; title?: string }>()\nconst emit = defineEmits<{\n  (e: ''update'', value: number): void\n  (e: ''close''): void\n}>()\n```\n\n**Односторонний поток данных**: props текут сверху вниз и **read-only** в дочернем компоненте. Мутация props напрямую — антипаттерн (Vue выдаст warning в dev). Причины:\n- При следующем рендере родителя локальная мутация будет **затёрта**.\n- Теряется предсказуемость: непонятно, кто владелец данных.\n\nКак правильно \"менять\" prop:\n- Хочешь локальную копию — заведи `ref`/`computed` на основе prop.\n- Хочешь изменить у родителя — отправь `emit`, родитель обновит источник.\n\nВалидация props (Options-стиль объявления): `type`, `required`, `default`, `validator`. Для объектов/массивов `default` — фабричная функция.\n\nНюансы:\n- Деструктуризация props ломала реактивность; в новых версиях (3.5+) появилась **reactive props destructure** с дефолтами через обычный `=`.\n- `defineProps`/`defineEmits` — **макросы компилятора**, их не нужно импортировать, работают только в `<script setup>`.\n- Невалидированные/необъявленные атрибуты попадают в **fallthrough attributes** (`$attrs`)."}'::jsonb, ARRAY['props', 'emits', 'one-way-data-flow', 'script-setup']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('80cfe6ca-2477-4d07-0308-bf293df23096', '1736de22-b1bc-c43f-84cc-57c925421aa2', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('a6d064f8-35b9-51ad-0e3d-ea2aab640598', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Как работает v-model на компоненте в Vue 3 и чем отличается от Vue 2?","Back":"`v-model` — синтаксический сахар над парой prop + событие.\n\nВ Vue 3 (до 3.4) дефолт: prop **`modelValue`** + событие **`update:modelValue`**:\n```vue\n<Child v-model=\"text\" />\n<!-- разворачивается в -->\n<Child :model-value=\"text\" @update:model-value=\"text = $event\" />\n```\n\nОтличия от Vue 2:\n- В Vue 2 дефолтный prop был `value` + событие `input`; кастомизация — через опцию `model`.\n- Vue 3 разрешает **несколько `v-model`** с аргументом: `v-model:title`, `v-model:content` (prop `title` + `update:title`).\n- **Кастомные модификаторы**: `v-model.capitalize` → доступен через `modelModifiers`.\n\nС Vue **3.4+** появился макрос **`defineModel()`** — рекомендуемый способ:\n```ts\nconst model = defineModel<string>()\n// или с аргументом\nconst title = defineModel<string>(''title'', { required: true })\nmodel.value = ''new'' // автоматически эмитит update:modelValue\n```\n`defineModel` возвращает ref, двусторонне связанный с родителем, и убирает бойлерплейт prop+emit."}'::jsonb, ARRAY['v-model', 'definemodel', 'two-way-binding', 'vue2-vs-vue3']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('8766336b-a9c7-1bd8-56dc-3df319e026e0', 'a6d064f8-35b9-51ad-0e3d-ea2aab640598', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('34460705-12dd-2ada-1180-555163389de8', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Слоты: default, named и scoped — как работают и в чём разница?","Back":"Слоты — механизм передачи **разметки** от родителя в дочерний компонент (паттерн composition вместо props-каши).\n\n**Default slot** — безымянный контент:\n```vue\n<!-- Child --> <slot>дефолт, если ничего не передали</slot>\n<!-- Parent --> <Child>контент</Child>\n```\n\n**Named slots** — несколько точек вставки:\n```vue\n<!-- Child --> <slot name=\"header\" /> <slot /> <slot name=\"footer\" />\n<!-- Parent -->\n<Child>\n  <template #header>Шапка</template>\n  Тело (default)\n  <template #footer>Подвал</template>\n</Child>\n```\n\n**Scoped slots** — дочерний компонент **передаёт данные наверх** в слот (инверсия: ребёнок владеет данными, родитель — разметкой):\n```vue\n<!-- Child --> <slot :item=\"item\" :index=\"i\" />\n<!-- Parent -->\n<Child v-slot=\"{ item, index }\">{{ index }}: {{ item.name }}</Child>\n```\nКлассический кейс — рендерлесс-компоненты (списки, таблицы, `<RouterView>`-подобные).\n\nНюансы:\n- Доступ к слотам в JS — через `useSlots()` / `slots` в render-функции.\n- Проверка наличия слота: `slots.header?.()` или `$slots.header`.\n- Слоты компилируются в **функции** — контент создаётся в скоупе родителя, но рендерится ребёнком.\n- Динамическое имя: `<template #[dynamicName]>`."}'::jsonb, ARRAY['slots', 'scoped-slots', 'named-slots', 'renderless']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('1f54963d-1268-66ff-3e4a-5844b8dd65ce', '34460705-12dd-2ada-1180-555163389de8', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('06718d70-9097-7082-62ee-23980531ef7f', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"provide / inject: как работает и как сделать реактивным?","Back":"**`provide(key, value)`** в предке делает значение доступным всем потомкам через **`inject(key, default?)`**, минуя проброс props по цепочке (prop drilling). Работает на любую глубину.\n\nРеактивность:\n- Если **provide-ить `ref`/`reactive`**, потомки получат реактивное значение — изменение источника обновит инжекторы:\n```ts\n// предок\nconst theme = ref(''dark'')\nprovide(''theme'', theme)\n// потомок\nconst theme = inject(''theme'') // ref, реактивен\n```\n- Если provide-ить **примитив** (`provide(''x'', 1)`) — реактивности не будет.\n\nЛучшие практики:\n- **Менять состояние должен provider**, а не потомок. Чтобы дать потомку контролируемый способ менять — провайдь и функцию-мутатор:\n```ts\nprovide(''theme'', { theme, setTheme: (v) => theme.value = v })\n```\n- Для **read-only** оборачивай в `readonly(state)`, чтобы потомки не мутировали напрямую.\n- Используй **`Symbol` или типизированный `InjectionKey<T>`** как ключ — избегаешь коллизий имён и получаешь типы:\n```ts\nimport { InjectionKey } from ''vue''\nconst key: InjectionKey<Ref<string>> = Symbol(''theme'')\n```\n\nГраницы применения: provide/inject хорош для \"вертикальных\" зависимостей (тема, локаль, форма), но для глобального общего состояния лучше **Pinia** — у него devtools, SSR, явная структура."}'::jsonb, ARRAY['provide-inject', 'reactivity', 'injection-key', 'dependency-injection']::text[]) on conflict (id) do nothing;
