insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('2e2ee184-3ec1-41e7-e8f7-9a9bdb101137', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Что такое computed и почему он эффективнее метода?","Back":"**`computed`** — производное реактивное значение с **кэшированием**. Пересчитывается лениво и только когда меняется одна из его реактивных зависимостей.\n\n```ts\nconst doubled = computed(() => count.value * 2)\n```\n\nПочему эффективнее метода в шаблоне:\n- **Метод** (`{{ getDoubled() }}`) выполняется **на каждый рендер** компонента, даже если входные данные не менялись.\n- **Computed** кэширует результат и отдаёт его без пересчёта, пока зависимости стабильны. Дорогие вычисления (фильтрация/сортировка списков) делать computed.\n\nМеханизм: computed — это особый эффект, который сам является зависимостью для тех, кто его читает, и сам зависит от того, что прочитал внутри. Флаг `dirty` помечает необходимость пересчёта при `trigger` зависимостей.\n\nНюансы:\n- Computed по умолчанию **read-only**; для записи — `computed({ get, set })`.\n- Геттер должен быть **чистым**: без сайд-эффектов, мутаций, асинхронщины. Для побочных эффектов — `watch`/`watchEffect`.\n- Кэш привязан к **реактивным** зависимостям: если внутри читать обычную переменную или `Date.now()`, кэш не будет инвалидироваться корректно.\n- В 3.4+ computed не триггерит зависимых, если новое значение **строго равно** старому (оптимизация)."}'::jsonb, ARRAY['computed', 'caching', 'reactivity', 'performance']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('3135de8e-6e75-1456-f8bd-2c50697b1ad2', '2e2ee184-3ec1-41e7-e8f7-9a9bdb101137', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('d2936587-5f6d-4a64-6ffe-785eaa014c26', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"v-once и v-memo: для чего нужны и чем отличаются?","Back":"Обе директивы — про **пропуск повторного рендера** ради производительности.\n\n**`v-once`** — рендерит элемент/поддерево **один раз** и больше никогда не обновляет, даже если данные изменились. Vue кэширует VNode и пропускает его при патче.\n```vue\n<div v-once>{{ expensiveStaticTitle }}</div>\n```\nКейс: статический контент, который вычисляется один раз (тяжёлый текст, не меняющиеся данные).\n\n**`v-memo=\"[deps]\"`** — мемоизирует поддерево: перерисовывает его, только если изменился хотя бы один элемент массива зависимостей (как `React.memo`/`useMemo`). Если deps те же — Vue переиспользует прошлые VNode.\n```vue\n<div v-for=\"item in list\" :key=\"item.id\" v-memo=\"[item.selected]\">\n  <!-- перерисуется только при смене selected -->\n</div>\n```\nКейс: **большие списки** (`v-for` на тысячи строк), где обновляется лишь малая часть.\n\nОтличия:\n- `v-once` — \"никогда не обновлять\"; `v-memo` — \"обновлять при смене указанных deps\".\n- `v-memo` с пустым `[]` ≈ `v-once`.\n\nПредостережение: это **точечные** оптимизации. Применять только при доказанных проблемах производительности — неправильные deps в `v-memo` дают **баги с устаревшим UI**, которые сложно отлаживать."}'::jsonb, ARRAY['v-once', 'v-memo', 'performance', 'memoization']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('f9cf4ba0-c9a5-a0c9-ce84-8236eb2611f7', 'd2936587-5f6d-4a64-6ffe-785eaa014c26', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('da1beea9-b16f-ce13-aabd-601bad1b1ced', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"shallowRef / shallowReactive: зачем нужны и какие подводные камни?","Back":"Обычные `ref`/`reactive` делают реактивность **глубокой** — вложенные объекты тоже оборачиваются в Proxy при доступе. Для больших/неизменяемых структур это лишние накладные расходы.\n\n**`shallowRef`** — реактивно только присвоение `.value` целиком; внутренности **не** реактивны:\n```ts\nconst state = shallowRef({ a: 1 })\nstate.value.a = 2      // НЕ триггерит рендер\nstate.value = { a: 2 } // триггерит (замена .value)\n```\n\n**`shallowReactive`** — реактивны только свойства верхнего уровня; вложенные объекты остаются \"сырыми\".\n\nКейсы:\n- **Большие неизменяемые структуры** (данные из API, которые целиком заменяешь) — экономия на оборачивании.\n- Интеграция с **внешними библиотеками** с собственным состоянием (инстансы редактора, графики, карты) — не хочешь, чтобы Vue лез в их потроха.\n- Иммутабельные паттерны: меняешь через замену ссылки.\n\nПодводные камни:\n- Мутация вложенного поля **не вызовет обновления** — частая причина \"почему не реагирует\". Нужно заменять верхний уровень или вызывать `triggerRef(state)` вручную.\n- `shallowReactive` поверхностный: `state.nested.x = 1` не реактивно.\n- Связан с **`markRaw`** — пометить объект, который никогда не должен становиться реактивным."}'::jsonb, ARRAY['shallowref', 'shallowreactive', 'performance', 'markraw']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('1ac2632d-ea32-6719-8f7e-539ba7c40327', 'da1beea9-b16f-ce13-aabd-601bad1b1ced', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('c0503727-e019-f519-dd7d-2d785bd8feaa', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"keep-alive: как работает кэширование компонентов и его хуки?","Back":"**`<KeepAlive>`** кэширует **инстансы** обёрнутых компонентов вместо их размонтирования при переключении. Состояние и DOM сохраняются — полезно для табов, форм-визардов, кэша страниц в роутере.\n\n```vue\n<KeepAlive>\n  <component :is=\"currentTab\" />\n</KeepAlive>\n```\n\nХуки жизненного цикла для кэшируемых компонентов:\n- **`onActivated`** — компонент достали из кэша и снова показали.\n- **`onDeactivated`** — компонент спрятали (но не размонтировали).\n`onMounted`/`onUnmounted` срабатывают только при реальном создании/уничтожении.\n\nНастройка кэша:\n- `include` / `exclude` — по имени компонента (важно: компонент должен иметь `name` или `__name`).\n- `max` — лимит количества инстансов в кэше (LRU-вытеснение).\n\nС роутером:\n```vue\n<RouterView v-slot=\"{ Component }\">\n  <KeepAlive>\n    <component :is=\"Component\" />\n  </KeepAlive>\n</RouterView>\n```\n\nПодводные камни:\n- **Утечки**: кэшируемые компоненты держат таймеры/подписки живыми — чисти/паузь их в `onDeactivated`, а не только в `onUnmounted`.\n- Без `max` большой кэш съедает память.\n- Данные не рефрешатся при возврате — если нужна свежесть, перезапрашивай в `onActivated`."}'::jsonb, ARRAY['keep-alive', 'caching', 'lifecycle', 'performance']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('198ebeb0-752e-2bdd-71c5-7def8ea55b76', 'c0503727-e019-f519-dd7d-2d785bd8feaa', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('e946df7f-ae66-d440-85a0-240cf563a7bf', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Ленивые (асинхронные) компоненты: defineAsyncComponent и code-splitting.","Back":"**`defineAsyncComponent`** позволяет загружать компонент **по требованию** (отдельным чанком), уменьшая начальный бандл:\n```ts\nimport { defineAsyncComponent } from ''vue''\nconst Heavy = defineAsyncComponent(() => import(''./Heavy.vue''))\n```\nДинамический `import()` — сигнал бандлеру (Vite/webpack) выделить **отдельный chunk**, который грузится при первом рендере компонента.\n\nРасширенная форма с UX-состояниями:\n```ts\nconst Comp = defineAsyncComponent({\n  loader: () => import(''./Comp.vue''),\n  loadingComponent: Spinner,\n  errorComponent: ErrorView,\n  delay: 200,      // задержка перед показом loading\n  timeout: 10000,  // когда считать ошибкой\n})\n```\n\nСвязка с **`<Suspense>`** (экспериментально): асинхронные компоненты с `async setup()` могут резолвиться внутри `<Suspense>`, который покажет fallback на время загрузки.\n\nКейсы code-splitting:\n- **Роуты** — ленивые компоненты в `vue-router` (`component: () => import(...)`).\n- **Тяжёлые виджеты** ниже фолда (графики, редакторы, модалки).\n\nПодводные камни:\n- Слишком мелкое дробление → много мелких запросов, оверхед. Балансируй гранулярность.\n- Нужна обработка **ошибки загрузки чанка** (например, после деплоя старый чанк пропал) — retry/перезагрузка страницы."}'::jsonb, ARRAY['async-components', 'code-splitting', 'lazy-loading', 'suspense']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('efcda206-4011-59b6-9eba-1370d6a001a6', 'e946df7f-ae66-d440-85a0-240cf563a7bf', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('df8fa9d0-e431-b4b9-122c-18a12a8e3cb3', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Зачем нужен key в v-for и при переключении компонентов?","Back":"**`key`** — уникальная подсказка алгоритму патчинга для идентификации VNode между рендерами.\n\nВ `v-for`:\n- Без `key` (или с `index` как key) Vue использует стратегию **\"in-place patch\"** — переиспользует DOM-элементы по позиции. При изменении порядка/вставке/удалении это приводит к **багам состояния**: значения инпутов, фокус, анимации \"прилипают\" не к тем элементам.\n- Стабильный уникальный `key` (например `item.id`) позволяет Vue корректно сопоставлять, **переиспользовать, перемещать или пересоздавать** элементы.\n\nПочему `index` — плохой key: при вставке в начало все индексы сдвигаются, Vue считает, что изменились все элементы → лишние перерисовки и потеря локального состояния.\n\nForce re-mount через key:\n```vue\n<UserProfile :key=\"userId\" :id=\"userId\" />\n```\nСмена `key` заставляет Vue **уничтожить старый и создать новый** инстанс (сброс состояния, повторный `onMounted`). Полезно, когда нужно \"перезапустить\" компонент при смене ключевого параметра (например, профиль другого юзера).\n\nНюанс: `key` влияет на алгоритм diff в `<transition>` — без него анимации переходов между элементами не сработают корректно."}'::jsonb, ARRAY['key', 'v-for', 'diffing', 'force-remount']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('04423381-c2d5-d255-5953-8af78cfb7857', 'df8fa9d0-e431-b4b9-122c-18a12a8e3cb3', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('4e94e06a-3d25-85ed-8a96-3fdef43e6394', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Как работает render-функция и h()? Когда писать render вместо шаблона?","Back":"Шаблоны Vue компилируются в **render-функцию**, возвращающую дерево VNode. Можно писать render вручную через **`h()`** (hyperscript / `createVNode`):\n```ts\nimport { h } from ''vue''\nexport default {\n  setup() {\n    return () => h(''div'', { class: ''box'' }, [\n      h(''span'', ''Привет''),\n      h(MyComponent, { msg: ''hi'' }, { default: () => ''slot content'' })\n    ])\n  }\n}\n```\n\nСигнатура: `h(type, props?, children?)`\n- `type` — строка тега, компонент или функциональный компонент.\n- `props` — атрибуты, события (`onClick`), `class`, `style`.\n- `children` — строка, массив VNode или **объект слотов** (`{ default: () => [...] }`).\n\nКогда render предпочтительнее шаблона:\n- **Высоко динамическая** структура, которую неудобно выразить шаблоном (генерация по схеме, рекурсивные деревья).\n- **Библиотечные/рендерлесс** компоненты, обёртки, динамический выбор тега.\n- Программная работа с VNode (клонирование, фильтрация слотов).\n\nТрейдоффы:\n- Минус: теряются **compile-time оптимизации** (static hoisting, patch flags) — шаблон обычно быстрее и читаемее.\n- Минус: меньше \"декларативности\", сложнее для команды.\n- `setup` должен **возвращать функцию** рендера, чтобы реактивность пересоздавала VNode при изменениях."}'::jsonb, ARRAY['render-function', 'h', 'vnode', 'templates']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('cca32ae7-a475-217d-66be-18feb4582abf', '4e94e06a-3d25-85ed-8a96-3fdef43e6394', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('bd21af24-3d54-42ac-254f-cbf6a552dcef', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"JSX/TSX во Vue 3: как работает и чем отличается от шаблонов?","Back":"Vue поддерживает **JSX/TSX** через babel-плагин (`@vue/babel-plugin-jsx`) или Vite-плагин. JSX — это синтаксический сахар над `h()`:\n```tsx\nimport { defineComponent, ref } from ''vue''\nexport default defineComponent({\n  setup() {\n    const count = ref(0)\n    return () => (\n      <button onClick={() => count.value++}>\n        Счёт: {count.value}\n      </button>\n    )\n  }\n})\n```\n\nОтличия от React-JSX:\n- Директивы выражаются иначе: вместо `v-if`/`v-for` — обычные JS-конструкции (тернарник, `.map()`).\n- События: `onClick` (как React), модификаторы — через `onClickCapture`, `v-on` объект или хелперы `withModifiers`.\n- `v-model` доступен в JSX-плагине, `v-show` тоже.\n- Слоты передаются как объект-children: `<Comp>{{ default: () => <span/> }}</Comp>`.\n\nТрейдоффы:\n- Плюс: вся мощь JS, удобно для **динамической** разметки и компонентов-фабрик; хорошая типизация.\n- Минус: теряются **compile-time оптимизации** шаблонного компилятора (patch flags, hoisting) — потенциально медленнее на горячих участках.\n- Минус: меньшая часть экосистемы/линтеров заточена под Vue-JSX; команда чаще привыкла к SFC-шаблонам.\n\nИтог: шаблоны — дефолт (оптимизации + читаемость), JSX — для редких сильно динамических случаев."}'::jsonb, ARRAY['jsx', 'tsx', 'render-function', 'templates']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('2ae83111-f5e9-a93f-da8a-2648267976b0', 'bd21af24-3d54-42ac-254f-cbf6a552dcef', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('41f9d1b2-d568-9570-be9e-5e668c1f1825', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Как устроены плагины во Vue 3? Что делает app.use()?","Back":"**Плагин** — объект с методом `install(app, options)` или просто функция. Регистрируется через **`app.use(plugin, options)`**:\n```ts\nconst myPlugin = {\n  install(app, options) {\n    app.config.globalProperties.$http = createHttp(options)\n    app.provide(''config'', options)\n    app.component(''GlobalBtn'', Btn)\n    app.directive(''focus'', { mounted: el => el.focus() })\n  }\n}\ncreateApp(App).use(myPlugin, { baseURL: ''/api'' }).mount(''#app'')\n```\n\nЧто типично делает плагин:\n- Регистрирует **глобальные компоненты/директивы**.\n- Добавляет **`globalProperties`** (аналог Vue.prototype из Vue 2).\n- Делает **`app.provide`** для inject во всём приложении (DI-способ, предпочтительнее globalProperties).\n- Инициализирует библиотеку (Pinia, Router, i18n).\n\nДетали:\n- `app.use` **идемпотентен**: повторная установка того же плагина игнорируется.\n- Возвращает экземпляр приложения → **чейнится**.\n- В отличие от Vue 2, всё привязано к **конкретному `app`-инстансу**, а не глобально — можно иметь несколько изолированных приложений на странице (важно для микрофронтендов, виджетов, тестов).\n\nИменно как плагины подключаются `app.use(router)`, `app.use(createPinia())`, `app.use(i18n)`."}'::jsonb, ARRAY['plugins', 'app-use', 'provide', 'global-properties']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('e6fcbe35-b606-5438-adf8-67499e8d44ed', '41f9d1b2-d568-9570-be9e-5e668c1f1825', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('5b0e74b1-d7be-c790-947e-b195bcf15e1c', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Опиши архитектуру Vue 3: компилятор шаблонов, реактивность, рантайм.","Back":"Vue 3 — модульный монорепозиторий из независимых пакетов:\n- **`@vue/reactivity`** — система реактивности (`ref`, `reactive`, `effect`, `computed`). Независима, используется и вне Vue.\n- **`@vue/compiler-core` / `compiler-dom` / `compiler-sfc`** — компилятор: парсит шаблон в AST, трансформирует, генерирует render-функцию.\n- **`@vue/runtime-core`** — платформо-независимый рантайм (компоненты, VNode, scheduler, patch-алгоритм).\n- **`@vue/runtime-dom`** — привязка к DOM (создание элементов, атрибуты, события).\n\nПоток рендера:\n1. **Компиляция** (build-time): шаблон → render-функция. Компилятор анализирует разметку и расставляет **оптимизационные подсказки**.\n2. **Создание VNode**: render-функция возвращает дерево виртуального DOM.\n3. **Mount**: рантайм создаёт реальный DOM из VNode.\n4. **Реактивное обновление**: рендер компонента оборачивается в **эффект**; при изменении зависимостей эффект перезапускается, создаёт новый VNode, и **patch** диффит старое дерево с новым.\n\nCompile-time оптимизации (отличают Vue 3):\n- **Patch flags** — VNode помечается, какие именно части динамичны (только class, только текст и т.п.) — патч проверяет только их.\n- **Static hoisting** — статические VNode выносятся за пределы render-функции, создаются один раз.\n- **Tree flattening / block tree** — собирает динамические узлы в плоский массив, пропуская статические поддеревья при diff.\n\nИменно компилятор + информированный рантайм дают прирост скорости по сравнению с Vue 2."}'::jsonb, ARRAY['architecture', 'compiler', 'runtime', 'reactivity']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('75960cf6-4058-4d05-63e7-de03f25c4fef', '5b0e74b1-d7be-c790-947e-b195bcf15e1c', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('ae3cf767-b81e-ad04-7778-9e323c6e2603', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Что такое Virtual DOM и как работает алгоритм patch во Vue 3?","Back":"**Virtual DOM (VNode)** — лёгкое JS-описание реального DOM-узла (тип, props, children). При изменении состояния создаётся новое дерево VNode, которое **диффится** со старым, и в реальный DOM применяются только различия.\n\nАлгоритм **patch** сравнивает старый и новый VNode:\n- Разные `type`/`key` → старый узел уничтожается, создаётся новый.\n- Одинаковые → патчатся props и рекурсивно children.\n\nДиф детей (особенно списков):\n- Использует **`key`** для сопоставления.\n- Применяется оптимизированный алгоритм с поиском **longest increasing subsequence (LIS)** для минимизации перемещений DOM-узлов при переупорядочивании.\n\nVue 3 vs наивный VDOM:\n- **Patch flags**: компилятор помечает, что в узле динамично. Патч не сравнивает всё дерево \"в лоб\", а идёт только по динамическим узлам.\n- **Block tree**: каждый блок хранит плоский массив динамических потомков (`dynamicChildren`), статические поддеревья **пропускаются целиком**. Стоимость diff пропорциональна количеству динамических узлов, а не размеру шаблона.\n\nПочему VDOM вообще: абстрагирует прямые DOM-манипуляции (которые дороги), даёт декларативность и кроссплатформенность (можно рендерить не только в DOM). Трейдофф — оверхед на создание/сравнение VNode, который Vue 3 минимизирует за счёт compile-time информации (в отличие от чисто рантаймовых VDOM-библиотек)."}'::jsonb, ARRAY['virtual-dom', 'patch', 'diffing', 'patch-flags']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('e9cb2bd4-f3c3-a68e-5665-41db226e39eb', 'ae3cf767-b81e-ad04-7778-9e323c6e2603', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('833eef89-a262-271c-4437-459ad961a307', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Pinia: что такое state/getters/actions и как объявить стор?","Back":"**Pinia** — официальный state-менеджер Vue 3. Два стиля объявления:\n\nSetup-стиль (рекомендуемый, ближе к Composition API):\n```ts\nexport const useCounter = defineStore(''counter'', () => {\n  const count = ref(0)              // state\n  const double = computed(() => count.value * 2) // getter\n  function increment() { count.value++ }          // action\n  return { count, double, increment }\n})\n```\n\nOptions-стиль:\n```ts\nexport const useCounter = defineStore(''counter'', {\n  state: () => ({ count: 0 }),\n  getters: { double: (s) => s.count * 2 },\n  actions: { increment() { this.count++ } }\n})\n```\n\nСоставляющие:\n- **state** — реактивные данные (фабрика-функция, чтобы каждый инстанс был изолирован, важно для SSR).\n- **getters** — производное кэшируемое состояние (как `computed`); могут обращаться к другим геттерам.\n- **actions** — методы для мутаций и **асинхронной** логики (запросы, бизнес-логика). В отличие от Vuex, **синхронные и асинхронные изменения делаются одинаково** в actions.\n\nИспользование:\n```ts\nconst store = useCounter()\n// деструктуризация с сохранением реактивности:\nconst { count, double } = storeToRefs(store)\nstore.increment() // методы можно деструктурировать напрямую\n```\n\nНюанс: стор — синглтон в рамках Pinia-инстанса; `useStore()` нужно вызывать внутри `setup`/компонента (или после установки Pinia)."}'::jsonb, ARRAY['pinia', 'state-management', 'store', 'storetorefs']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('3e876525-1b40-f5f8-5ec9-58f3f564ea16', '833eef89-a262-271c-4437-459ad961a307', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('212bce1b-e1d1-ace8-f053-71bbcac0d9e4', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Чем Pinia отличается от Vuex и почему стала дефолтом?","Back":"Pinia — преемник Vuex (по сути Vuex 5), стала официальной рекомендацией.\n\nКлючевые отличия:\n- **Нет mutations**. В Vuex был обязательный слой `mutations` (только синхронные) + `actions` (асинхронные). В Pinia всё меняется прямо в **actions** или даже напрямую через `store.count++`. Меньше бойлерплейта.\n- **Нет модулей и namespaced-ада**. Вместо одного дерева с модулями — **плоский набор независимых сторов**, каждый со своим id. Импортируешь нужный стор хуком `useStore()`.\n- **Типизация из коробки**. Vuex имел слабую поддержку TS (типы для `state`/`commit`/`dispatch` приходилось дописывать). Pinia типобезопасна без усилий.\n- **Composition API дружелюбна**: setup-стиль стора = тот же код, что в компоненте.\n- **Меньше API**: нет `mapState`/`mapActions`-магии строками; вместо этого `storeToRefs` и прямой вызов.\n- **Code-splitting**: сторы тришейкаются и грузятся лениво вместе с фичами.\n\nЧто общего: реактивное централизованное состояние, интеграция с **Vue Devtools** (timeline, time-travel), плагины, SSR-поддержка.\n\nИтог: Pinia проще, типобезопаснее и легче, поэтому Vue-команда сделала её стандартом, а Vuex переведён в maintenance-режим."}'::jsonb, ARRAY['pinia', 'vuex', 'state-management', 'comparison']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('baaf92b1-510b-2f14-472a-5dca8d5ebc75', '212bce1b-e1d1-ace8-f053-71bbcac0d9e4', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('fd4ae528-59f0-0d50-ad79-c9633feffa4e', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Vue Router: динамические маршруты и доступ к параметрам.","Back":"**Динамические сегменты** объявляются через `:param`:\n```ts\nconst routes = [\n  { path: ''/users/:id'', component: User },\n  { path: ''/files/:path(.*)*'', component: File } // catch-all с regex\n]\n```\nДоступ к параметрам:\n- В шаблоне/Options: `$route.params.id`.\n- В Composition API: `const route = useRoute(); route.params.id`.\n\nВажные нюансы:\n- При переходе **между одним и тем же компонентом** с разными params (`/users/1` → `/users/2`) компонент **переиспользуется**, `onMounted` **не вызывается** повторно. Чтобы реагировать — `watch(() => route.params.id, ...)` или `beforeRouteUpdate`. Альтернатива — форс-ремаунт через `:key=\"route.fullPath\"` на `<RouterView>`.\n- **Props-режим**: `props: true` в роуте передаёт params как props компонента — компонент развязан с роутером, легче тестировать.\n- **Опциональные** и **повторяющиеся** параметры: `:id?`, `:chapters+`, `:chapters*`.\n- Кастомный regex в сегменте: `/:id(\\\\d+)` — только цифры.\n\nРежимы истории: `createWebHistory()` (HTML5, нужны серверные rewrites на index.html), `createWebHashHistory()` (через `#`, без настройки сервера), `createMemoryHistory()` (SSR/тесты)."}'::jsonb, ARRAY['vue-router', 'dynamic-routes', 'route-params', 'history-mode']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('8aa3f493-6a06-5d02-5762-a2d72815c49f', 'fd4ae528-59f0-0d50-ad79-c9633feffa4e', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('e7516acd-61bf-6e42-482e-a97171cd96c4', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Navigation guards в Vue Router: какие бывают и порядок срабатывания.","Back":"Гарды позволяют контролировать навигацию (авторизация, подтверждение ухода, загрузка данных).\n\nУровни:\n- **Глобальные**: `router.beforeEach`, `router.beforeResolve`, `router.afterEach`.\n- **На уровне маршрута**: `beforeEnter` в объекте route.\n- **В компоненте**: `beforeRouteEnter`, `beforeRouteUpdate`, `beforeRouteLeave` (+ Composition-аналоги `onBeforeRouteUpdate`, `onBeforeRouteLeave`).\n\nАPI гарда: `(to, from)` → возвращает:\n- `true`/`undefined` — продолжить;\n- `false` — отменить;\n- объект location (`{ name: ''login'' }`) — редирект.\n(В Vue Router 4 предпочтителен **return** вместо старого `next()`.)\n\nПолный порядок при навигации:\n1. `beforeRouteLeave` (покидаемых компонентов)\n2. `beforeEach` (глобальный)\n3. `beforeRouteUpdate` (переиспользуемых компонентов)\n4. `beforeEnter` (маршрута)\n5. резолв async-компонентов\n6. `beforeRouteEnter` (входящих компонентов)\n7. `beforeResolve` (глобальный)\n8. навигация подтверждена\n9. `afterEach` (глобальный, без возможности отмены)\n\nНюансы:\n- В `beforeRouteEnter` нет доступа к `this` (компонент ещё не создан) — используют колбэк `next(vm => ...)`.\n- Защита авторизации обычно в `beforeEach`: проверка токена/роли и редирект на login.\n- Не делать тяжёлые блокирующие операции — навигация будет \"висеть\"."}'::jsonb, ARRAY['vue-router', 'navigation-guards', 'authorization', 'lifecycle']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('43673e5f-59bd-212a-54aa-e52163e0db37', 'e7516acd-61bf-6e42-482e-a97171cd96c4', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('ef94703e-3a7b-bdef-ecac-d990bc62b2b0', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"Ленивая загрузка маршрутов в Vue Router: как и зачем?","Back":"Вместо статического импорта компонента маршрута используют **динамический `import()`**, чтобы выделить роут в отдельный чанк и не тащить его в начальный бандл:\n```ts\nconst routes = [\n  { path: ''/'', component: () => import(''./views/Home.vue'') },\n  { path: ''/admin'', component: () => import(''./views/Admin.vue'') }\n]\n```\nБандлер (Vite/webpack) создаёт отдельный chunk на каждый такой импорт; он грузится **при первом переходе** на маршрут.\n\nЗачем:\n- **Меньше initial bundle** → быстрее First Contentful Paint, особенно для крупных приложений с десятками страниц.\n- Редко используемые/тяжёлые разделы (админка, отчёты) не грузятся всем пользователям.\n\nГруппировка чанков (webpack): магический коммент `/* webpackChunkName: \"group\" */` объединяет несколько роутов в один чанк. В Vite — через настройку `manualChunks` в Rollup.\n\nUX-нюансы:\n- На время загрузки чанка показывают индикатор (можно через `router.beforeResolve`/глобальный лоадер или `<Suspense>`).\n- Нужна обработка **ошибки загрузки чанка** (после деплоя старые хэши пропадают): глобальный `router.onError` + перезагрузка страницы.\n- Не дробить слишком мелко — иначе много мелких запросов и оверхед. Часто комбинируют с **prefetch** для предзагрузки вероятных следующих роутов."}'::jsonb, ARRAY['vue-router', 'lazy-loading', 'code-splitting', 'performance']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('3f94adfc-0f33-2bac-9b9f-96d2e477e04e', 'ef94703e-3a7b-bdef-ecac-d990bc62b2b0', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('b12b5972-7685-e651-8843-c6f199f22032', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550004', '{"Front":"i18n во Vue (vue-i18n): локализация, интерполяция и плюрализация.","Back":"**vue-i18n** — стандартная библиотека локализации. Подключается плагином:\n```ts\nconst i18n = createI18n({\n  legacy: false,           // Composition API режим\n  locale: ''ru'',\n  fallbackLocale: ''en'',\n  messages: { ru: {...}, en: {...} }\n})\napp.use(i18n)\n```\nВ Composition API: `const { t, locale } = useI18n()`; в шаблоне — `$t(''key'')`.\n\n**Интерполяция** (именованная/списочная):\n```js\n{ greeting: ''Привет, {name}!'' }\nt(''greeting'', { name: ''Сергей'' })\n```\n\n**Плюрализация** — формы множественного числа через `|`. У русского сложные правила (1, 2-4, 5+), vue-i18n поддерживает кастомный `pluralizationRules`:\n```js\n{ apples: ''нет яблок | {n} яблоко | {n} яблока | {n} яблок'' }\nt(''apples'', 5) // выберет нужную форму по числу\n```\nПо числу `n` выбирается индекс ветки согласно правилу локали (для en — 2 формы, для ru — 3-4).\n\nДополнительно:\n- **DatetimeFormat / NumberFormat** — форматирование дат, валют, чисел по локали (через Intl).\n- **Ленивая загрузка локалей**: подгружать словари динамическим `import()` при смене языка — не тащить все языки сразу.\n- **`fallbackLocale`** — резервный язык для отсутствующих ключей.\n- Реактивность: смена `locale.value` перерисовывает все переводы автоматически.\n\nПодводный камень: ключи-строки легко \"протухают\" — полезны проверки на отсутствующие/неиспользуемые ключи в CI."}'::jsonb, ARRAY['i18n', 'vue-i18n', 'localization', 'pluralization']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('6a49d31e-3261-8039-d8a0-de8d712851fa', 'b12b5972-7685-e651-8843-c6f199f22032', '55555555-5555-5555-5555-555555550004', 0, 'new') on conflict (id) do nothing;
