insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('4334a950-440a-f284-0c65-52d52558d8be', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Сравните REST, gRPC, GraphQL, SOAP и WebSocket: в чём суть каждого протокола и когда что выбирать?","Back":"**REST** — архитектурный стиль поверх HTTP, ресурсы и стандартные глаголы (GET/POST/PUT/PATCH/DELETE), stateless, кэшируемость через HTTP-кэш. Прост, повсеместен, но страдает от **over-/under-fetching** и версионирования.\n\n**gRPC** — RPC поверх **HTTP/2** с бинарной сериализацией **Protobuf**. Контракт через `.proto`, кодогенерация клиента/сервера, мультиплексирование, стриминг (uni/bi-directional). Идеален для **service-to-service** в бэкенде. На фронте — только через `grpc-web` + прокси (нет нативной поддержки HTTP/2 trailer''ов в браузере).\n\n**GraphQL** — язык запросов с единым endpoint''ом; клиент сам описывает нужные поля → нет over-/under-fetching. Сильная типизация схемы. Цена: сложность кэширования (POST по умолчанию ломает HTTP-кэш), N+1 на резолверах, риск тяжёлых запросов (нужны depth/cost limiting).\n\n**SOAP** — XML-протокол с жёстким контрактом (WSDL), встроенные WS-Security/транзакции. Тяжёлый, legacy/enterprise (банки, гос).\n\n**WebSocket** — полнодуплексный персистентный канал поверх одного TCP. Для **real-time**: чаты, котировки, коллаборация. Не кэшируется, нужен свой протокол поверх (часто STOMP/socket.io).\n\n**Выбор:**\n- Публичный API / CRUD → REST.\n- Внутренние микросервисы, низкая латентность → gRPC.\n- Богатый клиент с разными вью на одни данные → GraphQL.\n- Двусторонний real-time → WebSocket (или SSE для одностороннего push).\n- Legacy enterprise → SOAP."}'::jsonb, ARRAY['protocols', 'rest', 'grpc', 'graphql', 'websocket', 'soap']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('db2ff523-da22-cf70-5c23-7cb69af65dba', '4334a950-440a-f284-0c65-52d52558d8be', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('7dc1a6fe-36b6-1d4b-5e2b-c914e6accfd7', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Чем WebSocket отличается от SSE и long-polling? Когда достаточно SSE?","Back":"**Long-polling** — клиент шлёт запрос, сервер держит его открытым до появления данных, затем клиент переоткрывает. Эмуляция push поверх обычного HTTP; высокие накладные расходы на переустановку соединений.\n\n**SSE (Server-Sent Events)** — однонаправленный поток server→client поверх обычного HTTP (`text/event-stream`). Плюсы: авто-reconnect, `Last-Event-ID` для докачки, проходит через прокси/HTTP-кэш-инфраструктуру, проще WebSocket. Минусы: только сервер→клиент, лимит соединений на домен в HTTP/1.1 (~6), нет бинарных данных.\n\n**WebSocket** — полный дуплекс, бинарь + текст, минимальный overhead на фрейм. Но: не проходит «бесплатно» через всё (нужна поддержка Upgrade у прокси), нет встроенного reconnect/докачки — реализуешь сам.\n\n**Когда SSE достаточно:** нотификации, лента событий, прогресс задач, обновление дашборда — всё, где поток идёт **только от сервера**. Если клиенту нужно часто слать наверх (чат, игры, совместное редактирование) → WebSocket."}'::jsonb, ARRAY['protocols', 'websocket', 'sse', 'real-time']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('88de1e97-f696-2336-8e9b-1a825fda9ee4', '7dc1a6fe-36b6-1d4b-5e2b-c914e6accfd7', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('1255b0e7-c60c-a87f-11d1-0a50c06709d7', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Что такое нормализация БД (1NF–3NF/BCNF) и зачем сознательно денормализуют?","Back":"Нормализация — устранение избыточности и аномалий вставки/обновления/удаления.\n\n- **1NF** — атомарные значения, нет повторяющихся групп/массивов в ячейке.\n- **2NF** — 1NF + нет частичной зависимости неключевых атрибутов от **части** составного ключа.\n- **3NF** — 2NF + нет транзитивных зависимостей (неключевой атрибут не зависит от другого неключевого).\n- **BCNF** — усиление 3NF: каждая детерминанта — суперключ.\n\n**Зачем денормализуют:** нормализованная схема требует много JOIN''ов → дорого на чтение. Денормализация (дублирование данных, вычисляемые/материализованные поля, кэш агрегатов) ускоряет чтение ценой:\n- риска рассогласования (нужно поддерживать копии синхронно — триггеры, events, периодический пересчёт);\n- усложнения записи.\n\n**Правило:** нормализуй по умолчанию, денормализуй точечно под измеренные горячие read-пути. OLTP тяготеет к нормализации, OLAP/аналитика — к денормализации (star/snowflake schema)."}'::jsonb, ARRAY['database', 'normalization', 'data-modeling']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('fca26a04-2747-b64c-c777-78a1b5c60924', '1255b0e7-c60c-a87f-11d1-0a50c06709d7', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('503759cb-737c-e448-6d2d-b29f4ae58a57', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Как моделировать связи 1:1, 1:N и M:N в реляционной БД? Что такое внешний ключ?","Back":"**Foreign key (FK)** — столбец, ссылающийся на PK другой таблицы; СУБД гарантирует ссылочную целостность (нельзя сослаться на несуществующую строку; `ON DELETE CASCADE/RESTRICT/SET NULL` управляет каскадом).\n\n**1:N** (один-ко-многим) — FK кладётся на стороне «многих». Пример: `orders.user_id → users.id`. Самая частая связь.\n\n**1:1** — FK с `UNIQUE`-ограничением (или общий PK). Используют для разнесения редко используемых/чувствительных полей, опциональных профилей.\n\n**M:N** (многие-ко-многим) — через **связующую (junction/join) таблицу** с двумя FK: `user_roles(user_id, role_id)`, PK = пара. Туда же кладут атрибуты самой связи (например, `assigned_at`).\n\n**Подводные камни:**\n- FK по умолчанию **не индексируется** (PK — да). На стороне «многих» нужен индекс по FK, иначе каскады и JOIN''ы тормозят.\n- Полиморфные связи (один FK на разные таблицы) ломают ссылочную целостность — лучше отдельные таблицы или общая таблица сущностей."}'::jsonb, ARRAY['database', 'relations', 'foreign-key', 'data-modeling']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('c7590c80-a76f-af06-9b64-77a9416dc837', '503759cb-737c-e448-6d2d-b29f4ae58a57', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('f1ffaf66-53c2-1378-f3c6-a1cb313bc6fa', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Как работают индексы в реляционной БД? Когда они помогают, а когда вредят?","Back":"Большинство индексов — **B-tree**: сбалансированное дерево, поиск/диапазон за O(log n). Ускоряют `WHERE`, `JOIN`, `ORDER BY`, `GROUP BY` по индексированным столбцам.\n\n**Виды:**\n- **Составной индекс** — работает по **префиксу** (правило leftmost): индекс `(a, b, c)` помогает запросам по `a`, `(a,b)`, `(a,b,c)`, но не по одному `b`.\n- **Covering index** — содержит все нужные столбцы → запрос читается прямо из индекса (index-only scan), без обращения к таблице.\n- **Partial index** — только по части строк (`WHERE active = true`).\n- **Hash** — только равенство, без диапазонов. **GIN/GiST** (Postgres) — для full-text, JSONB, geo.\n\n**Когда вредят:**\n- Замедляют **запись** (INSERT/UPDATE/DELETE обновляют все индексы).\n- Занимают место.\n- Низкая **селективность** (например, boolean-поле) → планировщик игнорирует индекс, делает seq scan.\n- Функция над столбцом в WHERE (`WHERE lower(email)=...`) убивает обычный индекс — нужен **функциональный/выраженческий** индекс.\n\nПравило: индексируй под реальные запросы (смотри `EXPLAIN ANALYZE`), а не «на всякий случай»."}'::jsonb, ARRAY['database', 'indexes', 'performance', 'b-tree']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('efaedcb5-6b6a-a1ea-7f30-1abdca2c2de5', 'f1ffaf66-53c2-1378-f3c6-a1cb313bc6fa', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('ad2018ce-ccf9-b122-5447-ff5fb72617db', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Что такое модель C4 для архитектурных диаграмм и чем она удобнее «коробочек со стрелочками»?","Back":"**C4** (Simon Brown) — иерархия из 4 уровней детализации, каждый — для своей аудитории:\n\n1. **Context** — система как чёрный ящик + пользователи и внешние системы. Для нетехнических стейкхолдеров.\n2. **Container** — приложения/сервисы/БД/SPA внутри системы и протоколы между ними (не Docker-контейнеры, а «исполняемые единицы»). Для архитекторов/DevOps.\n3. **Component** — логические компоненты внутри одного контейнера. Для разработчиков.\n4. **Code** — классы/интерфейсы (часто = UML class diagram, обычно генерится, не рисуется руками).\n\n**Преимущество:** единая нотация и масштабирование «карты» — можно зумиться от общей картины к деталям, не смешивая уровни. Лечит главную болезнь спонтанных диаграмм — смешение абстракций (юзеры, классы и очереди на одной схеме). Хорошо ложится на «диаграммы-как-код» (Structurizr, Mermaid, PlantUML) → версионируется в git."}'::jsonb, ARRAY['architecture-diagrams', 'c4', 'documentation']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('0199001e-4be7-d325-1fe4-3bee8cf5a575', 'ad2018ce-ccf9-b122-5447-ff5fb72617db', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('50358a67-f3f0-7693-c833-3194761c350a', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Какие виды UML-диаграмм реально полезны на фронтенде, и для чего нужна sequence-диаграмма?","Back":"UML делится на **структурные** и **поведенческие**. На практике (особенно фронту) полезны немногие:\n\n- **Sequence diagram** (поведенческая) — взаимодействие участников во времени: вертикальные lifelines, горизонтальные сообщения сверху вниз, activation-bars. Идеальна для описания **флоу**: OAuth-редиректы, цепочка компонент→стор→API→бэк, обработка вебхука. Показывает порядок и асинхронность.\n- **Class diagram** — структура: классы/интерфейсы, поля, связи (ассоциация, наследование, композиция/агрегация). На фронте — для доменных моделей, сторов.\n- **State diagram** — конечный автомат: полезен для сложных UI-состояний (форма, плеер, wizard), ложится на XState.\n- **Activity diagram** — блок-схема процесса с ветвлениями/параллелизмом.\n- **Component / Deployment** — модули и их размещение.\n\n**ER-диаграмма** формально не UML, но рядом: сущности, атрибуты, кардинальность связей (crow''s foot нотация) — для проектирования данных.\n\nГлавная мысль на собесе: диаграмма — **инструмент коммуникации**, а не самоцель; выбирай минимальную, объясняющую идею."}'::jsonb, ARRAY['uml', 'sequence-diagram', 'architecture-diagrams', 'er-diagram']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('7f1a9657-9bee-66cb-c86a-11b6414edbb0', '50358a67-f3f0-7693-c833-3194761c350a', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('0e949481-b6c2-5776-7c74-6b8c738876f0', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Расскажите про паттерн Observer (Наблюдатель). Где он встречается во Vue?","Back":"**Observer** — поведенческий паттерн: объект-**subject** хранит список **observer''ов** и оповещает их об изменении состояния (push). Развязывает источник события и подписчиков (один-ко-многим), они не знают друг о друге напрямую.\n\n**Где во фронте/Vue:**\n- **Реактивность Vue 3** — это Observer поверх `Proxy`: при чтении реактивного свойства внутри эффекта (`watchEffect`, рендер-функция) трекается зависимость, при записи — триггерятся подписанные эффекты. Это и есть subject↔observers.\n- **DOM-события** (`addEventListener`) — классический Observer.\n- **EventBus / mitt**, RxJS `Observable`, Node `EventEmitter`.\n\n**Подводные камни:**\n- **Утечки памяти** — забытая отписка (observer жив, subject держит ссылку). Во Vue эффекты чистятся при unmount автоматически, но `setInterval`/глобальные listener''ы — вручную в `onUnmounted`.\n- **Лавина обновлений** и трудно отслеживаемый порядок оповещений (отсюда батчинг/`nextTick` во Vue)."}'::jsonb, ARRAY['design-patterns', 'observer', 'behavioral', 'vue-reactivity']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('ed5463e9-4730-93ea-fb98-a6f340a458a0', '0e949481-b6c2-5776-7c74-6b8c738876f0', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('a22b3c66-e3f2-3f16-548f-e11c9234b120', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Чем отличаются Strategy и Factory? Приведите фронтенд-пример каждого.","Back":"**Strategy** (поведенческий) — инкапсулирует **взаимозаменяемые алгоритмы** за общим интерфейсом, выбор делается в рантайме. Убирает разросшиеся `if/switch`.\n```ts\nconst validators: Record<string, (v: string) => boolean> = {\n  email: v => /.+@.+/.test(v),\n  phone: v => /^\\d{10}$/.test(v),\n};\nfunction validate(type: string, v: string) {\n  return validators[type](v); // стратегия выбирается по ключу\n}\n```\nПримеры: разные алгоритмы сортировки/форматирования, способы оплаты, стратегии кэширования.\n\n**Factory** (порождающий) — инкапсулирует **создание объектов**, скрывая конкретный класс за общим интерфейсом. Клиент получает продукт, не зная `new` какого класса вызван.\n```ts\nfunction createNotifier(channel: ''email'' | ''sms'' | ''push''): Notifier {\n  switch (channel) {\n    case ''email'': return new EmailNotifier();\n    case ''sms'': return new SmsNotifier();\n    case ''push'': return new PushNotifier();\n  }\n}\n```\n**Суть различия:** Strategy выбирает **как делать** (поведение), Factory решает **что создать** (объект). Часто работают вместе: фабрика создаёт нужную стратегию."}'::jsonb, ARRAY['design-patterns', 'strategy', 'factory', 'behavioral', 'creational']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('eda496f7-810a-5608-1d18-f4d77ef0e263', 'a22b3c66-e3f2-3f16-548f-e11c9234b120', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('2e92c5fa-b822-1fc6-d3fe-75edaf47e8de', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Что такое Singleton, какие у него проблемы и как он проявляется в Pinia/инстансе API?","Back":"**Singleton** (порождающий) — гарантирует **единственный экземпляр** класса и глобальную точку доступа.\n```ts\nlet instance: ApiClient | null = null;\nexport function getApiClient() {\n  return (instance ??= new ApiClient(baseURL));\n}\n```\n**Где во фронте:** экземпляр axios, конфиг, логгер, шина событий. **Pinia-store** по сути синглтон в рамках приложения (один store на app-инстанс).\n\n**Проблемы:**\n- **Глобальное состояние** → скрытые зависимости, трудно тестировать (нужно мокать/сбрасывать).\n- **SSR-катастрофа:** модульный синглтон шарится между запросами разных пользователей → утечка данных. Поэтому в Nuxt/SSR Pinia и API-клиенты создаются **на каждый запрос** (через app context), а не как module-level singleton.\n- Скрывает количество зависимостей, нарушает DIP.\n\n**Альтернатива:** DI-контейнер / `provide`-`inject`, передача зависимости явно. Синглтон оправдан для действительно процесс-глобальных, stateless ресурсов."}'::jsonb, ARRAY['design-patterns', 'singleton', 'creational', 'ssr', 'pinia']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('d2b7ebe2-74b2-59f4-934b-3f1648bfdba7', '2e92c5fa-b822-1fc6-d3fe-75edaf47e8de', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('88e5d97d-fea8-adc9-2b6d-f009d14fe90f', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Объясните паттерны Adapter и Facade. В чём разница и где применяются на фронте?","Back":"Оба **структурные**, оба «обёртки», но цели разные.\n\n**Adapter** — приводит **несовместимый интерфейс** к ожидаемому. Цель — совместимость.\n```ts\n// бэкенд отдаёт snake_case, приложению нужен camelCase\nfunction adaptUser(dto: UserDTO): User {\n  return { id: dto.user_id, fullName: dto.full_name };\n}\n```\nПримеры: маппинг DTO→доменная модель, обёртка сторонней либы под наш интерфейс, антикоррупционный слой к legacy API.\n\n**Facade** — даёт **упрощённый интерфейс** к сложной подсистеме. Цель — снизить сложность, спрятать оркестрацию нескольких модулей.\n```ts\n// фасад над авторизацией: внутри токены, refresh, хранилище, redirect\nconst auth = {\n  login(creds) { /* api + сохранить токен + редирект */ },\n  logout() { /* очистить + редирект */ },\n};\n```\nПримеры: сервисный слой/use-case, обёртка над набором API-вызовов, единая точка для аналитики.\n\n**Разница:** Adapter меняет **форму** одного интерфейса (1:1), Facade **упрощает** доступ к многим компонентам (1:N), не обязан сохранять их интерфейс."}'::jsonb, ARRAY['design-patterns', 'adapter', 'facade', 'structural']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('e1e20b83-4002-044d-dfb6-919e186c5b8a', '88e5d97d-fea8-adc9-2b6d-f009d14fe90f', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('b2df493f-0de1-490f-4d9c-97279e6bfcc3', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Сгруппируйте паттерны GoF: какие порождающие, структурные и поведенческие, и в чём смысл деления?","Back":"GoF делит 23 паттерна по **назначению**:\n\n**Порождающие (Creational)** — про создание объектов, развязывают код от конкретных классов:\n- Singleton, Factory Method, Abstract Factory, Builder, Prototype.\n\n**Структурные (Structural)** — про композицию объектов/классов в большие структуры:\n- Adapter, Facade, Decorator, Proxy, Composite, Bridge, Flyweight.\n\n**Поведенческие (Behavioral)** — про взаимодействие и распределение ответственности:\n- Observer, Strategy, Command, State, Iterator, Mediator, Template Method, Chain of Responsibility, Visitor, Memento, Interpreter.\n\n**Самые ходовые на фронте:** Observer (реактивность/события), Strategy (взаимозаменяемое поведение), Factory (создание сервисов), Adapter (DTO-маппинг), Facade (сервисный слой), Decorator (HOC/composables, middleware), Proxy (буквально `Proxy` в реактивности Vue 3), Command (undo/redo, action''ы), State (XState, UI-автоматы).\n\nСмысл деления — словарь для коммуникации: «здесь Strategy» сразу передаёт намерение. Но **не натягивай** паттерны ради паттернов (YAGNI)."}'::jsonb, ARRAY['design-patterns', 'gof', 'creational', 'structural', 'behavioral']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('83345bb5-82c0-59b7-d1f9-8cc52630d373', 'b2df493f-0de1-490f-4d9c-97279e6bfcc3', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('84936936-5dba-6c9f-b49e-76d4d22e6ccb', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"KISS, DRY, YAGNI — что это и где они конфликтуют между собой?","Back":"**KISS** (Keep It Simple, Stupid) — выбирай простейшее работающее решение; сложность оправдывай.\n\n**DRY** (Don''t Repeat Yourself) — единый источник истины для знания; дублирование логики → одно изменение в N местах → баги.\n\n**YAGNI** (You Aren''t Gonna Need It) — не строй абстракции «на будущее», которое может не наступить; реализуй то, что нужно сейчас.\n\n**Конфликты и нюансы:**\n- **DRY vs KISS/преждевременная абстракция:** ранняя погоня за DRY (вынести «общее» из двух похожих, но эволюционирующих по-разному мест) рождает дырявую абстракцию с кучей флагов. Правило: **дублирование дешевле неправильной абстракции** (rule of three — обобщай на третьем повторении).\n- **DRY ≠ совпадение кода:** DRY про дублирование **знания/правила**, а не текстуально похожих строк. Два куска, случайно похожих, но из разных доменов, объединять нельзя (ложный DRY).\n- **YAGNI vs расширяемость:** YAGNI не запрещает чистые границы — он запрещает спекулятивную обобщённость без текущей потребности.\n\nИтог: KISS и YAGNI сдерживают избыточную инженерию, DRY борется с дублированием знания — баланс, а не догма."}'::jsonb, ARRAY['principles', 'kiss', 'dry', 'yagni', 'clean-code']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('1eb165eb-2e6b-b36a-a57e-3b78367a1534', '84936936-5dba-6c9f-b49e-76d4d22e6ccb', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('8efb6458-270b-cd1b-65fa-c7fa8402cd84', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"SOLID: что означает буква S (Single Responsibility) и как нарушение выглядит во Vue-компоненте?","Back":"**SRP (Single Responsibility Principle)** — у модуля должна быть **одна причина для изменения**, т.е. он отвечает перед одним «актором»/одной осью изменений.\n\nЧасто формулируют как «один класс — одна обязанность», но точнее — **одна причина меняться**. Если модуль трогают и при изменении бизнес-правил, и при смене формата API, и при редизайне — у него три причины меняться → нарушение.\n\n**Нарушение во Vue:** «толстый» компонент, который одновременно:\n- ходит в API (`fetch`),\n- держит и мутирует бизнес-состояние,\n- форматирует данные,\n- содержит сложную разметку и стили.\n\n**Рефакторинг:**\n- запрос данных и бизнес-логику → в **composable** (`useUsers()`) или сервисный слой/стор;\n- форматирование → отдельные утилиты/computed;\n- компонент оставляем «тонким» — отвечает только за представление.\n\nЭффект: тестируемость (логику можно проверить без монтирования DOM), переиспользование, локализованные изменения."}'::jsonb, ARRAY['solid', 'srp', 'principles', 'vue']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('1a189453-e3ee-bc43-5244-15b50c1573dd', '8efb6458-270b-cd1b-65fa-c7fa8402cd84', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('2469dc59-e56f-d4d1-e493-75eae3be25b3', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"SOLID: Open/Closed Principle — что значит «открыт для расширения, закрыт для изменения»?","Back":"**OCP** — сущность должна быть **открыта для расширения**, но **закрыта для изменения**: новое поведение добавляется без правки существующего, протестированного кода.\n\nМеханизм — **абстракция + полиморфизм/композиция**: вместо роста `switch` по типам — добавление новой реализации интерфейса.\n\n**Анти-пример (нарушение):**\n```ts\nfunction area(shape) {\n  if (shape.type === ''circle'') return ...;\n  if (shape.type === ''square'') return ...;\n  // каждый новый тип — правка этой функции\n}\n```\n**По OCP:** каждая фигура реализует `area()`; добавление новой фигуры = новый класс, функция не трогается.\n\n**Фронтенд:**\n- Strategy/реестр (`Record<type, handler>`) вместо ветвлений.\n- Плагины Vue/Vite, слоты и `<component :is>` — точки расширения без правки ядра.\n- Конфигурируемые компоненты через props/слоты, а не форки.\n\n**Важно:** OCP не значит «всё абстрагировать заранее» (это против YAGNI). Точки расширения добавляют там, где **ось изменений уже видна**."}'::jsonb, ARRAY['solid', 'ocp', 'principles', 'open-closed']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('8e4c0568-62ab-1517-5e07-d0ea461bda11', '2469dc59-e56f-d4d1-e493-75eae3be25b3', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('fe4faec6-76ba-c2d5-d4e8-a9b83e053114', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"SOLID: Liskov Substitution Principle — что нарушается, если подтип нельзя подставить вместо базового?","Back":"**LSP** — объекты подтипа должны подставляться вместо базового типа **без нарушения корректности** программы. Подтип не должен «обманывать» ожидания, заданные базовым контрактом.\n\n**Правила (контракт):**\n- **Предусловия** нельзя усиливать (подтип не вправе требовать больше, чем база).\n- **Постусловия** нельзя ослаблять (должен гарантировать не меньше).\n- **Инварианты** базового типа сохраняются; не бросать новые непредвиденные исключения.\n\n**Классические нарушения:**\n- `Square extends Rectangle`: установка width меняет height — ломает код, ожидавший независимости сторон.\n- Подкласс, который на часть методов кидает `NotSupportedException` (значит, он не настоящий подтип).\n\n**Фронтенд:** компонент-«наследник» через props, который ломает контракт родителя (другой формат события, игнорирует `v-model`), или реализация общего TS-интерфейса, которая для части методов кидает ошибку/возвращает не то. TypeScript ловит структурную совместимость, но **семантику** контракта (что метод реально делает) — нет."}'::jsonb, ARRAY['solid', 'lsp', 'principles', 'liskov']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('f5b0f201-607a-a82a-8e68-2dc529f0f673', 'fe4faec6-76ba-c2d5-d4e8-a9b83e053114', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('5c2f56d7-d9f8-66f8-e944-38b0f1095a5b', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"SOLID: Interface Segregation и Dependency Inversion — в чём суть и фронтенд-проекция?","Back":"**ISP (Interface Segregation)** — клиента нельзя заставлять зависеть от методов, которые он не использует. Лучше **много узких** интерфейсов, чем один «жирный».\n- Нарушение: огромный пропс-интерфейс компонента/большой TS-интерфейс сервиса, где половина опциональна и не используется. Дроби на роли.\n- Фронт: дробление больших composables/сторов; компонент принимает ровно те props, что ему нужны.\n\n**DIP (Dependency Inversion)** — модули верхнего уровня не зависят от нижнего; **оба зависят от абстракции**. Детали зависят от абстракций, не наоборот.\n```ts\n// плохо: бизнес-логика жёстко зависит от конкретного fetch/axios\n// хорошо: зависит от интерфейса\ninterface UserRepo { getById(id: string): Promise<User>; }\nfunction useProfile(repo: UserRepo) { /* ... */ }\n// в проде — HttpUserRepo, в тестах — FakeUserRepo\n```\n**Фронт:** `provide/inject` как DI-контейнер, инъекция API-клиента/репозитория в composable вместо прямого импорта axios. Это резко упрощает тестирование (подмена мока) и смену реализации.\n\n**Связь:** DIP реализуют через интерфейсы (ISP-границы), а инверсию управления часто даёт DI-механизм фреймворка."}'::jsonb, ARRAY['solid', 'isp', 'dip', 'principles', 'dependency-injection']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('b2bcc778-8fa6-5091-c665-ea28fa785871', '5c2f56d7-d9f8-66f8-e944-38b0f1095a5b', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('04d5ace4-afc3-e761-122b-c4eaaa162994', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Сравните CSR, SSR, SSG и ISR: что рендерится где, и какие трейдоффы по TTFB/FCP/SEO?","Back":"**CSR (Client-Side Rendering)** — сервер отдаёт пустой `<div id=app>` + JS-бандл, рендер в браузере. Быстрый TTFB, но **медленный FCP/LCP** (ждём загрузки и выполнения JS), слабое SEO без пре-рендера. Классический SPA.\n\n**SSR (Server-Side Rendering)** — HTML генерится на сервере **на каждый запрос**, затем гидратация на клиенте. Хороший FCP и SEO, актуальные данные. Цена: нагрузка на сервер, выше TTFB (ждём рендер), сложность (нет `window` на сервере, дубли запросов, состояние per-request).\n\n**SSG (Static Site Generation)** — HTML генерится **на этапе билда**, раздаётся с CDN. Лучший TTFB/FCP, дёшево, отличное SEO. Минус: данные «застывают» на момент билда; много страниц → долгий билд. Для контента, который редко меняется (доки, блог, лендинги).\n\n**ISR (Incremental Static Regeneration)** — гибрид: статика + фоновое перегенерирование страниц по TTL/по запросу. Свежесть SSG-страниц без полного ребилда.\n\n**Выбор:** дашборд за авторизацией → CSR/SPA; маркетинг/SEO-страницы → SSG/ISR; персонализированный контент с SEO → SSR. Современные мета-фреймворки (Nuxt, Next) позволяют **смешивать режимы по маршрутам**."}'::jsonb, ARRAY['rendering', 'csr', 'ssr', 'ssg', 'isr', 'performance']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('55c2a1f6-c640-51e9-808b-062e2bff5fc6', '04d5ace4-afc3-e761-122b-c4eaaa162994', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('3feb5cdd-eb5a-64c7-c2df-f4ae5688e384', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Что такое гидратация, какие у неё проблемы и что такое hydration mismatch?","Back":"**Гидратация** — процесс, когда клиентский JS «оживляет» уже отрендеренный сервером статичный HTML: фреймворк строит VDOM, **сопоставляет его с существующим DOM** и навешивает обработчики/реактивность, не перерисовывая разметку с нуля.\n\n**Проблемы:**\n- **Hydration mismatch** — клиентский VDOM не совпал с серверным HTML. Причины: рендер от `Date.now()`/`Math.random()`, `window`/`localStorage` при первом рендере, невалидная вложенность тегов, разная локаль/таймзона на сервере и клиенте. Vue/React предупреждают в консоли и могут перерисовать поддерево → мигание, потеря состояния.\n- **«Uncanny valley»** — HTML видно, но кнопки не реагируют, пока не загрузился и не отработал JS (TTI > FCP). Чем больше бандл, тем дольше.\n\n**Решения/эволюция:**\n- **Lazy/partial hydration**, **islands** — гидратировать только интерактивные участки.\n- **Resumability** (Qwik) — не повторять работу сервера, а «возобновлять» из сериализованного состояния, без полного восстановления VDOM.\n- Выносить браузер-зависимый код в `onMounted`/`ClientOnly`."}'::jsonb, ARRAY['rendering', 'hydration', 'ssr', 'performance']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('8d1ad208-0cea-f792-8e51-a1321dfd49d8', '3feb5cdd-eb5a-64c7-c2df-f4ae5688e384', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('095ccd0c-aaa9-1071-9bbf-8cdaa831c316', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Что такое островная архитектура (islands) и чем она лучше монолитной гидратации SPA?","Back":"**Islands Architecture** (Astro, частично Nuxt/Fresh) — страница в основе **статический HTML**, а интерактивность точечная: отдельные «острова» (виджеты) гидратируются **независимо**, остальное остаётся статикой и вообще не тянет JS.\n\n**Чем лучше монолитной гидратации:**\n- В классическом SSR-SPA гидратируется **всё дерево** целиком → большой JS, долгий TTI, даже если на странице 90% статичного контента.\n- В islands JS грузится **только для интерактивных кусков**, остальное — нулевой клиентский JS. Резко меньше bundle, лучше TTI/LCP.\n- Острова можно грузить по стратегиям: `client:load`, `client:idle`, `client:visible` (ленивая гидратация при появлении в вьюпорте).\n\n**Трейдоффы:**\n- Острова **изолированы** — обмен состоянием между ними сложнее (нужны сторы/события/URL), нет единого SPA-роутера-навигации по умолчанию.\n- Не подходит для высокоинтерактивных приложений (редакторы, дашборды), где интерактивна вся страница — там обычный SPA/SSR уместнее.\n\nИдея в одном предложении: **платить JS-ом только за то, что реально интерактивно**."}'::jsonb, ARRAY['rendering', 'islands-architecture', 'performance', 'hydration']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('0405f655-0ad7-69f8-c18b-19b5075e654b', '095ccd0c-aaa9-1071-9bbf-8cdaa831c316', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('fe582915-5a4d-f581-8b1d-4919acd12ad3', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Сравните слоистую, модульную и Feature-Sliced Design (FSD) архитектуры фронтенда. В чём боль чисто слоистой?","Back":"**Слоистая (layered) «по типам»** — папки `components/`, `services/`, `store/`, `utils/`. Просто на старте, но при росте: связанный по фиче код размазан по всем папкам, высокая связанность между фичами, тяжело понять границы и удалять фичи. Низкая когезия по бизнесу.\n\n**Модульная (по фичам)** — код группируется по бизнес-домену (`user/`, `cart/`), внутри модуля — свои компоненты/логика. Высокая когезия, но без правил легко скатиться в хаотичные cross-import''ы между модулями.\n\n**FSD (Feature-Sliced Design)** — методология с жёсткими правилами:\n- **Слои** сверху вниз: `app → processes → pages → widgets → features → entities → shared`.\n- **Срезы (slices)** внутри слоя — по бизнес-домену.\n- **Сегменты**: `ui / model / api / lib`.\n- **Главное правило импортов:** модуль может импортировать только из **нижележащих** слоёв (никогда из вышележащих и редко — из соседних на том же слое). Это убирает циклы и задаёт направление зависимостей.\n\n**Итог:** FSD сочетает плюсы модульности с дисциплиной направленных зависимостей; цена — порог входа и оверхед на маленьких проектах (там KISS)."}'::jsonb, ARRAY['architecture', 'fsd', 'layered-architecture', 'modular', 'frontend-architecture']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('68d10d10-2a41-30be-9154-7199707cd1b6', 'fe582915-5a4d-f581-8b1d-4919acd12ad3', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('451f4f9f-9e5a-f35d-a906-3e60ec4960fd', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Что такое микрофронтенды и монорепо? Это одно и то же? Когда они оправданы?","Back":"**Монорепо** — способ **организации кода**: много проектов/пакетов в одном репозитории (pnpm workspaces, Nx, Turborepo). Плюсы: общий код/типы, атомарные кросс-пакетные изменения, единый CI. Минусы: нужны инструменты для масштаба (кэш сборок, affected-граф). Это **vs polyrepo**, и к рантайму отношения не имеет.\n\n**Микрофронтенды (MFE)** — способ **деплоя/композиции рантайма**: приложение собирается из независимо разрабатываемых и **независимо деплоящихся** частей разными командами (Module Federation, import maps, web components, разные роуты за прокси). Плюсы: автономия команд, независимые релизы, изоляция стека. Минусы: дублирование зависимостей (если не шарить через MF), сложность общего состояния/стилей/версий, нагрузка на bundle и контракт между частями.\n\n**Не одно и то же:** можно иметь монорепо без MFE (один SPA, много пакетов) и MFE из polyrepo. Часто сочетают: монорепо для DX + MFE для деплоя.\n\n**Когда MFE оправданы:** несколько крупных команд, разные циклы релизов, легаси-миграция по частям. Для одной команды/одного продукта MFE — обычно **оверинжиниринг** (YAGNI); хватит модульного монолита/FSD."}'::jsonb, ARRAY['architecture', 'microfrontends', 'monorepo', 'module-federation']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('e83023c2-7841-fd1d-10e0-15dfa76ef97c', '451f4f9f-9e5a-f35d-a906-3e60ec4960fd', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('ed37a2e3-b9d7-8061-5ea7-ad3bbf7edeb9', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550005', '{"Front":"Что такое проектирование бизнес-процессов (BP) и зачем фронтендеру понимать его при системном дизайне?","Back":"**Бизнес-процесс** — последовательность действий с участниками (ролями), событиями, шлюзами (ветвлениями) и результатом, реализующая бизнес-ценность (например, «оформление заказа»: корзина → оплата → резерв склада → доставка).\n\n**Нотации/инструменты:**\n- **BPMN** — стандарт моделирования процессов: события (круги), задачи (прямоугольники), шлюзы (ромбы — XOR/AND/OR), потоки, **дорожки (swimlanes)** для ролей/систем.\n- **State machine** — для процессов как набора состояний и переходов (хорошо ложится на XState на фронте).\n- Activity-диаграмма UML — упрощённый вариант.\n\n**Зачем фронту:**\n- UI-флоу = проекция BP: мастера (wizard), статусы заявки, доступность действий зависят от текущего шага/состояния → моделируешь как **конечный автомат**, а не россыпь boolean-флагов (меньше «невозможных» состояний и багов).\n- Понимание шлюзов/исключений = понимание граничных кейсов (отмена, таймаут, частичная оплата), которые надо отрисовать.\n- Общий язык с аналитиками/бэком: где сторона клиента, где сервер, где валидация и идемпотентность.\n\n**Принцип:** делай **невозможные состояния невыразимыми** (явный автомат состояний вместо комбинации флагов)."}'::jsonb, ARRAY['business-process', 'bpmn', 'state-machine', 'workflow']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('e0bdd8ee-1c98-a7a9-9d6d-b3fbf15711b2', 'ed37a2e3-b9d7-8061-5ea7-ad3bbf7edeb9', '55555555-5555-5555-5555-555555550005', 0, 'new') on conflict (id) do nothing;
insert into anki.decks (id, name, description, config) values ('55555555-5555-5555-5555-555555550006', 'Собеседование · Инфраструктура и безопасность', 'Подготовка: сборка, CI/CD, авторизация, безопасность', '{"newCardsPerDay":30,"maxReviewsPerDay":300}'::jsonb) on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('7b10b5b5-e9fa-0556-a8d7-20b2dec383f1', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Как устроена работа с GitLab: стратегии ветвления, merge requests и их связь с CI/CD?","Back":"**Стратегии ветвления:**\n- **GitLab Flow** — лёгкая модель: одна основная ветка (`main`/`master`) + feature-ветки + environment-ветки (`staging`, `production`) или release-ветки. Деплой через мерж в environment-ветку.\n- **Git Flow** — тяжёлая: `develop`, `feature/*`, `release/*`, `hotfix/*`, `main`. Хорошо для версионных релизов, избыточно для CD.\n- **Trunk-based** — короткоживущие ветки, частые мержи в `main`, фичи под feature-флагами.\n\n**Merge Request (MR):**\n- Запрос на слияние ветки с обсуждением, ревью, обязательными approvals.\n- **Merge methods:** merge commit (сохраняет историю ветки), squash (схлопывает в один коммит), fast-forward only (требует линейной истории, заставляет rebase).\n- **Защита:** protected branches (запрет прямого пуша), required approvals, обязательный зелёный пайплайн (`Pipelines must succeed`), резолв всех тредов.\n- **Подводные камни:** при squash теряется детальная история; при rebase переписываются SHA — нельзя rebase''ить общие ветки.\n\n**Связь с CI/CD:** MR триггерит pipeline (`merge_request_event`). Можно запускать lint/test/build только на MR, а деплой — только после мержа в защищённую ветку. `Merge When Pipeline Succeeds` автоматизирует слияние."}'::jsonb, ARRAY['gitlab', 'branching', 'merge-request', 'ci-cd', 'git-flow']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('1257a584-a115-8540-cf19-f604368245f2', '7b10b5b5-e9fa-0556-a8d7-20b2dec383f1', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('b8c90a85-050d-917c-167c-2c309cf11513', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Расскажи про GitLab CI/CD: структура .gitlab-ci.yml, стадии, раннеры, артефакты, кэш.","Back":"Конфигурация лежит в `.gitlab-ci.yml` в корне репозитория.\n\n```yaml\nstages:\n  - install\n  - test\n  - build\n  - deploy\n\nvariables:\n  NODE_ENV: production\n\ncache:\n  key: ${CI_COMMIT_REF_SLUG}\n  paths:\n    - node_modules/\n\ninstall:\n  stage: install\n  script: npm ci\n\nunit-test:\n  stage: test\n  script: npm run test:unit\n  rules:\n    - if: ''$CI_PIPELINE_SOURCE == \"merge_request_event\"''\n\nbuild:\n  stage: build\n  script: npm run build\n  artifacts:\n    paths: [dist/]\n    expire_in: 1 week\n\ndeploy-prod:\n  stage: deploy\n  script: ./deploy.sh\n  environment: production\n  rules:\n    - if: ''$CI_COMMIT_BRANCH == \"main\"''\n      when: manual\n```\n\n**Ключевые сущности:**\n- **stages** — последовательные этапы; джобы внутри одной стадии идут параллельно.\n- **runner** — агент, выполняющий джобы (shared/group/specific; executor: docker, shell, kubernetes).\n- **artifacts** — файлы, передающиеся между стадиями и доступные в UI; в отличие от cache, не для ускорения, а для передачи результатов.\n- **cache** — переиспользование зависимостей между пайплайнами (ускорение). Cache — best-effort, artifacts — гарантированы.\n- **rules / only-except** — условия запуска джобы (`only` устарел в пользу `rules`).\n\n**Подводные камни:** `npm ci` вместо `npm install` для воспроизводимости; неправильный `cache:key` ломает изоляцию между ветками; `when: manual` для прод-деплоя; `needs:` создаёт DAG и ускоряет пайплайн, разрывая жёсткую последовательность стадий."}'::jsonb, ARRAY['gitlab', 'ci-cd', 'pipelines', 'runners', 'artifacts', 'cache']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('6b8b242c-58a8-5d11-ad3b-b1f6d23970e4', 'b8c90a85-050d-917c-167c-2c309cf11513', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('4df50623-7b19-c42d-921f-96de18b083b0', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Что такое HotFix и как организован его процесс: ветки, релиз, бэкпорт?","Back":"**HotFix** — срочное исправление критического бага прямо в продакшене, минуя обычный цикл разработки.\n\n**Процесс (Git Flow):**\n1. Ветка `hotfix/X.Y.Z+1` создаётся **от тега релиза / production-ветки**, а НЕ от `develop` (там могут быть незарелиженные фичи).\n2. Фикс + минимальные изменения, бамп патч-версии.\n3. Мерж в `main`/`production` → деплой.\n4. **Бэкпорт (back-merge):** обязательный мерж того же фикса обратно в `develop` (и в активные `release/*`), иначе при следующем релизе баг вернётся (регрессия).\n\n**Альтернатива в trunk-based / GitLab Flow:**\n- Если прод отстаёт от `main`, фикс делают в `main`, затем **cherry-pick** в production/release-ветку (`git cherry-pick <sha>`).\n- В GitLab есть кнопка `Cherry-pick` прямо из merged MR.\n\n**Подводные камни:**\n- Забытый бэкпорт = возврат бага — главная ошибка.\n- Hotfix от неверной базы тащит лишние изменения.\n- Конфликты при cherry-pick из-за дивергенции веток.\n- Нужны feature-флаги или быстрый rollback-план на случай, если фикс сам сломал прод."}'::jsonb, ARRAY['hotfix', 'git-flow', 'backport', 'cherry-pick', 'release']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('b75bdb72-5823-66d9-a8c6-8e6fee9c0e4d', '4df50623-7b19-c42d-921f-96de18b083b0', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('b6c8309a-d4f0-f91f-eb84-c4e148f9a1bb', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Из чего состоит процесс сборки фронтенд-проекта: bundling, tree-shaking, code splitting, минификация, source maps?","Back":"**Bundling** — сборка множества модулей (JS/CSS/assets) в ограниченное число файлов с разрешением импортов и построением графа зависимостей. Уменьшает число HTTP-запросов (для HTTP/1.1) и нормализует модульную систему.\n\n**Tree-shaking** — удаление неиспользуемого кода (dead code elimination) на основе статического анализа **ESM** (`import`/`export`). Работает только с ES-модулями, т.к. их структура статична. Требует:\n- `\"sideEffects\": false` в package.json (или список файлов с сайд-эффектами);\n- production-режим;\n- ESM-сборку библиотеки (CommonJS не трясётся).\n\n**Code splitting** — разбиение бандла на чанки, загружаемые по требованию:\n- по роутам (`() => import(''./Page.vue'')`);\n- vendor-чанк (отделение библиотек);\n- динамические импорты.\nУлучшает Time-to-Interactive и кэширование.\n\n**Минификация** — удаление пробелов, сокращение имён переменных, dead code (terser/esbuild для JS, cssnano для CSS).\n\n**Source maps** — маппинг собранного/минифицированного кода на исходники для отладки. Типы: `eval`, `cheap-module-source-map`, `source-map` (полный, медленный). На проде обычно `hidden-source-map` (грузится только в DevTools/Sentry, не отдаётся всем) — иначе утечка исходников.\n\n**Трейдофф:** агрессивный splitting → много мелких запросов и waterfall; крупные чанки → плохое кэширование. Нужен баланс."}'::jsonb, ARRAY['bundling', 'tree-shaking', 'code-splitting', 'minification', 'source-maps', 'build']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('3b45334f-f9ec-fe2a-aa34-c19471f3b4be', 'b6c8309a-d4f0-f91f-eb84-c4e148f9a1bb', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('4337a9db-1c1c-a56e-5c54-e84a7b8ce62f', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Чем Vite принципиально отличается от webpack? Как работает dev-сервер и HMR в каждом?","Back":"**webpack (классический bundler):**\n- В dev-режиме **собирает весь бандл** перед стартом dev-сервера → медленный cold start на больших проектах.\n- HMR через webpack-dev-server: пересборка затронутого участка графа + push обновления по WS.\n- Универсален, огромная экосистема лоадеров/плагинов, гибок, но конфиг тяжёлый.\n\n**Vite:**\n- В dev **НЕ бандлит** прикладной код. Использует **нативные ESM в браузере**: отдаёт модули по запросу через dev-сервер (esbuild для трансформации TS/JSX на лету). Cold start почти мгновенный.\n- **Pre-bundling зависимостей** через esbuild (Go, в 10-100x быстрее JS-бандлеров): CommonJS-либы конвертируются в ESM, много мелких модулей (lodash-es) схлопываются в один — иначе сотни запросов.\n- **HMR поверх ESM** — обновляется только изменённый модуль, скорость не зависит от размера приложения.\n- В **production** Vite бандлит через **Rollup** (esbuild не используется для финальной сборки из-за менее зрелого code splitting и отсутствия некоторых оптимизаций). Это создаёт потенциальный **dev/prod несоответствие**.\n\n**Итог:** Vite быстрее в dev за счёт ESM + esbuild; webpack — зрелее и контролируемее. Vite-плагины совместимы с Rollup API (+ собственные хуки)."}'::jsonb, ARRAY['vite', 'webpack', 'hmr', 'dev-server', 'esm', 'esbuild', 'rollup']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('33ef25cd-9210-1688-0700-f87da35a2ce9', '4337a9db-1c1c-a56e-5c54-e84a7b8ce62f', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('c92b7d61-abed-47ba-cb82-0e78c1484990', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Почему Vite использует Rollup для прода и esbuild для dev? Что такое pre-bundling?","Back":"**Два разных движка по назначению:**\n\n**esbuild (dev + pre-bundling):**\n- Написан на Go, экстремально быстрый.\n- В dev: трансформирует TS/JSX → JS на лету (без типизации — только стрипает типы!).\n- **Dependency pre-bundling:** при старте Vite сканирует зависимости и предсобирает их в `node_modules/.vite`:\n  1. Конвертирует CommonJS/UMD → ESM (браузер понимает только ESM).\n  2. Объединяет множество внутренних модулей пакета в один файл → меньше HTTP-запросов (пакет с 600 файлами → 1).\n- Кэшируется; инвалидация по изменению lock-файла/зависимостей.\n\n**Rollup (production build):**\n- Зрелый tree-shaking, продвинутый code splitting, контроль над чанками (`manualChunks`), стабильный output.\n- esbuild для финальной сборки пока не используется: его splitting и плагин-экосистема менее зрелые.\n\n**Подводные камни:**\n- **Dev/prod расхождение:** в dev код не бандлится (нативный ESM), в prod бандлится Rollup''ом — баги вроде циклических зависимостей или сайд-эффектов могут проявиться только в prod-сборке.\n- esbuild не делает проверку типов → нужен отдельный `vue-tsc`/`tsc --noEmit` в CI."}'::jsonb, ARRAY['vite', 'rollup', 'esbuild', 'pre-bundling', 'build', 'dev-prod-parity']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('aa7b6c01-9877-cc48-0086-d0408c5d082e', 'c92b7d61-abed-47ba-cb82-0e78c1484990', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('74b209dd-81a1-b53f-667f-a1b699d3e001', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Покажи типовой конфиг Vite: алиасы, env-переменные, плагины, настройка прокси и сборки.","Back":"```ts\n// vite.config.ts\nimport { defineConfig, loadEnv } from ''vite''\nimport vue from ''@vitejs/plugin-vue''\nimport { fileURLToPath, URL } from ''node:url''\n\nexport default defineConfig(({ mode }) => {\n  const env = loadEnv(mode, process.cwd(), '''')\n  return {\n    plugins: [vue()],\n    resolve: {\n      alias: {\n        ''@'': fileURLToPath(new URL(''./src'', import.meta.url)),\n      },\n    },\n    server: {\n      proxy: {\n        ''/api'': {\n          target: env.VITE_API_URL,\n          changeOrigin: true,\n          rewrite: (p) => p.replace(/^\\/api/, ''''),\n        },\n      },\n    },\n    build: {\n      sourcemap: ''hidden'',\n      rollupOptions: {\n        output: {\n          manualChunks: { vendor: [''vue'', ''vue-router'', ''pinia''] },\n        },\n      },\n    },\n  }\n})\n```\n\n**Env-переменные в Vite:**\n- Файлы `.env`, `.env.production`, `.env.local` (последний в `.gitignore`).\n- В клиентский код попадают **только** переменные с префиксом `VITE_` (защита от утечки секретов). Доступ через `import.meta.env.VITE_API_URL`.\n- `import.meta.env.MODE`, `PROD`, `DEV` — встроенные.\n\n**Подводные камни:**\n- env инлайнятся на этапе сборки (статическая замена) — нельзя менять без пересборки; для рантайм-конфига отдают отдельный `config.json` или window-объект.\n- `changeOrigin: true` нужен, чтобы бэкенд не отверг запрос по Host."}'::jsonb, ARRAY['vite', 'config', 'aliases', 'env', 'proxy', 'manual-chunks']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('40e7c12b-d704-bc6a-10c5-b5d4728577a3', '74b209dd-81a1-b53f-667f-a1b699d3e001', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('96e3915e-a08f-5082-34a0-1932547c2020', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Покажи базовый конфиг webpack и объясни ключевые секции: entry, output, loaders, plugins, mode.","Back":"```js\n// webpack.config.js\nconst path = require(''path'')\nconst { VueLoaderPlugin } = require(''vue-loader'')\nconst HtmlWebpackPlugin = require(''html-webpack-plugin'')\n\nmodule.exports = {\n  mode: ''production'', // включает minification + tree-shaking\n  entry: ''./src/main.js'',\n  output: {\n    path: path.resolve(__dirname, ''dist''),\n    filename: ''[name].[contenthash].js'', // хэш для cache-busting\n    clean: true,\n  },\n  resolve: {\n    alias: { ''@'': path.resolve(__dirname, ''src'') },\n    extensions: [''.js'', ''.ts'', ''.vue''],\n  },\n  module: {\n    rules: [\n      { test: /\\.vue$/, use: ''vue-loader'' },\n      { test: /\\.ts$/, use: ''ts-loader'' },\n      { test: /\\.css$/, use: [''style-loader'', ''css-loader''] },\n      { test: /\\.(png|svg)$/, type: ''asset/resource'' },\n    ],\n  },\n  plugins: [\n    new VueLoaderPlugin(),\n    new HtmlWebpackPlugin({ template: ''./index.html'' }),\n  ],\n  optimization: {\n    splitChunks: { chunks: ''all'' }, // vendor splitting\n  },\n}\n```\n\n**Ключевые отличия от Vite:**\n- **Loaders** трансформируют файлы (цепочка справа налево); **plugins** влияют на весь процесс сборки.\n- `mode: production` автоматически включает terser, tree-shaking, scope hoisting.\n- `[contenthash]` в имени файла — для долгосрочного кэширования (меняется только при изменении содержимого).\n- env через `DefinePlugin` или `dotenv-webpack` (в отличие от встроенного `import.meta.env` у Vite)."}'::jsonb, ARRAY['webpack', 'config', 'loaders', 'plugins', 'contenthash', 'split-chunks']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('f74a121f-f510-2cf6-5ab8-52457164396e', '96e3915e-a08f-5082-34a0-1932547c2020', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('a70bc0c5-592c-a485-7e87-bb60c2c75172', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Сессии vs токены для аутентификации: в чём разница, плюсы и минусы каждого подхода?","Back":"**Session-based (stateful):**\n- Сервер создаёт сессию, хранит её в памяти/Redis/БД, клиенту отдаёт `Set-Cookie` с session ID.\n- Состояние на сервере → легко **отозвать** (удалить сессию), есть контроль.\n- **Минусы:** не масштабируется горизонтально без общего стора (sticky sessions или Redis); сервер несёт нагрузку хранения; сложнее для микросервисов и мобильных клиентов.\n\n**Token-based (stateless, JWT):**\n- Сервер выдаёт подписанный токен; клиент шлёт его в каждом запросе (`Authorization: Bearer`).\n- Сервер **не хранит состояние** — валидирует подпись → легко масштабируется, удобно для микросервисов/SPA/мобильных.\n- **Минусы:** токен нельзя легко **отозвать** до истечения (нужен blacklist/короткий TTL → теряется stateless); больший размер; payload виден (base64, не шифрование!).\n\n**Когда что:**\n- Классическое серверное веб-приложение, нужен мгновенный отзыв → сессии.\n- SPA/мобайл/микросервисы/множество доменов → токены (но с продуманным refresh + хранением).\n\n**Гибрид (рекомендуемый для SPA):** короткоживущий access-токен + refresh-токен в httpOnly cookie, серверный список refresh-токенов для отзыва — сочетает масштабируемость и контроль."}'::jsonb, ARRAY['auth', 'sessions', 'tokens', 'jwt', 'stateless', 'scaling']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('88d1121a-e128-c6df-f3a6-e2c3645fd75e', 'a70bc0c5-592c-a485-7e87-bb60c2c75172', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('c0cf7ab9-85ff-1553-fb07-ca20bfeaec64', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Что такое JWT: структура, как валидируется, какие частые ошибки безопасности?","Back":"**JWT (JSON Web Token)** — три base64url-части через точку: `header.payload.signature`.\n\n```\neyJhbGci... . eyJzdWIi... . SflKxwRJ...\n  header        payload      signature\n```\n- **header** — алгоритм (`alg`) и тип (`typ`).\n- **payload** — claims: `sub`, `exp`, `iat`, `iss`, `aud` + кастомные. **Не шифруется**, только кодируется → не клади секреты!\n- **signature** — `HMAC/RSA(header + payload, secret/privateKey)`. Гарантирует целостность и подлинность.\n\n**Валидация:** сервер пересчитывает подпись и проверяет `exp`, `iss`, `aud`.\n\n**Частые уязвимости:**\n- **`alg: none`** — атакующий ставит алгоритм \"none\" и убирает подпись. Защита: всегда whitelisting алгоритмов на сервере.\n- **Confusion-атака RS256→HS256** — публичный ключ используется как HMAC-секрет. Защита: явно фиксировать алгоритм.\n- **Хранение в localStorage** → доступен из JS → XSS крадёт токен.\n- **Невозможность отзыва** — поэтому короткий `exp` (5-15 мин) + refresh.\n- **Отсутствие проверки `exp`/`aud`** — токен другого сервиса проходит.\n\n**Важно:** JWT обеспечивает integrity, не confidentiality. Для секретности — JWE (шифрованный вариант)."}'::jsonb, ARRAY['jwt', 'auth', 'security', 'alg-none', 'claims', 'token-validation']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('8949a6f6-f455-48a3-f779-ff58350c4f65', 'c0cf7ab9-85ff-1553-fb07-ca20bfeaec64', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('08478c66-99f4-8337-5c92-ae4995b8e29e', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Как работает OAuth2 и Authorization Code Flow с PKCE? Зачем PKCE для SPA?","Back":"**OAuth2** — протокол **делегированной авторизации** (доступ к ресурсам без передачи пароля), не аутентификации (для неё — OpenID Connect поверх OAuth2).\n\n**Роли:** Resource Owner (юзер), Client (приложение), Authorization Server, Resource Server.\n\n**Authorization Code Flow (классический, для серверных приложений):**\n1. Клиент редиректит юзера на authorization server.\n2. Юзер логинится и даёт согласие.\n3. Authorization server редиректит обратно с **authorization code**.\n4. Клиент **на бэкенде** меняет code на access/refresh-токены (используя client_secret).\n\n**PKCE (Proof Key for Code Exchange) — для SPA/мобильных:**\n- Публичные клиенты не могут хранить `client_secret` (код виден в браузере).\n- Клиент генерирует `code_verifier` (случайная строка) и `code_challenge = SHA256(verifier)`.\n1. В авторизационном запросе шлёт `code_challenge`.\n2. При обмене code на токен шлёт `code_verifier`.\n3. Сервер сверяет хэш → перехваченный code бесполезен без verifier.\n\n**Почему важно:** защищает от **перехвата authorization code** (authorization code interception attack) на редиректе. Сейчас PKCE рекомендован для ВСЕХ клиентов, не только публичных.\n\n**Устаревшее:** Implicit Flow (токен прямо в URL-фрагменте) — небезопасен, заменён на Code Flow + PKCE."}'::jsonb, ARRAY['oauth2', 'pkce', 'auth', 'authorization-code', 'oidc', 'spa-security']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('83bbc7b6-849b-fdcc-4e67-b7b0476eae60', '08478c66-99f4-8337-5c92-ae4995b8e29e', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('550e0677-a33d-f85a-aa00-6d6612679eb0', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Зачем нужны refresh-токены и где безопасно хранить токены в SPA?","Back":"**Зачем refresh-токены:**\n- Access-токен делают короткоживущим (5-15 мин) — если украдут, окно атаки мало.\n- **Refresh-токен** (долгоживущий) используется только для получения нового access-токена, хранится серверно (для отзыва) и почти не передаётся.\n- Это компромисс между stateless-удобством JWT и возможностью отзыва.\n\n**Refresh Token Rotation:** при каждом обновлении выдаётся новый refresh-токен, старый инвалидируется. Если предъявлен уже использованный (украденный) — детект кражи → отзыв всей цепочки.\n\n**Где хранить — главный вопрос безопасности:**\n\n| Хранилище | XSS | CSRF | Авто-отправка |\n|-----------|-----|------|---------------|\n| localStorage | уязвим | защищён | нет (вручную) |\n| httpOnly cookie | защищён | уязвим* | да |\n| память (JS-переменная) | минимизирует | защищён | нет |\n\n**Рекомендуемый паттерн для SPA:**\n- **Refresh-токен → httpOnly + Secure + SameSite cookie** (недоступен из JS, защита от XSS-кражи).\n- **Access-токен → в памяти** (JS-переменная/стор), теряется при перезагрузке → восстанавливается через refresh.\n- CSRF на refresh-эндпоинте закрывают `SameSite=Strict/Lax` + CSRF-токеном.\n\n**Антипаттерн:** долгоживущий токен в localStorage — любой XSS = полный угон сессии без возможности быстрого отзыва."}'::jsonb, ARRAY['refresh-token', 'token-rotation', 'auth', 'token-storage', 'httponly', 'xss']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('db878e4b-8f88-c057-06ab-7874e85e949e', '550e0677-a33d-f85a-aa00-6d6612679eb0', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('a8866c7b-d308-8d57-259c-d8dcbec976d8', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Что такое XSS, какие виды бывают и как защищаться во Vue-приложении?","Back":"**XSS (Cross-Site Scripting)** — внедрение и выполнение чужого JS в контексте вашего сайта → кража токенов/cookies, действия от имени юзера.\n\n**Виды:**\n- **Stored** — вредоносный скрипт сохраняется на сервере (комментарий, профиль) и отдаётся всем.\n- **Reflected** — скрипт в URL/параметре, отражается в ответе (фишинговая ссылка).\n- **DOM-based** — уязвимость в клиентском коде (`innerHTML`, `eval`, небезопасный роутинг) без участия сервера.\n\n**Защита во Vue:**\n- Vue **по умолчанию экранирует** интерполяцию `{{ }}` и `v-bind` → безопасно.\n- **`v-html` — главная дыра:** рендерит сырой HTML без экранирования. Никогда не передавай туда пользовательский ввод; если нужно — санируй через **DOMPurify**.\n```js\nimport DOMPurify from ''dompurify''\nconst safe = DOMPurify.sanitize(userHtml)\n```\n- Не биндить пользовательский ввод в `href`/`src` без проверки схемы (`javascript:` URI).\n- Динамические компоненты/`:style`/`:class` из ввода — осторожно.\n\n**Защита в глубину:**\n- **CSP** (Content-Security-Policy) — даже при инъекции скрипт не выполнится.\n- Токены в **httpOnly cookie** — XSS не прочитает их из JS.\n- Экранирование на бэкенде тоже (defense in depth).\n\n**Подводный камень:** SSR (Nuxt) добавляет вектор — данные, инлайнящиеся в HTML, должны экранироваться."}'::jsonb, ARRAY['xss', 'security', 'vue', 'v-html', 'dompurify', 'csp', 'sanitization']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('9af38910-70ff-2749-827f-fb69a5cf6bff', 'a8866c7b-d308-8d57-259c-d8dcbec976d8', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('1429f6c4-a63d-3475-c149-399b8ca908d2', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Что такое CSRF, чем отличается от XSS и как защищаться? Роль SameSite-cookies.","Back":"**CSRF (Cross-Site Request Forgery)** — атакующий заставляет браузер жертвы отправить запрос на ваш сайт, используя её **автоматически прикрепляемые cookies**. Жертва на evil.com → скрытая форма/img шлёт `POST bank.com/transfer`, браузер прикрепляет cookie сессии → запрос проходит как легитимный.\n\n**Ключевое отличие от XSS:**\n- XSS — выполнение чужого кода на вашем сайте (проблема доверия к данным).\n- CSRF — легитимный браузер шлёт запрос, инициированный чужим сайтом (проблема доверия к источнику запроса). CSRF эксплуатирует **неявную авторизацию через cookie**.\n\n**Защита:**\n- **SameSite cookie:**\n  - `Strict` — cookie не шлётся при любых кросс-сайтовых запросах (даже по обычной ссылке) → ломает UX переходов.\n  - `Lax` (дефолт в современных браузерах) — шлётся при top-level GET-навигации, но не при кросс-сайтовых POST/iframe/fetch → закрывает большинство CSRF.\n  - `None` — шлётся всегда, **требует** `Secure`.\n- **CSRF-токен** (synchronizer token) — сервер генерит токен, кладёт в форму/заголовок; атакующий не может его прочитать (Same-Origin Policy).\n- **Double Submit Cookie** — токен в cookie + в заголовке, сервер сверяет.\n- Проверка заголовков `Origin`/`Referer`.\n\n**Важно:** токены в `Authorization`-заголовке (не cookie) **не уязвимы к CSRF** — браузер не прикрепляет их автоматически. Поэтому Bearer-токены из памяти иммунны к CSRF (но уязвимы к XSS — другой трейдофф)."}'::jsonb, ARRAY['csrf', 'security', 'samesite', 'csrf-token', 'cookies', 'xss-vs-csrf']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('4401d7b3-a6fc-42ac-dc27-c5932640c79f', '1429f6c4-a63d-3475-c149-399b8ca908d2', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('3c009190-cba6-91a4-cc24-d4327bf98880', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Как работает CORS и Same-Origin Policy? Что такое preflight-запрос?","Back":"**Same-Origin Policy (SOP)** — базовая защита браузера: скрипт может читать ответы только с того же **origin** (схема + хост + порт). Это НЕ запрещает отправку запроса, а запрещает чтение ответа из JS.\n\n**CORS (Cross-Origin Resource Sharing)** — механизм, которым **сервер** ослабляет SOP, явно разрешая определённым origin читать ответы. Управляется заголовками ответа:\n- `Access-Control-Allow-Origin: https://app.com` (или `*`, но `*` несовместим с credentials).\n- `Access-Control-Allow-Credentials: true` — разрешить cookies/auth.\n- `Access-Control-Allow-Methods`, `Access-Control-Allow-Headers`.\n\n**Simple vs Preflight:**\n- **Simple request** (GET/HEAD/POST с простыми заголовками и content-type из белого списка) — идёт сразу.\n- **Preflight** — браузер сначала шлёт `OPTIONS` с `Access-Control-Request-Method/Headers`, сервер отвечает разрешениями, только потом летит настоящий запрос. Триггерится при: методах PUT/DELETE/PATCH, кастомных заголовках (`Authorization` в некоторых случаях, `Content-Type: application/json`).\n- `Access-Control-Max-Age` кэширует preflight.\n\n**Частые заблуждения:**\n- CORS — это **не защита сервера**: запрос всё равно доходит и выполняется (важно для CSRF!). CORS лишь решает, увидит ли JS ответ.\n- При `credentials: ''include''` нельзя `Allow-Origin: *` — нужен конкретный origin.\n- Ошибка CORS в консоли = сервер не вернул нужные заголовки, а не проблема фронта; фиксится на бэкенде или через dev-прокси (`server.proxy` в Vite)."}'::jsonb, ARRAY['cors', 'same-origin-policy', 'preflight', 'security', 'credentials', 'browser']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('dae49c3d-0847-1440-d0a5-0a0d44ffa552', '3c009190-cba6-91a4-cc24-d4327bf98880', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('90fb6e48-d7e0-a49e-7265-77a2bb11979b', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550006', '{"Front":"Что такое CSP и httpOnly/Secure/SameSite атрибуты cookies? Как они усиливают защиту?","Back":"**CSP (Content-Security-Policy)** — заголовок (или meta), задающий белые списки источников ресурсов. Главная **защита в глубину против XSS**: даже если скрипт внедрён, он не выполнится без разрешения.\n\n```\nContent-Security-Policy:\n  default-src ''self'';\n  script-src ''self'' https://cdn.trusted.com;\n  style-src ''self'' ''unsafe-inline'';\n  img-src ''self'' data:;\n  connect-src ''self'' https://api.app.com;\n  frame-ancestors ''none'';\n```\n- `script-src ''self''` — блокирует inline-скрипты и внешние домены → нейтрализует большинство XSS.\n- **`''unsafe-inline''`** сводит защиту на нет; вместо него — **nonce** (`''nonce-rAnd0m''`) или **hash** для разрешённых inline-скриптов.\n- `frame-ancestors ''none''` — современная замена `X-Frame-Options` (защита от clickjacking).\n- `Content-Security-Policy-Report-Only` + `report-uri` — обкатка политики без блокировки.\n\n**Подводный камень для Vue/Vite:** inline-стили и dev-сборка могут конфликтовать с жёстким CSP; нужны nonce или ослабление в dev.\n\n**Атрибуты cookies:**\n- **`HttpOnly`** — cookie недоступна из `document.cookie` (JS) → XSS не украдёт токен сессии.\n- **`Secure`** — отправляется только по HTTPS → защита от перехвата (MITM).\n- **`SameSite`** (`Strict`/`Lax`/`None`) — контролирует отправку при кросс-сайтовых запросах → защита от CSRF.\n- **`__Host-` префикс** — заставляет cookie быть Secure, без Domain, path=/ → максимальная привязка к origin.\n\n**Комбинация:** `Set-Cookie: token=...; HttpOnly; Secure; SameSite=Strict; Path=/` — эталон для сессионных/refresh-токенов."}'::jsonb, ARRAY['csp', 'cookies', 'httponly', 'samesite', 'secure', 'security', 'clickjacking']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('ef5448c4-641c-0bd2-ffe2-07ea74b36802', '90fb6e48-d7e0-a49e-7265-77a2bb11979b', '55555555-5555-5555-5555-555555550006', 0, 'new') on conflict (id) do nothing;
insert into anki.decks (id, name, description, config) values ('55555555-5555-5555-5555-555555550007', 'Собеседование · Анализ и проектирование', 'Подготовка: анализ, оценка, проектирование', '{"newCardsPerDay":30,"maxReviewsPerDay":300}'::jsonb) on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('b6d5231e-bb64-fee0-c4f2-111257f705f6', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Как ты подходишь к анализу постановки задачи перед началом разработки? Что делаешь в первую очередь?","Back":"Цель анализа — превратить размытое \"хочу кнопку\" в проверяемое описание поведения системы. Порядок действий:\n\n1. **Понять проблему, а не решение.** Заказчик часто приходит с уже придуманным решением (\"добавь модалку\"). Сначала вытаскиваю **проблему и контекст**: какую боль закрываем, кто пользователь, как часто это происходит. Вопрос \"зачем?\" важнее \"что?\".\n2. **Определить границы (scope).** Что входит, а что явно НЕ входит. Зафиксировать out-of-scope письменно — это защита от scope creep.\n3. **Выявить акторов и сценарии.** Кто инициирует, какие роли, happy path + альтернативные ветки + ошибки.\n4. **Найти неявные требования.** Нефункциональные: производительность, доступность (a11y), локализация, безопасность, поведение на мобильных, состояние offline/загрузки/пустых данных.\n5. **Зафиксировать критерии приёмки** до старта.\n\nПодводный камень: соглашаться писать код по первому же тикету. Молчаливые допущения — главный источник переделок. **Лучше потратить час на уточнение, чем неделю на переделку.**"}'::jsonb, ARRAY['requirements', 'analysis', 'scope', 'discovery']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('82c12185-8b04-0883-2d3e-98c0bf45a0b1', 'b6d5231e-bb64-fee0-c4f2-111257f705f6', '55555555-5555-5555-5555-555555550007', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('f4033062-4b7d-8a37-f80b-cac8370ed53d', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Тебе дали задачу: «Сделать фильтр на странице каталога». Какие уточняющие вопросы задашь?","Back":"Намеренно расплывчатая постановка — нужно вскрыть допущения. Группирую вопросы:\n\n**Функциональные:**\n- По каким полям фильтруем? Один фильтр или несколько одновременно (AND/OR)?\n- Фильтрация на клиенте или на сервере? Сколько данных (10 записей или 100k)?\n- Сохранять состояние фильтра в URL (для шаринга/перезагрузки)?\n- Сбрасывается ли фильтр при пагинации/смене сортировки?\n\n**UX:**\n- Применять мгновенно или по кнопке \"Применить\"? Нужен ли debounce?\n- Что показываем при пустом результате?\n- Поведение на мобильных (выезжающая панель)?\n\n**Нефункциональные:**\n- Ожидаемый объём данных и допустимая задержка?\n- a11y: управление с клавиатуры, ARIA?\n- Локализация значений фильтра?\n\n**Контекст/приоритеты:**\n- Какой дедлайн? Можно ли резать scope?\n- Есть ли уже готовый компонент фильтра в дизайн-системе?\n\n**Сениорский нюанс:** вопросы — это не \"допрос заказчика\", а демонстрация, что ты видишь риски. Часто половина ответов = \"а мы не подумали\", и ты только что предотвратил баг в проде."}'::jsonb, ARRAY['requirements', 'clarifying-questions', 'ux', 'frontend']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('a35d95eb-0c06-da8b-6726-080b420425d7', 'f4033062-4b7d-8a37-f80b-cac8370ed53d', '55555555-5555-5555-5555-555555550007', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('22dc9142-dcba-4a17-9552-ef0aaac38512', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Что такое критерии приёмки (acceptance criteria) и как их правильно формулировать?","Back":"**Критерии приёмки** — набор условий, при выполнении которых задача считается сделанной. Это \"definition of done\" на уровне конкретной фичи и одновременно основа для тест-кейсов.\n\nХорошие критерии:\n- **Проверяемые** (можно однозначно сказать да/нет), не \"должно быть удобно\".\n- **Атомарные** — один критерий = одно условие.\n- Покрывают **happy path + граничные случаи + ошибки**.\n\nЧастый формат — **Gherkin (Given-When-Then):**\n```gherkin\nGiven пользователь на странице каталога с активным фильтром по категории\nWhen он перезагружает страницу\nThen фильтр восстанавливается из URL и список отфильтрован\n```\n\nИли чек-лист:\n```\n- [ ] При пустом результате показывается заглушка \"Ничего не найдено\"\n- [ ] Состояние фильтра пишется в query-параметры\n- [ ] Запрос к API дебаунсится на 300мс\n```\n\n**Зачем фронтендеру:** критерии = граница ответственности. Если в них нет \"состояния загрузки\" — формально ты не обязан его делать (но лучше уточнить заранее). Они же защищают на код-ревью и приёмке: \"работает по критериям\" вместо споров о вкусах.\n\n**Антипаттерн:** критерии, описывающие реализацию (\"использовать Pinia\"), а не поведение. Критерии — про *что*, а не *как*."}'::jsonb, ARRAY['acceptance-criteria', 'requirements', 'gherkin', 'definition-of-done']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('a4f92626-2d8f-0fc0-5749-eda98fe5fd51', '22dc9142-dcba-4a17-9552-ef0aaac38512', '55555555-5555-5555-5555-555555550007', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('f9d8fadd-8c51-9c0e-bd11-564cc87e3da3', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Зачем нужна оценка задач (estimation) и почему оценивают в story points, а не в часах?","Back":"Оценка нужна для **планирования спринта, прогнозирования сроков и выявления слишком крупных/рискованных задач** (если не можешь оценить — плохо понял задачу).\n\n**Часы — плохая единица, потому что:**\n- Зависят от исполнителя (джун vs сеньор).\n- Люди системно занижают абсолютное время (planning fallacy).\n- Создают ложное ощущение точности и превращаются в обещание/дедлайн.\n\n**Story points** — относительная мера, учитывающая сразу три фактора:\n1. **Объём работы** (сколько делать).\n2. **Сложность** (насколько хитро).\n3. **Неопределённость/риск** (сколько неизвестного).\n\nТипично используют **ряд Фибоначчи** (1, 2, 3, 5, 8, 13): чем больше число, тем грубее оценка — это честно отражает рост неопределённости. Задачу в 13+ SP обычно нужно **декомпозировать**.\n\nОценивают относительно **эталонной задачи** (\"эта примерно как та, что была на 3\"). Через несколько спринтов команда набирает **velocity** (SP за спринт) — и это даёт прогноз сроков на уровне команды, не привязанный к конкретному человеку.\n\n**Трейдофф:** SP хороши для команды и среднесрока, но менеджмент часто хочет даты. Тогда velocity → даты, но с диапазоном, а не точкой."}'::jsonb, ARRAY['estimation', 'story-points', 'agile', 'velocity']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('552d4be8-8fcc-cc87-03fb-ed2331fcfae8', 'f9d8fadd-8c51-9c0e-bd11-564cc87e3da3', '55555555-5555-5555-5555-555555550007', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('b58a9e9c-22e5-1f9a-050a-9d71a1389976', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Чем story points отличаются от T-shirt sizing? Когда что применять?","Back":"Оба метода — **относительная оценка**, отличаются гранулярностью и контекстом.\n\n**Story Points (числа, обычно Фибоначчи 1–13):**\n- Точнее, дают velocity и прогноз.\n- Подходят для **груминга бэклога перед спринтом**, когда задачи достаточно проработаны.\n- Минус: больше времени на обсуждение, риск \"торга о цифрах\".\n\n**T-shirt sizing (XS, S, M, L, XL):**\n- Грубая, быстрая оценка.\n- Подходит на **раннем этапе**: оценка эпиков, roadmap, приоритизация бэклога, когда деталей ещё нет.\n- Намеренно нет ложной точности — нельзя \"поторговаться\" между M и M+.\n- Минус: не складывается в velocity напрямую (нужно маппить размеры в диапазоны SP).\n\n**Практика:** часто комбинируют — эпики оценивают в T-shirt для roadmap, затем при декомпозиции в истории переходят на SP. \n\n**Общий принцип обоих:** оценка — это **снижение неопределённости и инструмент коммуникации**, а не контракт. Главная польза часто не в самой цифре, а в **обсуждении**, которое вскрывает разное понимание задачи у разработчиков (техника Planning Poker именно для этого — расхождение оценок = сигнал, что задачу поняли по-разному)."}'::jsonb, ARRAY['estimation', 't-shirt-sizing', 'story-points', 'planning']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('09272f33-5a65-5e60-cae9-28c1e11c3b4e', 'b58a9e9c-22e5-1f9a-050a-9d71a1389976', '55555555-5555-5555-5555-555555550007', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('16b92ac0-1a88-e01a-0b66-3cf32aa02878', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Как ты декомпозируешь крупную фичу на задачи? По какому принципу режешь?","Back":"Главный принцип — **резать по вертикали (vertical slicing), а не по слоям**.\n\n**Плохо (горизонтально):** \"задача — вся вёрстка\", \"задача — все API-запросы\", \"задача — вся логика\". Тогда ничего не работает целиком, пока не сделано всё, нельзя выкатить инкремент, поздно всплывают интеграционные проблемы.\n\n**Хорошо (вертикально):** каждая задача — тонкий сквозной кусок ценности (UI + логика + данные), который можно показать и выкатить. Например, фичу \"корзина\" режем как:\n- Добавление товара в корзину (минимально: 1 товар, без скидок).\n- Изменение количества.\n- Промокоды.\n- Сохранение корзины между сессиями.\n\n**Критерии хорошей декомпозиции (INVEST):** Independent, Negotiable, Valuable, Estimable, Small, Testable.\n\n**Приёмы дробления:**\n- По шагам workflow / по CRUD-операциям.\n- По бизнес-правилам (сначала happy path, потом edge cases отдельными задачами).\n- По данным (один тип сначала, остальные потом).\n- Выделить **spike** (исследование) отдельной задачей, если высокая неопределённость.\n\n**Сигнал, что надо дробить:** задача >8–13 SP, не помещается в спринт, или не можешь её оценить. \n\n**Фронтенд-специфика:** отдельно стоит выделять переиспользуемые компоненты дизайн-системы — их часто делают как самостоятельную задачу-зависимость для нескольких фич."}'::jsonb, ARRAY['decomposition', 'vertical-slicing', 'invest', 'task-breakdown']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('669b09ef-7a1a-19b1-6d0a-0af3ea863cd5', '16b92ac0-1a88-e01a-0b66-3cf32aa02878', '55555555-5555-5555-5555-555555550007', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('4cbb9e25-6a95-402f-1b6e-8bbe5869e58d', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Что такое риски и буферы при оценке? Как закладывать запас, не обманывая себя?","Back":"**Риск** — событие с неопределённостью, которое может увеличить сроки: непонятное legacy, зависимость от другой команды/чужого API, новая технология, нечёткие требования.\n\n**Буфер** — заложенный запас времени/SP на эти неизвестные.\n\n**Как делать правильно:**\n1. **Не размазывать буфер по каждой задаче** (\"+30% на всё\") — это прячет проблему и провоцирует закон Паркинсона (работа занимает всё отведённое время). Лучше — **общий буфер на проект/спринт** (метод критической цепи Голдратта).\n2. **Идентифицировать риски явно**, а не закладывать абстрактный запас. Завести список рисков с вероятностью и влиянием.\n3. **Снижать неопределённость до оценки**, а не закладывать её в число: для рискованной части — **spike/прототип** на ограниченный timebox, потом переоценка.\n4. **Оценивать диапазоном/сценариями**, а не точкой: оптимистичный / реалистичный / пессимистичный (база PERT: `(O + 4M + P) / 6`).\n\n**Анти-обман самого себя:**\n- Помнить про **planning fallacy** — мы хронически оптимисты. Опираться на исторические данные (прошлый velocity), а не на ощущение.\n- Учитывать **скрытую работу**: код-ревью, тесты, интеграция, исправление багов, обсуждения, переключение контекста.\n- Различать **estimate (честная оценка)** и **commitment (обещание)** — менеджмент часто давит, чтобы оценка стала обещанием. Это ловушка.\n\n**Трейдофф:** слишком большой буфер → команда расслабляется и теряет доверие бизнеса; слишком маленький → постоянные переносы. Калибруется по факту через ретро."}'::jsonb, ARRAY['estimation', 'risks', 'buffers', 'pert', 'planning-fallacy']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('2fe9aaf3-e0a1-4910-0cfe-12257c1eb5a4', '4cbb9e25-6a95-402f-1b6e-8bbe5869e58d', '55555555-5555-5555-5555-555555550007', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('08a35999-951e-b81c-b52a-698339c795bf', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Как ты выбираешь подход к решению, когда есть несколько вариантов? По каким критериям сравниваешь?","Back":"Проектирование — это **управляемый выбор из альтернатив**, а не \"сел и написал\". Алгоритм:\n\n1. **Сгенерировать минимум 2–3 варианта.** Если вариант один — ты, скорее всего, не понял задачу или взял первое, что пришло в голову.\n2. **Определить критерии сравнения** под конкретный контекст. Типичные оси:\n   - **Сложность реализации** и время.\n   - **Сопровождаемость / читаемость** (кто будет это поддерживать через год).\n   - **Производительность** (есть ли реальные требования или преждевременная оптимизация).\n   - **Масштабируемость** (заложенный рост — но без over-engineering под гипотетическое будущее).\n   - **Соответствие существующей архитектуре** и стеку команды.\n   - **Зависимости и vendor lock-in** (новая библиотека = поддержка, размер бандла, безопасность).\n   - **Тестируемость**.\n   - **Обратимость решения** — дешево ли откатить, если ошиблись.\n3. **Оценить трейдоффы явно.** Идеального решения нет; есть подходящее под ограничения. Часто полезна простая таблица решений (варианты × критерии).\n\n**Ключевой принцип — обратимость (Безос: type-1 vs type-2 решения):** необратимые решения (выбор фреймворка, схема БД, публичный API-контракт) требуют тщательного анализа; обратимые (внутренняя структура компонента) — лучше быстро попробовать, чем долго анализировать.\n\n**Сениорский маркер:** умение сказать \"возьмём вариант проще, потому что требования к нагрузке низкие\" — это зрелость, а не лень. **YAGNI и KISS — тоже инженерные решения.**"}'::jsonb, ARRAY['solution-design', 'tradeoffs', 'decision-making', 'architecture']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('23e84e05-b578-0856-54b9-75614701ad93', '08a35999-951e-b81c-b52a-698339c795bf', '55555555-5555-5555-5555-555555550007', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('919f00c6-ac3b-e42c-5b3b-52fbe8fcbec4', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Когда и зачем нужно прототипирование (PoC / spike) на этапе проектирования?","Back":"**Прототип** нужен, чтобы **дёшево снизить неопределённость** до того, как вложишься в полноценную реализацию. Это инструмент исследования, а не продукт.\n\n**Виды и когда применять:**\n- **Spike** — исследовательская задача с жёстким **timebox** (\"2 дня выяснить, тянет ли библиотека X наш кейс\"). Результат — знание и оценка, а не готовый код.\n- **PoC (proof of concept)** — доказать техническую возможность (\"можно ли вообще отрисовать 100k точек на canvas с приемлемым FPS\").\n- **UI-прототип** — проверить UX/дизайн-гипотезу до интеграции с бэком (моки данных).\n- **Throwaway vs Evolutionary:** одноразовый (выкинуть после) vs эволюционный (доращивать). \n\n**Критичный подводный камень:** прототип **легко превращается в прод** под давлением сроков (\"да оно же работает, давай задеплоим\"). У throwaway-прототипа специально нет тестов, обработки ошибок, edge-cases. Нужно либо изначально договориться, что код выкидываем, либо честно закладывать время на доведение.\n\n**Когда НЕ нужен прототип:** задача типовая и понятная, риск низкий — тогда прототип = трата времени, делай сразу.\n\n**Frontend-кейсы для spike:** оценка новой библиотеки графиков/таблиц, проверка производительности рендера большого списка (нужна ли виртуализация), совместимость с SSR, поведение анимаций на слабых устройствах."}'::jsonb, ARRAY['prototyping', 'poc', 'spike', 'timebox', 'risk-reduction']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('72f0779f-f7f8-f5b9-f9b9-0e7019eba7d2', '919f00c6-ac3b-e42c-5b3b-52fbe8fcbec4', '55555555-5555-5555-5555-555555550007', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('2b619da8-8fd4-837a-669c-e182a83bc3a4', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550007', '{"Front":"Как и зачем документировать принятое архитектурное/проектное решение? Что такое ADR?","Back":"Документация решения нужна, чтобы через полгода (или новому человеку) был понятен **не только итог, но и контекст и причины** — иначе \"почему так сделано?\" приводит к ошибочным переделкам или повторению уже отвергнутых вариантов.\n\n**ADR (Architecture Decision Record)** — короткий неизменяемый документ на одно значимое решение. Хранится в репозитории (`docs/adr/0007-state-management.md`), версионируется вместе с кодом. Типовая структура:\n```markdown\n# ADR-0007: Выбор менеджера состояния\n## Статус\nПринято (2026-06-10). Заменяет ADR-0003.\n## Контекст\nПриложение разрастается, prop drilling, нужно разделяемое состояние...\n## Решение\nИспользуем Pinia.\n## Альтернативы\n- Vuex — legacy, хуже TS-поддержка.\n- Provide/inject — не хватает devtools и структуры.\n## Последствия\n+ Хорошая типизация, devtools.\n- Ещё одна зависимость, команде нужно изучить.\n```\n\n**Ключевые свойства ADR:**\n- **Immutable** — не редактируем старые, а помечаем `Superseded` и пишем новый. Сохраняется история мышления.\n- Фиксирует **отвергнутые альтернативы и причины** — это самое ценное.\n- Короткий (1 экран), иначе никто не пишет и не читает.\n\n**Что ещё документировать:** диаграммы (C4-модель для архитектуры, sequence-диаграммы для потоков), контракты API (OpenAPI), нефункциональные требования.\n\n**Принцип:** документируй **значимые и необратимые** решения. Документировать каждую мелочь — overhead, который устаревает быстрее, чем пишется. Лучшая документация — близко к коду, версионируется и обновляется в том же PR."}'::jsonb, ARRAY['documentation', 'adr', 'architecture', 'decision-records', 'c4-model']::text[]) on conflict (id) do nothing;
