insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('88c7d99d-ce1e-dacf-00cc-964c2ac8b053', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Как ты организуешь работу команды: планирование, приоритизация, выбор между Scrum и Kanban?","Back":"Организация работ — это поток ценности с минимумом потерь, а не \"раздача задач\".\n\n**Планирование (горизонты):**\n- **Стратегия (квартал):** product goals → epics. Лид защищает scope и сроки перед бизнесом.\n- **Тактика (спринт/2 недели):** декомпозиция epics на stories, оценка, sprint goal.\n- **Операционка (день):** дейли как синхронизация по блокерам, а не отчёт начальнику.\n\n**Приоритизация — фреймворки, а не интуиция:**\n- **RICE** (Reach × Impact × Confidence / Effort) — для продуктовых фич.\n- **WSJF** (Weighted Shortest Job First = Cost of Delay / Job Size) — из SAFe, хорошо для техдолга vs фич.\n- **MoSCoW** (Must/Should/Could/Won''t) — для фиксации scope перед релизом.\n- Отдельный **бюджет на техдолг** (например 20%), иначе он никогда не приоритизируется.\n\n**Scrum vs Kanban (трейдофф):**\n```\nScrum   → фиксированные итерации, фокус на predictability,\n          хорош для продуктовой разработки с дискретными целями.\nKanban  → непрерывный поток, WIP-лимиты, фокус на flow/latency,\n          хорош для support/maintenance/непредсказуемого входящего потока.\n```\n- **Ключевая метрика Kanban — WIP-лимит:** ограничение незавершёнки заставляет команду \"дотаскивать\", а не плодить начатое. Это контринтуитивно увеличивает throughput (закон Литтла: Lead Time = WIP / Throughput).\n- На практике многие команды живут в **Scrumban**: итерации для планирования + WIP-лимиты для потока.\n\n**Ретро (главный механизм улучшения):**\n- Не \"что плохо\", а **actionable items с owner и сроком**. Без этого ретро деградирует в нытьё.\n- Проверяй на следующем ретро, что прошлые items закрыты — иначе теряется доверие к формату.\n- Форматы: Start/Stop/Continue, Mad/Sad/Glad, 5 Whys для конкретного инцидента.\n\n**Подводный камень:** карго-культ Agile — церемонии ради церемоний. Лид должен резать ритуалы, которые не дают ценности конкретной команде."}'::jsonb, ARRAY['agile', 'scrum', 'kanban', 'prioritization', 'planning', 'retro']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('077360cc-3945-1ac1-607f-f5621687ca86', '88c7d99d-ce1e-dacf-00cc-964c2ac8b053', '55555555-5555-5555-5555-555555550008', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('914e10c4-2e5c-fb5b-24e2-69627f8ff6e8', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Чем велосити (velocity) полезна и почему её опасно использовать как KPI?","Back":"**Velocity** — сумма story points завершённых задач за спринт. Это **инструмент прогнозирования для самой команды**, а не метрика производительности.\n\n**Для чего реально нужна:**\n- Прогноз: \"сколько влезет в следующий спринт\" на основе среднего за 3-5 спринтов.\n- Выявление аномалий: резкое падение → блокеры, выгорание, недооценка.\n\n**Почему нельзя делать KPI / сравнивать команды:**\n- **Story points относительны** — они калиброваны внутри одной команды. 8 SP в команде A ≠ 8 SP в команде B.\n- **Закон Гудхарта:** \"когда метрика становится целью, она перестаёт быть хорошей метрикой\". Команда начнёт **инфлировать оценки** — велосити растёт, ценность нет.\n- Поощряет дробление и game the system вместо доставки ценности.\n\n**Что мерить лидом вместо этого (DORA-метрики):**\n```\nDeployment Frequency   — как часто катим в прод\nLead Time for Changes  — от коммита до прода\nChange Failure Rate    — % деплоев с инцидентами\nMTTR                   — время восстановления\n```\nDORA измеряет **здоровье процесса доставки**, а не \"скорость кодинга\", и его сложнее заиграть.\n\n**Главный трейдофф:** скорость без качества = накопление техдолга, который убьёт скорость через полгода. Лид балансирует."}'::jsonb, ARRAY['velocity', 'metrics', 'dora', 'goodharts-law', 'kpi']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('33699286-4ed3-b550-015a-60cb96cd0b26', '914e10c4-2e5c-fb5b-24e2-69627f8ff6e8', '55555555-5555-5555-5555-555555550008', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('5f48d457-eadc-3b80-508a-057e7571ca35', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Как ты проводишь эффективное 1-1 с разработчиком?","Back":"**1-1 — это время сотрудника, а не статус-митинг.** Статус по задачам берётся из трекера; 1-1 про человека.\n\n**Принципы:**\n- **Регулярность важнее длительности:** раз в 1-2 недели по 30 мин стабильно > часовая встреча раз в квартал.\n- **Повестку ведёт сотрудник**, лид добавляет свои пункты. Общий док с running notes — видна динамика обещаний.\n- **Не отменять без крайней нужды** — отмена 1-1 = сигнал \"ты неважен\".\n\n**О чём говорить (уровни глубины):**\n```\nКраткосрочно  → блокеры, что мешает работать прямо сейчас\nСреднесрочно  → загрузка, интересность задач, отношения в команде\nДолгосрочно   → карьера, рост, чего хочет через год-два\n```\n\n**Техники:**\n- Больше слушать (правило 80/20: 80% времени говорит сотрудник).\n- Открытые вопросы: \"что бы ты изменил в нашем процессе?\", \"что тебя демотивирует?\".\n- Скип-левел встречи у тимлидов с твоими подчинёнными помогают увидеть слепые зоны.\n\n**Red flags, которые ловишь на 1-1:**\n- Перестал жаловаться вообще → либо идеально (редко), либо уже мысленно уволился.\n- Растущий цинизм, \"мне всё равно\".\n- Постоянная перегрузка, о которой молчал.\n\n**Подводный камень:** превращение 1-1 в допрос по задачам убивает доверие. Психологическая безопасность строится годами и рушится за одну встречу."}'::jsonb, ARRAY['one-on-one', 'team-management', 'leadership', 'feedback']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('52e972b8-a85b-87fb-8026-c6e8ad13552f', '5f48d457-eadc-3b80-508a-057e7571ca35', '55555555-5555-5555-5555-555555550008', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('50a02514-a669-bcf9-42a0-ab8aab9b294a', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Как давать обратную связь, чтобы она работала? Какие модели используешь?","Back":"Обратная связь — основной инструмент роста команды. Плохая ОС демотивирует сильнее, чем её отсутствие.\n\n**Принципы:**\n- **Своевременность:** разбирать ситуацию через месяц бесполезно — контекст утерян.\n- **Конкретика, не ярлыки:** не \"ты безответственный\", а \"вчера деплой упал, потому что не прогнали миграции\".\n- **Хвалить публично, критиковать наедине.**\n- **Про поведение, не про личность** — поведение можно изменить, личность атаковать бессмысленно.\n\n**Модели:**\n```\nSBI (Situation–Behavior–Impact):\n  \"На ревью (S) ты переписал PR коллеги без обсуждения (B),\n   из-за этого он расстроился и перестал брать сложные задачи (I)\".\n  → Факты, без оценок и домыслов о мотивах.\n\nCOIN (Context–Observation–Impact–Next) — добавляет шаг про действия.\n```\n\n**Радикальная искренность (Ким Скотт):**\n```\n              Заботишься лично\n                    ↑\n   Деструктивная   |   Радикальная\n   эмпатия         |   искренность   ← цель\n   ─────────────────────────────────→ Бросаешь вызов прямо\n   Манипулятивная  |   Агрессивная\n   неискренность   |   прямота\n```\n- Большинство руководителей залипают в **деструктивной эмпатии**: жалеют и молчат, человек не растёт.\n\n**Двусторонность:** регулярно проси ОС о себе. \"Что я делаю, что тебе мешает?\" — без этого лид слепнет.\n\n**Подводный камень:** \"сэндвич\" (похвала-критика-похвала) обесценился — люди ждут подвоха после похвалы и не слышат суть. Лучше прямо и с заботой."}'::jsonb, ARRAY['feedback', 'radical-candor', 'sbi', 'leadership', 'team-growth']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('f0669666-664a-ef4f-e973-cd0c95282f49', '50a02514-a669-bcf9-42a0-ab8aab9b294a', '55555555-5555-5555-5555-555555550008', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('3921d4dd-8255-532a-eb4d-a77de1d70160', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Как ты выстраиваешь развитие разработчика: менторство, рост грейдов, IDP?","Back":"Развитие — это удержание + рост capacity команды. Люди уходят из-за стагнации чаще, чем из-за денег.\n\n**IDP (Individual Development Plan):**\n- Совместный документ: куда хочет расти сотрудник + что нужно бизнесу. Пересечение = зона роста.\n- **SMART-цели** на квартал/полгода: не \"стать лучше в архитектуре\", а \"спроектировать и провести через ревью модуль X к концу Q2\".\n- Привязка к **матрице компетенций / грейдам** — прозрачные критерии перехода Junior→Middle→Senior, чтобы рост не зависел от настроения лида.\n\n**Менторство vs коучинг (разные инструменты):**\n```\nМенторство → \"я знаю как, показываю/советую\" (передача экспертизы)\nКоучинг    → \"задаю вопросы, ты находишь решение сам\" (развитие мышления)\nДелегирование с правом на ошибку → главный ускоритель роста сениоров\n```\n\n**Модель развития сложности задач (situational leadership):**\n- Джуну — directing (чёткие указания, частый контроль).\n- Сениору — delegating (цель и автономия, контроль по результату).\n- **Ошибка лида:** микроменеджить сениора (демотивация) или бросать джуна в автономию (выгорание + плохой код).\n\n**Рост вширь vs ввысь:**\n- Не все хотят в менеджмент. **Двойная карьерная лестница**: техническая (Senior→Staff→Principal) равна по статусу/деньгам управленческой.\n- Навязывание управления хорошему инженеру = потеря инженера и получение плохого менеджера (принцип Питера).\n\n**Метрика успеха лида:** сколько людей выросли в грейде и сколько готовы заменить тебя. Лид, на котором всё держится, — это bottleneck, а не герой."}'::jsonb, ARRAY['mentoring', 'idp', 'career-growth', 'competency-matrix', 'delegation']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('3f962819-88dd-ed04-7e63-af3e5f3ef270', '3921d4dd-8255-532a-eb4d-a77de1d70160', '55555555-5555-5555-5555-555555550008', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('e534b5c9-dbf6-6ade-2435-45de6a07d757', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Как ты структурируешь техническое интервью фронтендера и что именно оцениваешь?","Back":"Цель интервью — предсказать успех в **этой** роли, а не устроить экзамен по олимпиадным алгоритмам.\n\n**Структура (воронка из этапов):**\n```\n1. Скрининг (30 мин)    — sanity-check, мотивация, соответствие грейду\n2. Live coding (60 мин) — практическая задача, близкая к реальности\n3. System design (60)   — для Middle+/Senior: спроектировать фичу/приложение\n4. Поведенческое        — soft skills, конфликты, командность\n```\n\n**Что оцениваю на live coding (важнее результата — процесс):**\n- **Задаёт ли уточняющие вопросы** до кодинга (требования, edge cases) — сениор не бросается писать сразу.\n- **Ход мыслей вслух**, декомпозиция, нейминг, обработка ошибок.\n- Реакция на усложнение задачи и на свою ошибку.\n- Не \"знает ли наизусть API\", а \"умеет ли рассуждать и гуглить осмысленно\".\n\n**Фронтенд-специфика для Vue-сениора:**\n- Реактивность: понимает ли разницу ref/reactive, ловушки потери реактивности, когда watch vs computed.\n- Производительность: виртуализация списков, code-splitting, что вызывает лишние ре-рендеры.\n- Архитектура: компонентная декомпозиция, управление состоянием, границы ответственности (FSD/feature-based).\n- A11y, семантика, кросс-браузерность — отличает мидла от \"верстальщика на Vue\".\n\n**System design сигналы сениорства:**\n- Проговаривает трейдоффы (SSR vs SPA, optimistic UI, кеширование).\n- Думает про API-контракты, состояния загрузки/ошибок, offline.\n\n**Хорошая практика:** структурированное интервью с заранее заданными вопросами и шкалой оценки. Снижает bias и делает кандидатов сравнимыми. Анти-паттерн — каждый интервьюер спрашивает что хочет и решает \"по ощущениям\"."}'::jsonb, ARRAY['technical-interview', 'hiring', 'live-coding', 'system-design', 'vue']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('18104ea9-0d2e-7189-5217-a3eedc79c2e0', 'e534b5c9-dbf6-6ade-2435-45de6a07d757', '55555555-5555-5555-5555-555555550008', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('776973f0-0b0d-a37d-252d-2f2cdaab07ae', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Какие red flags ты ловишь на собеседовании, а какие \"красные флаги\" на самом деле ложные?","Back":"**Настоящие red flags:**\n- **Не задаёт ни одного уточняющего вопроса** к задаче — кодит по первому пониманию. В реальной работе это \"сделал не то\".\n- **Не признаёт незнание / блефует.** Сениор спокойно говорит \"не знаю, но искал бы так\". Блеф = риск тихих факапов в проде.\n- **Винит во всём всех вокруг** в рассказах о прошлом (бывших коллег, менеджеров, легаси). Ноль рефлексии о своём вкладе.\n- **Не может объяснить решение, которое сам принял** на прошлом проекте — значит, не он принимал или не понимал.\n- **Резко негативит к тестам/ревью/процессам** как к пустой трате времени — маркер незрелости.\n- **Токсичность под видом \"прямоты\"**, пренебрежение к джунам/смежникам.\n\n**Ложные red flags (на которые часто зря режут):**\n- **Волнение и оговорки** — это стресс собеседования, а не уровень. Хороший интервьюер снижает стресс.\n- **Не помнит точный синтаксис API** — гуглится за 10 секунд, не показатель. Важно понимание механизма.\n- **Job hopping сам по себе** — контекст важен (стартапы закрывались, релокация). Допрашивай причины, не штампуй ярлык.\n- **Нет модного стека в резюме** — сильный инженер переучивается быстро; фундамент важнее конкретного фреймворка.\n- **Несогласие с интервьюером** — если аргументировано, это плюс (умеет отстаивать позицию), а не \"неудобный\".\n\n**Мета-принцип:** интервью предвзято в сторону тех, кто хорошо проходит интервью, а не хорошо работает. Лид обязан осознавать **bias** (halo-эффект, \"похож на меня\") и компенсировать структурой и несколькими интервьюерами."}'::jsonb, ARRAY['technical-interview', 'red-flags', 'hiring', 'bias']::text[]) on conflict (id) do nothing;
