insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('daa3ae6c-7730-2a26-6742-effdf5d8141f', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Какой оптимальный размер фронтенд-команды и почему \"добавить людей\" не ускоряет проект?","Back":"**Оптимальный размер: 5-9 человек** (\"two-pizza team\" Безоса — команда, которую кормят две пиццы).\n\n**Почему именно столько — комбинаторика связей:**\n```\nКоличество каналов коммуникации = n(n-1)/2\n  3 чел  → 3 связи\n  6 чел  → 15 связей\n  10 чел → 45 связей\n  15 чел → 105 связей  ← коммуникация съедает работу\n```\nС ростом n накладные расходы на синхронизацию растут квадратично, а полезный выход — линейно (в лучшем случае). Поэтому большую команду **дробят на 2 поменьше с чёткими зонами ответственности**, а не растят бесконечно.\n\n**Brooks'' Law (\"Мифический человеко-месяц\"):**\n> \"Adding manpower to a late software project makes it later.\"\n\n**Механизм, почему новый человек сначала замедляет:**\n1. **Onboarding ramp-up** — новичок месяцы выходит на продуктивность, и отвлекает сениоров на менторинг (минус их продуктивность).\n2. **Рост коммуникационных издержек** (см. формулу выше).\n3. **Неделимость задач** — \"девять женщин не родят ребёнка за месяц\". Часть работы строго последовательна.\n\n**Вывод для лида:** на горящем проекте добавление людей в моменте делает только хуже. Решения: резать scope, убирать блокеры, а не накидывать头count."}'::jsonb, ARRAY['team-size', 'brooks-law', 'two-pizza-team', 'communication-overhead']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('4236797c-b7e6-0c9c-f5ad-092dd6b3563f', 'daa3ae6c-7730-2a26-6742-effdf5d8141f', '55555555-5555-5555-5555-555555550008', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('91691ad7-8889-7f96-8a10-8de2cc8f940e', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Как ты определяешь состав команды (роли) и балансируешь нагрузку? Что такое bus factor?","Back":"Команда — это набор **ролей и уровней**, а не просто N разработчиков.\n\n**Состав сбалансированной команды (грейды):**\n- **Анти-паттерн \"все сениоры\":** дорого, скучные задачи делать некому, конфликты эго, нет кому растить. Сениоры выгорают на рутине.\n- **Анти-паттерн \"все джуны\":** некому ревьюить, архитектура разваливается, техдолг растёт.\n- **Здоровый микс:** обычно пирамида/ромб — несколько сениоров (архитектура, ревью, менторство), ядро мидлов (основная доставка), джуны (рост + рутина). Точные пропорции зависят от зрелости продукта.\n\n**Роли (могут совмещаться в малой команде):**\n- Tech Lead — техническое направление, архитектурные решения.\n- Product Owner — приоритеты и \"что делаем\".\n- Разработчики разных грейдов; в зрелых командах — QA, иногда выделенный DevOps.\n\n**Балансировка нагрузки:**\n- **Не грузить одного сениора всем сложным** — это создаёт bottleneck и bus factor = 1.\n- Учитывать невидимую нагрузку: ревью, менторинг, дежурства, собеседования — это часть capacity, а не \"сверху основной работы\".\n- Чередовать интересное и рутину, чтобы не выгорали сильнейшие.\n\n**Bus factor (он же truck factor):**\n```\nBus factor = сколько человек должны \"попасть под автобус\" (уйти),\n             чтобы проект встал из-за потери критичных знаний.\nBus factor = 1 → один человек знает критичную подсистему. Катастрофа.\n```\n- **Повышать через:** парное программирование, ротацию задач, code review как передачу знаний, документацию, отказ от \"героев-владельцев модулей\".\n- Лид целенаправленно **размывает экспертизу** по команде, даже ценой краткосрочной скорости.\n\n**Подводный камень:** оптимизация только под скорость доставки повышает bus factor и хрупкость. Лид держит баланс delivery vs resilience."}'::jsonb, ARRAY['team-composition', 'bus-factor', 'workload', 'roles', 'seniority-mix']::text[]) on conflict (id) do nothing;
insert into anki.cards (id, note_id, deck_id, template_index, state) values ('ab9dc4a8-70f1-37e0-99ca-ad61da459fa6', '91691ad7-8889-7f96-8a10-8de2cc8f940e', '55555555-5555-5555-5555-555555550008', 0, 'new') on conflict (id) do nothing;
insert into anki.notes (id, note_type_id, deck_id, fields, tags) values ('8c7b684b-4d2d-9dc4-dd2c-e2b39d14ae45', '11111111-1111-1111-1111-111111110001', '55555555-5555-5555-5555-555555550008', '{"Front":"Как ты внедряешь изменения в процессы команды и работаешь с сопротивлением?","Back":"Лид постоянно меняет процессы (новый CI, code review policy, переход на Kanban). Главная ошибка — **приказ сверху без вовлечения**.\n\n**Принципы внедрения изменений:**\n- **Проблема, а не решение, первична.** Сначала команда соглашается, что проблема есть (\"релизы по 3 дня\"), потом обсуждаем решение. Иначе сопротивление гарантировано.\n- **Вовлечение в выработку решения** = ownership. Люди не саботируют то, что придумали сами.\n- **Эксперимент с метрикой, а не \"навсегда\":** \"пробуем 3 спринта, смотрим на lead time, на ретро решаем\". Снижает страх необратимости.\n- **Маленькие итерации** — не менять 5 процессов разом, иначе не понять, что сработало.\n\n**Работа с сопротивлением (это сигнал, не помеха):**\n```\nТипы сопротивления:\n  \"Раньше работало\"      → покажи данные/боль, которую новый процесс решает\n  \"Это лишняя бюрократия\" → возможно правы — проверь ценность ритуала\n  Тихий саботаж          → худший случай: вытащи на 1-1, найди реальную причину\n```\n- Сопротивление сениоров особенно ценно — у них часто есть контекст, которого нет у лида. Слушать, а не продавливать.\n\n**Модели для опоры:**\n- **ADKAR** (Awareness–Desire–Knowledge–Ability–Reinforcement) — нельзя перескочить через Desire к Ability.\n- **Закрепление (Reinforcement):** без него команда откатывается к старому. Новый процесс должен стать default (автоматизация, шаблоны, линтеры вместо устных договорённостей).\n\n**Подводный камень:** \"чайка-менеджмент\" — лид прилетел с новой методологией с конференции, всё переломал, улетел. Изменения без закрепления и измерения = только хаос и потеря доверия."}'::jsonb, ARRAY['change-management', 'adkar', 'process-improvement', 'resistance', 'leadership']::text[]) on conflict (id) do nothing;
